import { UserProfile } from '../types';
import { api } from '../services/apiService';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [authView, setAuthView] = useState<'login' | 'signup'>('login');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    mobile: '',
    dob: '',
    password: ''
  });

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    try {
      if (authView === 'login') {
        const response = await api.login({ email: formData.email, password: formData.password });
        setSuccess("Access Granted. Synchronizing Workspace...");
        setTimeout(() => onLogin(response.user), 1000);
      } else if (authView === 'signup') {
        await api.signup(formData);
        setSuccess("Identity Node Created. You may now authorize.");
        setTimeout(() => {
          setAuthView('login');
          setSuccess("");
        }, 2000);
      }
    } catch (err: any) {
      setError(err.message || "Authorization Protocol Failed");
    } finally {
      setIsSubmitting(false);
    }
  };

