                <ShieldCheck className="w-8 h-8 text-white" />
              </div>
              <div>
                <h1 className="text-3xl font-black tracking-tighter uppercase text-white leading-none">Lumina</h1>
                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] mt-1">Enterprise Studio X</p>
              </div>
            </div>

            <h2 className="text-7xl font-black leading-[0.9] mb-8 text-white tracking-tighter">
              The Future of <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-emerald-400">Creative Production.</span>
            </h2>

            <p className="text-slate-400 text-xl font-medium leading-relaxed max-w-xl mb-12">
