                 { label: 'Photo Studio', icon: ImageIcon, color: 'text-cyan-400' },
                 { label: 'Secure Cloud', icon: Shield, color: 'text-indigo-400' }
               ].map((item, i) => (
                 <div key={i} className="flex items-center space-x-4 group cursor-default">
                    <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center group-hover:scale-110 transition-transform">
                       <item.icon className={`w-5 h-5 ${item.color}`} />
                    </div>
                    <span className="text-[11px] font-black text-slate-300 uppercase tracking-widest">{item.label}</span>
                 </div>
               ))}
            </div>
          </div>

          <div className="relative z-10 space-y-8">
             <div className="p-8 bg-black/40 rounded-[2.5rem] border border-white/5 flex items-center justify-between backdrop-blur-md">
                <div className="flex items-center space-x-6">
                   <div className="flex -space-x-3">
                      {[1,2,3].map(i => <div key={i} className="w-10 h-10 rounded-full border-4 border-slate-900 bg-slate-800" />)}
                   </div>
                   <div>
                      <p className="text-white font-bold text-sm">24,000+ Creators Active</p>
                      <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Global Node Network</p>
                   </div>
                </div>
                <div className="flex items-center space-x-2 text-emerald-500">
                   <Zap className="w-4 h-4 fill-current" />
                   <span className="text-[10px] font-black uppercase tracking-widest">Live</span>
                </div>
             </div>
          </div>

          <div className="absolute -bottom-20 -left-20 opacity-5 pointer-events-none rotate-12">
             <Terminal className="w-[500px] h-[500px] text-white" />
          </div>
        </div>

