               >
                 Login Session
               </button>
               <button 
                 onClick={() => setAuthView('signup')}
                 className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${authView === 'signup' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
               >
                 Create Node
               </button>
            </div>

            <form onSubmit={handleAuth} className="space-y-6">
              {error && (
                <div className="p-5 bg-rose-500/10 border border-rose-500/30 rounded-2xl text-rose-500 text-[10px] font-black uppercase flex items-center animate-in shake duration-300">
                  <AlertCircle className="w-5 h-5 mr-4" /> {error}
                </div>
              )}
              {success && (
                <div className="p-5 bg-emerald-500/10 border border-emerald-500/30 rounded-2xl text-emerald-500 text-[10px] font-black uppercase flex items-center animate-in slide-in-from-top-2">
                  <CheckCircle2 className="w-5 h-5 mr-4" /> {success}
                </div>
              )}

              <div className="space-y-5">
                <div className="space-y-2">
