                      className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-5 pl-14 pr-6 text-white text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all placeholder:text-slate-800 tracking-widest uppercase" 
                      placeholder="kader / email" 
                    />
                  </div>
                </div>

                {authView === 'signup' && (
                  <div className="space-y-5 animate-in fade-in slide-in-from-top-2">
                    <div className="relative group">
                      <User className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700 group-focus-within:text-indigo-400" />
                      <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-5 pl-14 pr-6 text-white text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all uppercase" placeholder="Full Node Name" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="relative group">
                        <Smartphone className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700 group-focus-within:text-indigo-400" />
                        <input value={formData.mobile} onChange={e => setFormData({...formData, mobile: e.target.value})} className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-5 pl-14 pr-6 text-white text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="Mobile Node" />
                      </div>
                      <input type="date" value={formData.dob} onChange={e => setFormData({...formData, dob: e.target.value})} className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-5 px-6 text-white text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" />
                    </div>
                  </div>
                )}

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Secure Access Key</label>
                  <div className="relative group">
                    <Lock className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700 group-focus-within:text-indigo-400 transition-colors" />
                    <input 
                      required 
                      type={showPassword ? "text" : "password"} 
                      value={formData.password} 
                      onChange={e => setFormData({...formData, password: e.target.value})} 
                      className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-5 pl-14 pr-16 text-white text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all placeholder:text-slate-800 tracking-widest" 
                      placeholder="••••••••" 
                    />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-700 hover:text-white transition-colors">
                      {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                    </button>
                  </div>
                </div>
              </div>

              <button 
                disabled={isSubmitting} 
                className="w-full py-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-[2rem] font-black uppercase text-[11px] tracking-[0.4em] shadow-xl shadow-indigo-600/20 transition-all flex items-center justify-center relative overflow-hidden group"
              >
                <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
                {isSubmitting ? <RefreshCw className="w-6 h-6 animate-spin relative z-10" /> : 
                 <span className="relative z-10 flex items-center">
                   {authView === 'login' ? 'Authorize Session' : 'Synthesize Identity'} 
                   <ArrowRight className="w-5 h-5 ml-4 group-hover:translate-x-2 transition-transform" />
                 </span>}
              </button>
            </form>

            <div className="mt-12 text-center">
               <p className="text-[9px] font-black text-slate-700 uppercase tracking-[0.5em] mb-4">Lumina Security Framework v4.5</p>
               {authView === 'login' && (
                 <button className="text-[10px] font-black uppercase tracking-widest text-slate-600 hover:text-indigo-400 transition-all">
                   Forgot Access Key?
                 </button>
               )}
            </div>
          </div>
        </div>
      </div>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center space-x-8 opacity-40">
         <div className="flex items-center space-x-2">
            <ShieldAlert className="w-3 h-3 text-slate-600" />
            <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest">End-to-End Encrypted</span>
         </div>
         <div className="w-px h-3 bg-slate-800" />
         <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Cluster 001-A-Stable</span>
      </div>
    </div>
  );
};

export default Auth;

