};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ShieldAlert, Users, Activity, Search, CheckCircle, RefreshCw, ShieldCheck,
  Trash2, DollarSign, Terminal, Cpu, Database, CloudCog, Power,
  ShieldEllipsis, KeyRound, Mail, AlertTriangle, Binary, Shield, 
  ArrowRight, Eye, UserCheck, LayoutDashboard, Wand2, ShoppingBag, 
  BookOpen, FileSpreadsheet, Lock, Unlock, Zap, Layers, Server, Globe,
  Network, Code, Radio, Settings, PowerOff, Sparkles, Megaphone,
  Box, Upload, History, FileText, Smartphone as MobileIcon, UserPlus
} from 'lucide-react';
import { UserProfile, SiteConfig } from '../types';
import { api } from '../services/apiService';

type AdminTab = 'nodes' | 'matrix' | 'features' | 'telemetry' | 'deploy';

const AdminPanel: React.FC = () => {
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [loginStep, setLoginStep] = useState<'creds' | 'otp'>('creds');
  const [adminCreds, setAdminCreds] = useState({ email: 'admin@lumina.com', password: '' });
  const [otpValue, setOtpValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<AdminTab>('features');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>([]);

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : {
      maintenanceMode: false,
      activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
      globalAnnouncement: "System normal. All nodes operational.",
      version: "4.5.1",
      changelog: "Stability improvements.",
      lastUpdateDate: Date.now()
    };
  });

  const [deploymentForm, setDeploymentForm] = useState({
    version: siteConfig.version,
    changelog: siteConfig.changelog
  });

  const [systemStats, setSystemStats] = useState({ cpu: 42, memory: 68, storage: 84, traffic: 1204, threats: 0 });

  const loadData = async () => {
    setIsRefreshing(true);
    try {
      const fetchedUsers = await api.getUsers();
      setUsers(fetchedUsers);
    } catch (e) {
      console.error("Admin data fetch failed", e);
    } finally {
      setIsRefreshing(false);
    }
  };

  useEffect(() => {
    if (isUnlocked) loadData();
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.floor(Math.random() * 20) + 30,
        memory: Math.floor(Math.random() * 10) + 60,
        traffic: prev.traffic + Math.floor(Math.random() * 10),
        threats: Math.random() > 0.98 ? prev.threats + 1 : prev.threats
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isUnlocked]);

  const saveConfig = (newConfig: SiteConfig) => {
    setSiteConfig(newConfig);
    localStorage.setItem('lumina_site_config', JSON.stringify(newConfig));
    window.dispatchEvent(new Event('storage')); // Trigger update across tabs
  };

  const handleInitialLogin = async () => {
    setIsProcessing(true);
    setError(null);
    try {
      await api.adminLogin(adminCreds);
      setLoginStep('otp');
    } catch (e: any) {
      setError(e.message || "Invalid identity credentials");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleOtpVerify = async () => {
    setIsProcessing(true);
    setError(null);
    try {
      const res = await api.verifyAdminOtp({ email: adminCreds.email, otp: otpValue });
      localStorage.setItem('lumina_token', res.token);
      setIsUnlocked(true);
    } catch (e: any) {
      setError(e.message || "OTP verification failed");
    } finally {
      setIsProcessing(false);
    }
  };

  const toggleModule = (module: keyof SiteConfig['activeModules']) => {
    const newConfig = {
      ...siteConfig,
      activeModules: {
        ...siteConfig.activeModules,
        [module]: !siteConfig.activeModules[module]
      }
    };
    saveConfig(newConfig);
  };

  const deployUpdate = () => {
    setIsProcessing(true);
    setTimeout(() => {
      const newConfig = {
        ...siteConfig,
        version: deploymentForm.version,
        changelog: deploymentForm.changelog,
        lastUpdateDate: Date.now()
      };
      saveConfig(newConfig);
      setIsProcessing(false);
      alert(`Update v${deploymentForm.version} deployed to all nodes.`);
    }, 2000);
  };

  if (!isUnlocked) {
    return (
      <div className="h-[80vh] flex flex-col items-center justify-center p-6 animate-in fade-in duration-1000">
        <div className="w-full max-w-xl bg-black border border-rose-500/20 rounded-[4rem] p-16 shadow-[0_0_100px_rgba(225,29,72,0.1)] relative overflow-hidden space-y-12 text-center">
           <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-transparent via-rose-500 to-transparent animate-pulse" />
