                  </div>
                </div>
                <div className="space-y-2 text-left">
                  <label className="text-[10px] font-black text-slate-700 uppercase tracking-widest ml-2">Superuser Security Key</label>
                  <div className="relative group">
                    <KeyRound className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-800 group-focus-within:text-rose-500 transition-colors" />
                    <input type="password" value={adminCreds.password} onChange={(e) => setAdminCreds({...adminCreds, password: e.target.value})} placeholder="••••••••" className="w-full bg-slate-950/50 border border-slate-900 rounded-[1.8rem] py-5 pl-16 pr-8 text-sm text-white outline-none focus:border-rose-500/50 font-mono tracking-widest" />
                  </div>
                </div>
                <button onClick={handleInitialLogin} disabled={isProcessing || !adminCreds.password} className="w-full py-6 bg-rose-600 hover:bg-rose-500 text-white rounded-[2rem] text-[11px] font-black uppercase tracking-[0.4em] transition-all disabled:opacity-30 flex items-center justify-center shadow-[0_15px_30px_rgba(225,29,72,0.2)] active:scale-95">
                  {isProcessing ? <RefreshCw className="w-6 h-6 animate-spin" /> : "Initiate Terminal Protocol"}
                </button>
             </div>
           ) : (
             <div className="space-y-8 animate-in zoom-in-95 duration-500">
                <div className="p-8 bg-emerald-500/5 border border-emerald-500/10 rounded-[2rem] text-center">
                   <p className="text-[11px] font-black text-emerald-500 uppercase tracking-[0.3em]">Verification Cipher Dispatched</p>
                </div>
                <div className="space-y-3">
                   <label className="text-[10px] font-black text-slate-700 uppercase tracking-widest text-center block">Enter 6-Digit Auth Code</label>
                   <input type="text" maxLength={6} value={otpValue} onChange={(e) => setOtpValue(e.target.value.replace(/\D/g, ''))} placeholder="000000" className="w-full bg-slate-950 border border-slate-900 rounded-[2rem] py-7 text-center font-black tracking-[1.5em] text-4xl text-emerald-500 outline-none focus:border-emerald-500/50 shadow-inner" />
                </div>
                <div className="flex gap-4">
                   <button onClick={() => setLoginStep('creds')} className="flex-1 py-5 bg-slate-900 text-slate-500 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:text-white transition-all">Back</button>
                   <button onClick={handleOtpVerify} disabled={isProcessing || otpValue.length < 6} className="flex-[2] py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl shadow-emerald-900/20">
                     {isProcessing ? <RefreshCw className="w-5 h-5 animate-spin mx-auto" /> : "Authorize Terminal"}
                   </button>
                </div>
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-in fade-in duration-1000 pb-20 font-mono">
      {/* Admin Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-10">
        <div className="flex items-center space-x-10">
           <div className="w-24 h-24 bg-emerald-600/10 rounded-[3rem] border border-emerald-500/30 flex items-center justify-center text-emerald-500 shadow-[0_0_50px_rgba(16,185,129,0.1)] relative group">
              <ShieldCheck className="w-12 h-12 group-hover:scale-110 transition-transform duration-700" />
              <div className="absolute -top-2 -right-2 w-6 h-6 bg-emerald-500 rounded-full border-[4px] border-slate-950 animate-pulse" />
