          <button onClick={() => { setIsUnlocked(false); setLoginStep('creds'); }} className="px-6 py-4 rounded-[1.8rem] text-rose-500 hover:bg-rose-600 hover:text-white transition-all ml-2 border border-rose-900/20">
            <Power className="w-5 h-5" />
