           <button 
             onClick={() => navigate('/admin')}
             className={`p-4 rounded-2xl transition-all group relative border ${isAdminPanel ? 'bg-emerald-600 border-emerald-500 text-white shadow-[0_0_20px_rgba(16,185,129,0.3)]' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500 hover:bg-emerald-500 hover:text-white'}`}
