          {showLangMenu && (
            <div className="absolute top-full right-0 mt-6 w-64 max-h-96 overflow-y-auto bg-slate-900 border border-white/10 rounded-[2rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.8)] p-4 z-[100] custom-scrollbar animate-in slide-in-from-top-4">
              {languages.map(lang => (
                <button key={lang.code} onClick={() => { setLanguage(lang.code); setShowLangMenu(false); }} className={`w-full flex items-center space-x-4 p-5 rounded-2xl text-[10px] font-black uppercase transition-all ${user.language === lang.code ? 'bg-indigo-600 text-white shadow-xl' : 'hover:bg-white/5 text-slate-500 hover:text-white'}`}>
                  <span className="text-lg">{lang.flag}</span> <span>{lang.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        <div onClick={() => navigate('/profile')} className="flex items-center space-x-5 cursor-pointer group relative">
           <div className={`relative p-1 rounded-[1.4rem] transition-all duration-700 ${
             user.role === 'admin' ? 'bg-emerald-500/20 shadow-[0_0_20px_rgba(16,185,129,0.2)]' : 'bg-indigo-600/20'
           }`}>
              <img src={user.avatar} className={`w-12 h-12 rounded-[1.1rem] border-2 transition-all duration-700 ${
                user.role === 'admin' ? 'border-emerald-500' : 'border-indigo-600'
