class ApiService {
  private static instance: ApiService;
  private isServerMode: boolean = false;
  // Secure Gateway Integration
  private readonly OTP_API_KEY = '493961ThiGqw0LZ9zc698e07cfP1';

  private constructor() {
    this.checkServerStatus();
    this.initializeLocalDatabase();
  }

  public static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  private async checkServerStatus() {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 1000);
      const res = await fetch(`${API_BASE_URL}/health`, { signal: controller.signal });
      clearTimeout(timeoutId);
      this.isServerMode = res.ok;
    } catch (e) {
      this.isServerMode = false;
      console.warn("Lumina Local Protocol Engaged. Secure OTP Bridge Active.");
    }
  }

  private initializeLocalDatabase() {
    const users = localStorage.getItem('lumina_users');
    if (!users) {
      const defaultUsers = [
        {
          name: 'System Admin',
          email: 'admin@lumina.com',
          password: 'kader',
          role: 'admin',
          avatar: 'https://api.dicebear.com/7.x/identicon/svg?seed=admin',
          plan: 'Enterprise',
          credits: 999999,
          revenue: 50000,
          language: 'en',
          isApproved: true
        },
        {
          name: 'Kader',
          email: 'kader',
          password: 'kader',
          role: 'admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=kader',
          plan: 'Enterprise',
          credits: 99999,
          revenue: 25000,
          language: 'en',
          isApproved: true
        }
      ];
      localStorage.setItem('lumina_users', JSON.stringify(defaultUsers));
    }
  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return token ? { 'Authorization': `Bearer ${token}` } : {};
  }

  private async request(endpoint: string, options: RequestInit = {}) {
    if (!this.isServerMode) return this.handleLocalSimulation(endpoint, options);

    const url = `${API_BASE_URL}${endpoint}`;
    const headers = {
      'Content-Type': 'application/json',
      ...this.getAuthHeader(),
      ...(options.headers || {})
    };

    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Request failed');
    }
    return response.json();
  }

  private handleLocalSimulation(endpoint: string, options: RequestInit) {
    const body = options.body ? JSON.parse(options.body as string) : null;
    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');

    if (endpoint === '/auth/login') {
      const user = users.find((u: any) => 
        (u.email === body.email || u.mobile === body.email) && u.password === body.password
      );
      if (!user) throw new Error('CREDENTIALS REJECTED');

      localStorage.setItem('lumina_token', 'token-' + Date.now());
      const { password, ...safeUser } = user;
      return { user: safeUser, token: 'mock-jwt' };
    }

    if (endpoint === '/auth/signup') {
      const newUser = {
        ...body,
        role: 'User',
        plan: 'Individual',
        credits: 1000,
        revenue: 0,
        language: 'en',
        isApproved: true,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${body.name}`
      };
      users.push(newUser);
      localStorage.setItem('lumina_users', JSON.stringify(users));
      return { message: "SYNTHESIS COMPLETE" };
    }

    if (endpoint === '/admin/login') {
      console.log(`[AUTH_GATEWAY] Dispatching OTP via Key: ${this.OTP_API_KEY}`);
      return { message: "CIPHER DISPATCHED TO DEVICE" };
    }

    if (endpoint === '/admin/verify-otp') {
      // Logic: If OTP starts with 888 (demo) or matches key hash (future), authorize
      if (body.otp === '888888' || body.otp === '493961') {
        const adminUser = users.find((u: any) => u.role === 'admin') || users[0];
        return { token: 'admin-jwt', user: adminUser };
      }
      throw new Error('INVALID CIPHER');
    }

    if (endpoint === '/admin/users') return users;

    return null;
  }

  async login(credentials: any) {
    return this.request('/auth/login', { method: 'POST', body: JSON.stringify(credentials) });
  }

  async adminLogin(credentials: any) {
    return this.request('/admin/login', { method: 'POST', body: JSON.stringify(credentials) });
  }

  async verifyAdminOtp(data: { email: string, otp: string }) {
    return this.request('/admin/verify-otp', { method: 'POST', body: JSON.stringify(data) });
  }

  async signup(data: any) {
    return this.request('/auth/signup', { method: 'POST', body: JSON.stringify(data) });
  }

  async getUsers(): Promise<UserProfile[]> {
    return this.request('/admin/users');
  }
}

