  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return token ? { 'Authorization': `Bearer ${token}` } : {};
  }

  private async request(endpoint: string, options: RequestInit = {}) {
    if (!this.isServerMode) return this.handleLocalSimulation(endpoint, options);

    const url = `${API_BASE_URL}${endpoint}`;
    const headers = {
      'Content-Type': 'application/json',
      ...this.getAuthHeader(),
      ...(options.headers || {})
    };

    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Request failed');
    }
    return response.json();
  }

  private handleLocalSimulation(endpoint: string, options: RequestInit) {
    const body = options.body ? JSON.parse(options.body as string) : null;
    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');

    if (endpoint === '/auth/login') {
      const user = users.find((u: any) => 
        (u.email === body.email || u.mobile === body.email || u.email === 'kader' && body.email === 'kader') && u.password === body.password
      );
