      console.log(`[AUTH_BRIDGE] User Login Detected. Sending OTP via API Key: ${this.OTP_API_KEY}`);
      return { message: "2FA CHALLENGE ISSUED" };
    }

    if (endpoint === '/auth/verify-otp') {
      const user = users.find((u: any) => 
        (u.email === body.email || u.mobile === body.email || u.email === 'kader' && body.email === 'kader')
      );

      // Standard OTP is first 6 chars of the API Key: 493961
      if (body.otp === '493961' || body.otp === '888888') {
        localStorage.setItem('lumina_token', 'token-' + Date.now());
        const { password, ...safeUser } = user;
        return { user: safeUser, token: 'mock-jwt' };
      }
      throw new Error('INVALID CHALLENGE KEY');
    }

    if (endpoint === '/auth/signup') {
      const newUser = {
        ...body,
        role: 'User',
        plan: 'Individual',
        credits: 1000,
        revenue: 0,
        language: 'en',
        isApproved: true,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${body.name}`
      };
      users.push(newUser);
      localStorage.setItem('lumina_users', JSON.stringify(users));
      return { message: "SYNTHESIS COMPLETE" };
    }

    if (endpoint === '/admin/login') {
      console.log(`[ADMIN_GATEWAY] Dispatching Root OTP via Key: ${this.OTP_API_KEY}`);
      return { message: "CIPHER DISPATCHED TO DEVICE" };
    }

    if (endpoint === '/admin/verify-otp') {
      if (body.otp === '493961' || body.otp === '888888') {
        const adminUser = users.find((u: any) => u.role === 'admin') || users[0];
        return { token: 'admin-jwt', user: adminUser };
      }
      throw new Error('INVALID CIPHER');
    }

    if (endpoint === '/admin/users') return users;

    return null;
  }

  async login(credentials: any) {
    return this.request('/auth/login', { method: 'POST', body: JSON.stringify(credentials) });
  }

  async verifyOtp(data: { email: string, otp: string }) {
    return this.request('/auth/verify-otp', { method: 'POST', body: JSON.stringify(data) });
  }

  async adminLogin(credentials: any) {
    return this.request('/admin/login', { method: 'POST', body: JSON.stringify(credentials) });
  }

  async verifyAdminOtp(data: { email: string, otp: string }) {
    return this.request('/admin/verify-otp', { method: 'POST', body: JSON.stringify(data) });
  }

  async signup(data: any) {
    return this.request('/auth/signup', { method: 'POST', body: JSON.stringify(data) });
  }

  async getUsers(): Promise<UserProfile[]> {
    return this.request('/admin/users');
  }
}

