import React, { useState, useRef, useEffect } from 'react';
import { 
  Paintbrush, Eraser, Square, Circle, Minus, Wand2, Save, Undo,
  Download, Sparkles, Box, Layers, Palette, 
  Trash2, RotateCcw, Monitor, MousePointer2, Pencil, Shapes,
  Users, UserPlus, BoxSelect, Move3d, Zap, Ghost, Eye, Maximize2,
  RefreshCw, Film, Play, Pause, ChevronLeft, ChevronRight,
  Scissors, Copy, Sliders, Brush, Frame
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'shape' | 'rigging' | 'select';
type RenderStyle = '3d-disney' | '2d-anime' | '3d-realistic' | 'comic' | 'stylized-vfx' | 'pixel-art' | 'game-asset';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#6366f1');
  const [strokeWidth, setStrokeWidth] = useState(10);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('3d-disney');

  // Animation State
  const [currentFrame, setCurrentFrame] = useState(0);
  const [frames, setFrames] = useState<string[]>(['']); // Base64 of frames
  const [isPlaying, setIsPlaying] = useState(false);

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#020617' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    // Save state to current frame
    const canvas = canvasRef.current;
    if (canvas) {
      const updatedFrames = [...frames];
      updatedFrames[currentFrame] = canvas.toDataURL();
      setFrames(updatedFrames);
    }
  };

  const addFrame = () => {
    const newFrames = [...frames, ''];
    setFrames(newFrames);
    setCurrentFrame(newFrames.length - 1);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && canvasRef.current) {
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    let styleInstruction = "";
    switch(renderStyle) {
      case '3d-disney': styleInstruction = "3D Pixar Disney style character, cinematic lighting, 8k professional render."; break;
      case '2d-anime': styleInstruction = "Modern high-quality anime character, detailed cel-shading, Ghibli style vibes."; break;
      case '3d-realistic': styleInstruction = "Unreal Engine 5 hyper-realistic character, MetaHuman quality, 8k octane render."; break;
      case 'comic': styleInstruction = "Graphic novel art, vibrant inks, dynamic character posing, professional comic style."; break;
      case 'stylized-vfx': styleInstruction = "Stylized character with magical VFX glowing elements and particle systems."; break;
      case 'game-asset': styleInstruction = "Character game asset sheet, front and side views, stylized low-poly but highly detailed textures."; break;
      default: styleInstruction = "Artistic character design.";
    }

    const finalPrompt = `Professional creative character asset based on user sketch: ${prompt}. ${styleInstruction}`;
    const result = await gemini.generateImage(finalPrompt, "1:1", true);

    if (result) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx && canvasRef.current) {
          ctx.drawImage(img, 0, 0, canvasRef.current.width, canvasRef.current.height);
          const updatedFrames = [...frames];
          updatedFrames[currentFrame] = canvasRef.current.toDataURL();
          setFrames(updatedFrames);
        }
        onSave({ 
          id: Date.now().toString(), 
          name: prompt.substring(0, 20) || 'Character Synth', 
          type: StudioMode.PAINT, 
          thumbnail: result, 
          updatedAt: Date.now(), 
          status: 'draft', 
          data: { prompt, renderStyle, frames } 
        });
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-4 animate-in fade-in duration-700 overflow-hidden">
      {/* Studio Header */}
      <div className="flex justify-between items-center bg-slate-900/80 backdrop-blur-xl p-4 rounded-[2rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-3 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-600/20">
              <UserPlus className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tight">Character <span className="text-indigo-500">Animation</span> Suite</h2>
              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mt-1">Full Neural Rigging & Frame Synthesis</p>
           </div>
        </div>
        <div className="flex items-center space-x-4">
          <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx && canvasRef.current) { ctx.fillStyle = '#020617'; ctx.fillRect(0,0,1600,1200); }
          }} className="px-5 py-2.5 bg-slate-800 text-slate-400 rounded-xl text-[9px] font-black uppercase tracking-widest border border-slate-700 hover:text-white transition-all">Reset</button>

          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-8 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Synthesize Identity
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         {/* Advanced Toolbar */}
         <div className="w-20 bg-slate-900/80 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-4 flex flex-col items-center gap-4 shadow-2xl">
            {[
              { id: 'brush', icon: Pencil, label: 'Drawing' },
              { id: 'eraser', icon: Eraser, label: 'Eraser' },
              { id: 'rigging', icon: Move3d, label: 'Rigging' },
              { id: 'select', icon: MousePointer2, label: 'Select' },
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                title={t.label}
                className={`p-4 rounded-2xl transition-all group relative ${tool === t.id ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white hover:bg-white/5'}`}
              >
                <t.icon className="w-5 h-5" />
              </button>
            ))}
            <div className="w-10 h-px bg-white/5 my-2" />
            <input 
              type="color" 
              value={color} 
              onChange={(e) => setColor(e.target.value)} 
              className="w-10 h-10 rounded-xl border-none cursor-pointer p-0 bg-transparent overflow-hidden shadow-xl" 
            />
            <div className="w-10 h-px bg-white/5 my-2" />
            <div className="flex flex-col gap-2">
               {['#6366f1', '#10b981', '#f43f5e', '#ffffff'].map(c => (
                 <button key={c} onClick={() => setColor(c)} className={`w-8 h-8 rounded-full border-2 transition-all ${color === c ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'}`} style={{ backgroundColor: c }} />
               ))}
