                 <div className={`w-44 flex items-center px-6 rounded-2xl ${track.color} border border-white/5 shrink-0 shadow-lg z-10 transition-all group-hover:scale-[1.02]`}>
                    <track.icon className="w-5 h-5 mr-4" />
                    <span className="text-[10px] font-black truncate tracking-widest uppercase">{track.label}</span>
                 </div>
                 <div 
                   ref={track.id === 1 ? timelineRef : null}
                   onMouseDown={handleTimelineInteraction}
                   className="flex-1 bg-white/[0.03] rounded-2xl ml-4 relative overflow-hidden border border-white/[0.05] cursor-text group-hover:bg-white/[0.05] transition-all"
                 >
                    {layers.filter(l => l.track === track.id).map(l => (
                      <div 
                        key={l.id}
                        onClick={(e) => { e.stopPropagation(); setSelectedLayerId(l.id); }}
                        style={{ left: `${l.start}%`, width: `${l.duration}%` }}
                        className={`absolute inset-y-2 rounded-2xl border flex items-center px-5 cursor-pointer transition-all shadow-xl ${selectedLayerId === l.id ? 'bg-white text-black border-white ring-[10px] ring-rose-500/10 z-20 scale-y-110' : 'bg-slate-800 text-slate-400 border-white/5 hover:bg-slate-700 z-10'}`}
                      >
                         <div className={`w-3 h-3 rounded-full mr-3 shrink-0 ${selectedLayerId === l.id ? 'bg-rose-500' : 'bg-slate-600'} shadow-lg`} />
                         <span className="text-[10px] font-black uppercase truncate tracking-tighter">{l.name}</span>
                      </div>
                    ))}
                 </div>
              </div>
            ))}

            {/* Playhead Indicator */}
            <div 
              style={{ left: `calc(176px + 16px + ${playheadPos}%)` }}
              className="absolute top-0 bottom-0 w-px bg-rose-500 shadow-[0_0_25px_rgba(244,63,94,1)] z-30 transition-all duration-75 pointer-events-none"
            >
               <div className="absolute top-0 -left-2 w-5 h-5 bg-rose-500 rounded-full border-[3px] border-white shadow-2xl flex items-center justify-center">
                  <div className="w-1.5 h-1.5 bg-white rounded-full animate-pulse" />
               </div>
            </div>
         </div>
      </div>
    </div>
  );
};

