import React, { useState, useRef, useEffect } from 'react';
import { 
  Paintbrush, Eraser, Square, Circle, Minus, Wand2, Save, Undo,
  Download, Sparkles, Box, Layers, Palette, 
  Trash2, RotateCcw, Monitor, MousePointer2, Pencil, Shapes,
  Users, UserPlus, BoxSelect, Move3d, Zap, Ghost, Eye, Maximize2,
  RefreshCw, Film, Play, Pause, ChevronLeft, ChevronRight,
  Scissors, Copy, Sliders, Brush, Frame, Plus, Star, Rigging,
  Dna, Layout
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'shape' | 'rigging' | 'select' | 'bone';
type RenderStyle = '3d-disney' | '2d-anime' | '3d-realistic' | 'comic' | 'stylized-vfx' | 'pixel-art' | 'game-asset';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#6366f1');
  const [strokeWidth, setStrokeWidth] = useState(10);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('3d-disney');

  // Animation State
  const [currentFrame, setCurrentFrame] = useState(0);
  const [frames, setFrames] = useState<string[]>(['']); // Base64 of frames
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(12); // FPS

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  useEffect(() => {
    let interval: any;
    if (isPlaying) {
      interval = setInterval(() => {
        setCurrentFrame(prev => (prev + 1) % frames.length);
      }, 1000 / playbackSpeed);
    }
    return () => clearInterval(interval);
  }, [isPlaying, frames.length, playbackSpeed]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (ctx && canvas && frames[currentFrame]) {
      const img = new Image();
      img.onload = () => {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
      };
      img.src = frames[currentFrame];
    }
  }, [currentFrame]);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#020617' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    if (canvas) {
      const updatedFrames = [...frames];
      updatedFrames[currentFrame] = canvas.toDataURL();
      setFrames(updatedFrames);
    }
  };

  const addFrame = () => {
    const newFrames = [...frames, ''];
    setFrames(newFrames);
    setCurrentFrame(newFrames.length - 1);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && canvasRef.current) {
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    let styleInstruction = "";
    switch(renderStyle) {
      case '3d-disney': styleInstruction = "3D Pixar/Disney style high-quality character render, cinematic lighting, sub-surface scattering."; break;
      case '2d-anime': styleInstruction = "Professional anime character concept art, high-fidelity cel shading, crisp line work."; break;
      case '3d-realistic': styleInstruction = "Unreal Engine 5 metahuman realistic character, 8k octane render, hyper-detailed textures."; break;
      case 'comic': styleInstruction = "Vintage comic book art style character, bold inks, dynamic action pose, detailed hatching."; break;
      case 'stylized-vfx': styleInstruction = "Stylized character with magical glowing particles, fantasy aesthetics, high-energy visuals."; break;
      case 'game-asset': styleInstruction = "Game character asset sheet, front and side view references, stylized low-poly professional model look."; break;
      default: styleInstruction = "Artistic creative character design.";
    }

    const finalPrompt = `Synthesize professional character asset from this sketch concept: ${prompt}. ${styleInstruction}`;
    const result = await gemini.generateImage(finalPrompt, "1:1", true);

    if (result) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx && canvasRef.current) {
          ctx.drawImage(img, 0, 0, canvasRef.current.width, canvasRef.current.height);
          const updatedFrames = [...frames];
          updatedFrames[currentFrame] = canvasRef.current.toDataURL();
          setFrames(updatedFrames);
        }
        onSave({ 
          id: Date.now().toString(), 
          name: prompt.substring(0, 20) || 'Character Identity Synth', 
          type: StudioMode.PAINT, 
          thumbnail: result, 
          updatedAt: Date.now(), 
          status: 'published', 
          data: { prompt, renderStyle, frames } 
        });
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-4 animate-in fade-in duration-700 overflow-hidden text-slate-200">
      {/* Studio Header */}
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-2xl p-4 rounded-[2rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-3 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-600/20">
              <UserPlus className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Animation <span className="text-indigo-500">Suite</span> Pro</h2>
              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mt-1">Full Neural Rigging & Frame Synthesis</p>
           </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1.5 rounded-2xl border border-white/5">
             <button onClick={() => setPlaybackSpeed(12)} className={`px-4 py-2 rounded-xl text-[9px] font-black transition-all ${playbackSpeed === 12 ? 'bg-white text-black' : 'text-slate-500'}`}>12 FPS</button>
             <button onClick={() => setPlaybackSpeed(24)} className={`px-4 py-2 rounded-xl text-[9px] font-black transition-all ${playbackSpeed === 24 ? 'bg-white text-black' : 'text-slate-500'}`}>24 FPS</button>
          </div>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-8 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Synthesize Frames
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         {/* Advanced Toolbar */}
         <div className="w-20 bg-slate-900/90 backdrop-blur-3xl rounded-[2.5rem] border border-white/5 p-4 flex flex-col items-center gap-5 shadow-2xl overflow-y-auto custom-scrollbar">
            {[
              { id: 'brush', icon: Pencil, label: 'Drawing' },
              { id: 'eraser', icon: Eraser, label: 'Eraser' },
              { id: 'rigging', icon: Move3d, label: '3D Rigging' },
              { id: 'bone', icon: Dna, label: 'Bone Structure' },
              { id: 'select', icon: MousePointer2, label: 'Select Node' },
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                title={t.label}
                className={`p-4 rounded-2xl transition-all group relative ${tool === t.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-500 hover:text-white hover:bg-white/5'}`}
              >
                <t.icon className="w-5 h-5 group-hover:scale-110 transition-transform" />
              </button>
            ))}
            <div className="w-10 h-px bg-white/10 my-1" />
            <input 
              type="color" 
              value={color} 
              onChange={(e) => setColor(e.target.value)} 
              className="w-10 h-10 rounded-xl border-none cursor-pointer p-0 bg-transparent overflow-hidden shadow-xl" 
            />
            <div className="w-10 h-px bg-white/10 my-1" />
            <div className="flex flex-col gap-2">
               {['#6366f1', '#10b981', '#f43f5e', '#ffffff', '#000000'].map(c => (
                 <button key={c} onClick={() => setColor(c)} className={`w-8 h-8 rounded-full border-2 transition-all ${color === c ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'}`} style={{ backgroundColor: c }} />
               ))}
            </div>
         </div>

         {/* Main Workspace */}
         <div className="flex-1 flex flex-col gap-4">
            <div className="flex-1 bg-black rounded-[3.5rem] border border-white/5 p-6 flex flex-col shadow-2xl relative overflow-hidden group">
               <div className="flex-1 bg-[#020617] rounded-[2.5rem] overflow-hidden relative cursor-crosshair border border-white/5 shadow-inner group ring-1 ring-white/5">
                  <canvas 
                    ref={canvasRef} width={1600} height={1200}
                    onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                    className="w-full h-full object-contain"
                  />
                  {isGenerating && (
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-2xl flex flex-col items-center justify-center z-50 animate-in fade-in duration-500 text-center px-10">
                        <div className="w-20 h-20 border-[6px] border-indigo-500 border-t-transparent rounded-full animate-spin mb-8 shadow-[0_0_60px_rgba(99,102,241,0.5)]" />
                        <p className="text-indigo-400 font-black uppercase tracking-[0.5em] text-sm animate-pulse">Constructing Neural Skeleton...</p>
                    </div>
                  )}
               </div>

               {/* Frame Timeline Integration */}
               <div className="mt-4 bg-slate-900/60 backdrop-blur-3xl p-4 rounded-3xl border border-white/5 flex items-center space-x-4">
                  <div className="flex items-center space-x-3 mr-4 border-r border-white/10 pr-4">
                     <button onClick={() => setIsPlaying(!isPlaying)} className={`p-3 rounded-2xl transition-all shadow-xl ${isPlaying ? 'bg-rose-600 text-white' : 'bg-indigo-600 text-white'}`}>
                        {isPlaying ? <Pause className="w-5 h-5" /> : <Play className="w-5 h-5 fill-current" />}
                     </button>
                     <button className="p-3 bg-slate-800 text-slate-500 hover:text-white rounded-2xl"><RotateCcw className="w-5 h-5" /></button>
                  </div>
                  <div className="flex-1 flex space-x-3 overflow-x-auto scrollbar-hide py-1">
                     {frames.map((f, i) => (
                        <button 
                           key={i} 
                           onClick={() => setCurrentFrame(i)}
                           className={`w-20 h-16 rounded-2xl shrink-0 border-2 transition-all relative overflow-hidden bg-[#020617] group/frame ${currentFrame === i ? 'border-indigo-500 ring-8 ring-indigo-500/10' : 'border-white/5 hover:border-white/20'}`}
                        >
                           {f ? <img src={f} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-[10px] font-black text-slate-700 uppercase">F{i+1}</div>}
                           {currentFrame === i && <div className="absolute inset-0 bg-indigo-600/20" />}
                           <div className="absolute bottom-1 right-1 px-1 bg-black/60 rounded text-[6px] font-black text-white opacity-40 uppercase">0.0{i}s</div>
                        </button>
                     ))}
                     <button onClick={addFrame} className="w-20 h-16 rounded-2xl shrink-0 border-2 border-dashed border-slate-700 flex items-center justify-center text-slate-600 hover:border-indigo-500 hover:text-white hover:bg-indigo-600/5 transition-all">
                        <Plus className="w-6 h-6" />
                     </button>
                  </div>
               </div>
            </div>

            {/* AI Control Center */}
            <div className="bg-slate-900/90 p-5 rounded-[2.5rem] border border-white/5 flex gap-4 shadow-2xl">
              <div className="flex-1 relative group">
                <input 
                  value={prompt} onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Describe Character: 'Space Marine with plasma sword'..." 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-8 py-4 text-white text-sm font-black uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none"
                />
                <Sparkles className="absolute right-6 top-1/2 -translate-y-1/2 w-5 h-5 text-indigo-500 animate-pulse" />
              </div>
              <div className="flex bg-slate-950 border border-slate-800 p-1 rounded-2xl">
                {[
                  { id: '3d-disney', label: 'Disney' },
                  { id: '2d-anime', label: 'Anime' },
                  { id: 'game-asset', label: 'Game' }
                ].map(s => (
                  <button 
                    key={s.id} 
                    onClick={() => setRenderStyle(s.id as RenderStyle)}
                    className={`px-8 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${renderStyle === s.id ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'}`}
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>
         </div>

         {/* Animation & Rigging Panel */}
         <div className="w-80 bg-slate-900/40 backdrop-blur-3xl rounded-[3rem] border border-white/5 p-8 flex flex-col gap-8 shadow-2xl overflow-y-auto custom-scrollbar">
            <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Layout className="w-5 h-5 mr-3 text-indigo-400" /> Animation Rig</h3>

            <div className="flex-1 space-y-8 pr-1">
               <div className="space-y-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">Motion Templates</p>
