                     <button onClick={() => { setActiveMode(p.type); navigate(`/${p.type}`); }} className="p-6 bg-white text-black rounded-full shadow-2xl hover:scale-110 transition-all">
                        <Plus className="w-8 h-8" />
                     </button>
