  const [duration, setDuration] = useState("30-60");
  const [vadooVid, setVadooVid] = useState<string | null>(null);

  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Master Cinematic 4K', type: 'video', start: 0, duration: 60, content: 'https://picsum.photos/seed/v-master/1280/720', track: 1, opacity: 100, scale: 1 },
    { id: '2', name: 'Ambient Soundscape', type: 'audio', start: 0, duration: 90, content: 'audio-src', track: 0, volume: 80 },
    { id: '3', name: 'Neural VFX Overlay', type: 'vfx', start: 10, duration: 30, content: 'vfx-src', track: 2, opacity: 50 },
    { id: '4', name: 'Dynamic Title Node', type: 'text', start: 5, duration: 25, content: 'PRATIK PRODUCTION', track: 3, opacity: 100 },
  ]);

  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const timelineRef = useRef<HTMLDivElement>(null);
  const activeLayer = layers.find(l => l.id === selectedLayerId) || layers[0];

  const handleTimelineInteraction = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const percentage = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setPlayheadPos(percentage);
