        throw new Error("Invalid API Response");
      }
    } catch (err) {
      console.error("Vadoo API Synthesis Failed", err);
      setStatusMessage("External API Synthesis Failed. Reverting to Gemini.");

      // Fallback to Gemini
      const gemini = GeminiService.getInstance();
      const videoUrl = await gemini.generateVideo(`Professional clip about: ${topic}. Style: ${theme}`, aspectRatio === '16:9' ? '16:9' : '9:16');
