const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [showUpdateModal, setShowUpdateModal] = useState(false);
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { 
      maintenanceMode: false, 
      activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true, notebook: true }, 
      globalAnnouncement: "",
      version: "4.5.1",
      changelog: "Stability improvements and UI refinements.",
      lastUpdateDate: Date.now()
    };
  });

  useEffect(() => {
    const syncConfig = () => {
      const saved = localStorage.getItem('lumina_site_config');
      if (saved) {
        const newConfig = JSON.parse(saved);
        if (newConfig.version !== siteConfig.version && user?.role !== 'admin') {
           setShowUpdateModal(true);
        }
        setSiteConfig(newConfig);
      }
    };
    window.addEventListener('storage', syncConfig);
    return () => window.removeEventListener('storage', syncConfig);
  }, [siteConfig.version, user?.role]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    } else {
      localStorage.removeItem('lumina_session');
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'admin' as any };
    setUser(elevatedUser);
  };

  if (!user) return <Auth onLogin={setUser} />;

  if (siteConfig.maintenanceMode && user.role !== 'admin') {
    return (
      <div className="min-h-screen bg-[#020617] flex items-center justify-center p-10 font-sans text-center">
         <div className="max-w-xl space-y-12">
            <div className="w-32 h-32 bg-rose-500/10 rounded-[3rem] border border-rose-500/30 flex items-center justify-center text-rose-500 mx-auto shadow-[0_0_50px_rgba(244,63,94,0.2)] animate-pulse">
               <ShieldAlert className="w-16 h-16" />
            </div>
            <div className="space-y-4">
              <h1 className="text-5xl font-black text-white uppercase tracking-tighter">System <span className="text-rose-500">Standby</span></h1>
              <p className="text-slate-400 font-medium text-lg uppercase tracking-widest leading-relaxed">
                The global node is currently undergoing high-priority maintenance. Standard sessions are restricted.
              </p>
            </div>
            <div className="p-8 bg-slate-900/50 rounded-[2rem] border border-white/5 font-mono text-xs text-slate-500">
               <div className="flex items-center justify-center space-x-3 mb-4">
                  <RefreshCw className="w-4 h-4 animate-spin" />
                  <span>Synchronizing Kernel Build {siteConfig.version}</span>
               </div>
               <p>{siteConfig.globalAnnouncement || "Rerouting traffic to stable clusters. ETA: T-Minus 20 minutes."}</p>
            </div>
            <button onClick={() => window.location.reload()} className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-600 hover:text-white transition-colors">Attempt Re-Handshake</button>
         </div>
      </div>
    );
  }

  const isRtl = ['ar'].includes(user.language);

  return (
    <HashRouter>
      <div className={`flex h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans ${isRtl ? 'rtl' : 'ltr'}`}>
        {showUpdateModal && (
          <div className="fixed inset-0 z-[2000] bg-slate-950/90 backdrop-blur-2xl flex items-center justify-center p-6 animate-in fade-in zoom-in-95 duration-500">
             <div className="w-full max-w-xl bg-indigo-900 border border-indigo-500/30 rounded-[4rem] p-16 shadow-[0_0_150px_rgba(99,102,241,0.2)] relative overflow-hidden text-center">
                <div className="absolute top-0 right-0 p-10 opacity-5 pointer-events-none">
                  <Sparkles className="w-64 h-64 text-white" />
                </div>
                <div className="w-24 h-24 bg-white/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 shadow-2xl">
                   <Zap className="w-12 h-12 text-indigo-400 fill-current" />
                </div>
                <h2 className="text-4xl font-black text-white uppercase tracking-tighter mb-4">System Update Deployed</h2>
                <p className="text-indigo-200 text-xs font-black uppercase tracking-[0.4em] mb-10">Lumina Version {siteConfig.version}</p>
                <div className="bg-black/40 p-8 rounded-[2.5rem] border border-white/5 text-left mb-10 max-h-48 overflow-y-auto custom-scrollbar">
                   <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-3">Changelog:</p>
                   <p className="text-sm text-slate-300 font-medium leading-relaxed whitespace-pre-wrap">{siteConfig.changelog}</p>
                </div>
                <button onClick={() => setShowUpdateModal(false)} className="w-full py-6 bg-white text-indigo-600 rounded-[2rem] font-black uppercase text-xs tracking-[0.5em] shadow-2xl hover:scale-105 active:scale-95 transition-all">
                  Initialize New Core
                </button>
             </div>
          </div>
        )}

        <div className="fixed top-0 inset-x-0 h-10 bg-black/40 backdrop-blur-md flex items-center justify-between px-6 z-[100] border-b border-white/5 select-none">
           <div className="flex items-center space-x-2.5">
              <div className="w-3 h-3 rounded-full bg-rose-500/80 shadow-[0_0_10px_rgba(244,63,94,0.3)]" />
              <div className="w-3 h-3 rounded-full bg-amber-500/80 shadow-[0_0_10px_rgba(245,158,11,0.3)]" />
              <div className="w-3 h-3 rounded-full bg-emerald-500/80 shadow-[0_0_10px_rgba(16,185,129,0.3)]" />
           </div>
           <p className="text-[10px] font-black uppercase tracking-[0.6em] text-slate-500 pl-16">Lumina Enterprise Creative Studio x64</p>
           <div className="flex items-center space-x-6">
              <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">Build {siteConfig.version}-Stable</span>
              <div className="w-20" />
           </div>
        </div>

        <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} activeMode={activeMode} setActiveMode={setActiveMode} lang={user.language as any} isAdmin={user.role === 'admin'} activeModules={siteConfig.activeModules} />

        <div className="flex-1 flex flex-col min-w-0 h-full relative pt-10">
          <Header user={user} onLogout={() => setUser(null)} setLanguage={(l) => setUser({...user, language: l})} onElevate={handleElevate} announcement={siteConfig.globalAnnouncement} />

          <main className="flex-1 overflow-hidden relative bg-gradient-to-br from-[#020617] to-[#0f172a]">
            <div className="absolute inset-0 overflow-auto p-4 md:p-10 custom-scrollbar">
                <Routes>
                <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} announcement={siteConfig.globalAnnouncement} />} />
                <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
                <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
                <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
                <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
                <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
                <Route path="/notebook" element={<NotebookStudio onSave={saveProject} />} />
                <Route path="/education" element={<EducationStudio />} />
                <Route path="/templates" element={<TemplatesGallery />} />
                <Route path="/admin" element={user.role === 'admin' ? <AdminPanel /> : <Navigate to="/" />} />
                <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={() => setUser(null)} />} />
                <Route path="/storage" element={<CloudStorage projects={projects} />} />
                <Route path="/shop" element={<Shop user={user} />} />
                <Route path="/communication" element={<CommunicationStudio user={user} />} />
                <Route path="/office" element={<OfficeSuite user={user} onSave={saveProject} />} />
                <Route path="/support" element={<SupportCenter user={user} />} />
                </Routes>
            </div>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
