import { GoogleGenAI, Type, Modality } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  // Generate a video from a prompt using the Veo model.
  async generateVideo(prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: aspectRatio
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!downloadLink) return null;

      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      const blob = await response.blob();
      return URL.createObjectURL(blob);
    } catch (error) {
      console.error("Video generation failed", error);
      return null;
    }
  }

  // NotebookLM Style: Comprehensive artifact generation
  async generateArtifact(sourceText: string, type: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptMap: Record<string, string> = {
        quiz: "Create a 5-question multiple choice quiz based on this text. Return as JSON with 'questions' array containing 'question', 'options' (array), and 'correctIndex'.",
        flashcards: "Create 8 flashcards. Return as JSON with 'cards' array containing 'front' and 'back'.",
        slides: "Create a 5-slide presentation outline. Return as JSON with 'slides' array containing 'title' and 'bullets' (array).",
        mindmap: "Create a conceptual mind-map structure. Return as JSON with 'nodes' array containing 'id', 'label', and 'parentId'.",
        datatable: "Create a data table comparing key concepts. Return as JSON with 'headers' (array) and 'rows' (array of arrays).",
        infographic: "Summarize this content for an infographic. Return as JSON with 'sections' array containing 'icon', 'headline', and 'stats' or 'text'."
      };

      const prompt = `${promptMap[type] || "Summarize this content:"} Source: "${sourceText.substring(0, 4000)}"`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error(`Artifact generation failed for ${type}`, error);
      return null;
    }
  }

  // NotebookLM Style: Generate a multi-speaker deep dive podcast script and audio.
  async generateNotebookDeepDive(sourceText: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const scriptResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a podcast script between two hosts (Joe and Jane) summarizing and discussing this content: "${sourceText.substring(0, 4000)}". The tone should be engaging and educational.`,
      });

      const script = scriptResponse.text || "";
      const audioResponse = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Deep Dive Podcast: ${script}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            multiSpeakerVoiceConfig: {
              speakerVoiceConfigs: [
                { speaker: 'Joe', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
                { speaker: 'Jane', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } }
              ]
            }
          },
        },
      });

      const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return {
        script,
        audioUrl: base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null
      };
    } catch (error) {
      console.error("Notebook deep dive failed", error);
      return null;
    }
  }

  // Generate an image from a prompt.
  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1", qualityOrImage: boolean | string = false) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isHighQuality = typeof qualityOrImage === 'boolean' ? qualityOrImage : !!qualityOrImage;
      const imageData = typeof qualityOrImage === 'string' ? qualityOrImage : null;

      const model = isHighQuality ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
      const parts: any[] = [{ text: prompt }];
      if (imageData) {
        const matches = imageData.match(/^data:([^;]+);base64,(.+)$/);
        if (matches) {
          parts.push({ inlineData: { mimeType: matches[1], data: matches[2] } });
        }
      }

      const response = await ai.models.generateContent({
        model: model,
        contents: { parts },
        config: { imageConfig: { aspectRatio, imageSize: model === 'gemini-3-pro-image-preview' ? "1K" : undefined } }
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }
      return null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const mimeType = base64Image.match(/^data:([^;]+);base64,/)?.[1] || 'image/png';
      const data = base64Image.split(',')[1] || base64Image;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data, mimeType } },
            { text: instruction }
          ]
        }
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }
      return null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async refineText(text: string, style: 'formal' | 'creative' | 'short') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Refine the following text to be more ${style}: "${text}"`,
      });
      return response.text;
    } catch (error) {
      console.error("Text refinement failed", error);
      return text;
    }
  }

  async generateSpeech(text: string, voice: string = 'Kore') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice } } },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null;
    } catch (error) {
      console.error("Speech generation failed", error);
      return null;
    }
  }

  async generateAdCampaign(theme: string, category: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a professional marketing campaign for a brand with theme: "${theme}" in the business category: "${category}". Provide a catchy headline, a short persuasive description, and exactly two call-to-action button labels.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              headline: { type: Type.STRING },
              description: { type: Type.STRING },
              ctas: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["headline", "description", "ctas"],
          }
        }
      });
      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error("Ad campaign generation failed", error);
      return { headline: "Innovative Branding", description: "Transform your vision into high-impact reality.", ctas: ["Discover", "Synthesize"] };
    }
  }
}

