  const [sources, setSources] = useState<SourceNode[]>([]);
  const [inputText, setInputText] = useState("");
  const [inputName, setInputName] = useState("");
  const [isSynthesizing, setIsSynthesizing] = useState(false);
  const [activeArtifact, setActiveArtifact] = useState<NotebookArtifact | null>(null);
  const [artifacts, setArtifacts] = useState<NotebookArtifact[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  const handleAddSource = () => {
    if (!inputText || !inputName) return;
    const newNode: SourceNode = {
      id: Date.now().toString(),
      name: inputName,
      content: inputText,
      type: 'text'
    };
    setSources([...sources, newNode]);
    setInputText("");
    setInputName("");
  };

  const generateArtifact = async (type: NotebookArtifact['type']) => {
    if (sources.length === 0) return;
    setIsSynthesizing(true);
    const fullContext = sources.map(s => `[SOURCE: ${s.name}]\n${s.content}`).join('\n\n');
    const gemini = GeminiService.getInstance();

    let result;
    if (type === 'audio') {
      result = await gemini.generateNotebookDeepDive(fullContext);
    } else if (type === 'video') {
       // Mock whiteboard video synthesis via multiple Gemini image calls + narration simulation
       const img = await gemini.generateImage(`Whiteboard summary illustration of: ${sources[0].name}. Simple, professional, educational.`, "16:9");
       result = { videoUrl: img, summary: "Whiteboard Synthesis Active" };
