import { GoogleGenAI, Type, Modality } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  async generateVideo(prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: aspectRatio
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!downloadLink) return null;

      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      const blob = await response.blob();
      return URL.createObjectURL(blob);
    } catch (error) {
      console.error("Video generation failed", error);
      return null;
    }
  }

  async generateArtifact(sourceText: string, type: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptMap: Record<string, { prompt: string, schema: any }> = {
        quiz: {
          prompt: "Create a multiple choice quiz based on the provided text.",
          schema: {
            type: Type.OBJECT,
            properties: {
              questions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    question: { type: Type.STRING },
                    options: { type: Type.ARRAY, items: { type: Type.STRING } },
                    correctIndex: { type: Type.NUMBER }
                  },
                  required: ["question", "options", "correctIndex"]
                }
              }
            },
            required: ["questions"]
          }
        },
        flashcards: {
          prompt: "Generate study flashcards summarizing the key concepts.",
          schema: {
            type: Type.OBJECT,
            properties: {
              cards: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    front: { type: Type.STRING },
                    back: { type: Type.STRING }
                  },
                  required: ["front", "back"]
                }
              }
            },
            required: ["cards"]
          }
        },
        slides: {
          prompt: "Outline a professional slide deck presentation.",
          schema: {
            type: Type.OBJECT,
            properties: {
              slides: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    bullets: { type: Type.ARRAY, items: { type: Type.STRING } }
                  },
                  required: ["title", "bullets"]
                }
              }
            },
            required: ["slides"]
          }
        },
        mindmap: {
          prompt: "Structure a conceptual mind-map hierarchy.",
          schema: {
            type: Type.OBJECT,
            properties: {
              nodes: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    id: { type: Type.STRING },
                    label: { type: Type.STRING },
                    parentId: { type: Type.STRING }
                  },
                  required: ["id", "label"]
                }
              }
            },
            required: ["nodes"]
          }
        },
        datatable: {
          prompt: "Compare key data points in a structured table format.",
          schema: {
            type: Type.OBJECT,
            properties: {
              headers: { type: Type.ARRAY, items: { type: Type.STRING } },
              rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } }
            },
            required: ["headers", "rows"]
          }
        },
        infographic: {
          prompt: "Summarize content for a visual infographic layout.",
          schema: {
            type: Type.OBJECT,
            properties: {
              sections: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    icon: { type: Type.STRING },
                    headline: { type: Type.STRING },
                    text: { type: Type.STRING }
                  },
                  required: ["icon", "headline", "text"]
                }
              }
            },
            required: ["sections"]
          }
        }
      };

      const entry = promptMap[type] || {
        prompt: "Summarize this content:",
        schema: { type: Type.OBJECT, properties: { summary: { type: Type.STRING } }, required: ["summary"] }
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `${entry.prompt} Source: "${sourceText.substring(0, 8000)}"`,
        config: {
          responseMimeType: "application/json",
          responseSchema: entry.schema
        }
      });

      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error(`Artifact generation failed for ${type}`, error);
      return null;
    }
  }

  async askSource(sourceText: string, query: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Context: "${sourceText.substring(0, 8000)}"\n\nQuestion: "${query}"\n\nProvide a detailed answer based strictly on the context.`,
      });
      return response.text || "I couldn't find an answer in your sources.";
    } catch (error) {
      console.error("Source chat failed", error);
      return "An error occurred while analyzing the sources.";
    }
  }

  async generateNotebookDeepDive(sourceText: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const scriptResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Create a podcast script between host Joe and guest Jane discussing this material: "${sourceText.substring(0, 4000)}". Make it insightful and conversational.`,
      });

      const script = scriptResponse.text || "Deep dive script generated.";
      const audioResponse = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Deep Dive Session: ${script}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            multiSpeakerVoiceConfig: {
              speakerVoiceConfigs: [
                { speaker: 'Joe', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
                { speaker: 'Jane', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } }
              ]
            }
          },
        },
      });

      const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return { script, audioUrl: base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null };
    } catch (error) {
      console.error("Notebook deep dive failed", error);
      return null;
    }
  }

  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1", qualityOrImage: boolean | string = false) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isHighQuality = typeof qualityOrImage === 'boolean' ? qualityOrImage : !!qualityOrImage;
      const imageData = typeof qualityOrImage === 'string' ? qualityOrImage : null;
      const model = isHighQuality ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

      const parts: any[] = [{ text: prompt }];
      if (imageData) {
        const matches = imageData.match(/^data:([^;]+);base64,(.+)$/);
        if (matches) parts.push({ inlineData: { mimeType: matches[1], data: matches[2] } });
      }

      const response = await ai.models.generateContent({
        model: model,
        contents: { parts },
        config: { imageConfig: { aspectRatio, imageSize: model === 'gemini-3-pro-image-preview' ? "1K" : undefined } }
      });

      const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const matches = base64Image.match(/^data:([^;]+);base64,(.+)$/);
      if (!matches) return null;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: matches[1], data: matches[2] } },
            { text: instruction }
          ]
        }
      });

      const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async refineText(text: string, style: 'formal' | 'creative' | 'short') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Refine this text to be ${style}: "${text}"`,
      });
      return response.text || text;
    } catch (error) {
      return text;
    }
  }

  async generateSpeech(text: string, voice: string = 'Kore') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice } } },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null;
    } catch (error) {
      return null;
    }
  }

  async generateAdCampaign(theme: string, category: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a marketing campaign for: ${theme} in ${category}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              headline: { type: Type.STRING },
              description: { type: Type.STRING },
              ctas: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["headline", "description", "ctas"],
          }
        }
      });
      return JSON.parse(response.text || "{}");
    } catch (error) {
      return { headline: "Lumina Brand", description: "Creative synthesis.", ctas: ["Start", "Sync"] };
    }
  }
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  Library, Upload, Sparkles, Play, Pause, FileText, Download, 
  Share2, Plus, Trash2, RefreshCw, Volume2, Mic2, Brain, 
  CheckCircle, Headphones, ArrowRight, Video, HelpCircle, 
  Layers, Presentation, LayoutTemplate, Network, Table, Layout, X, Info,
  ChevronRight, Lightbulb, Target, Zap, MessageSquare, Send, History,
  FileDown, FileUp, Globe, Hash
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, NotebookArtifact } from '../types';

interface NotebookStudioProps {
  onSave: (p: Project) => void;
}

interface SourceNode {
  id: string;
  name: string;
  content: string;
}

const NotebookStudio: React.FC<NotebookStudioProps> = ({ onSave }) => {
  const [sources, setSources] = useState<SourceNode[]>([]);
  const [inputText, setInputText] = useState("");
  const [inputName, setInputName] = useState("");
  const [chatQuery, setChatQuery] = useState("");
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([]);
  const [isSynthesizing, setIsSynthesizing] = useState(false);
  const [isChatting, setIsChatting] = useState(false);
  const [activeArtifact, setActiveArtifact] = useState<NotebookArtifact | null>(null);
  const [artifacts, setArtifacts] = useState<NotebookArtifact[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleAddSource = () => {
    if (!inputText || !inputName) return;
    setSources([...sources, { id: Date.now().toString(), name: inputName, content: inputText }]);
    setInputText(""); setInputName("");
  };

  const handleChat = async () => {
    if (!chatQuery || sources.length === 0) return;
    const userMsg = chatQuery;
    setChatQuery("");
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsChatting(true);

    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const answer = await GeminiService.getInstance().askSource(fullContext, userMsg);

    setChatHistory(prev => [...prev, { role: 'ai', text: answer }]);
    setIsChatting(false);
  };

  const generateArtifact = async (type: NotebookArtifact['type']) => {
    if (sources.length === 0) return;
    setIsSynthesizing(true);
    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const gemini = GeminiService.getInstance();

    let result;
    if (type === 'audio') {
      result = await gemini.generateNotebookDeepDive(fullContext);
    } else if (type === 'video') {
       const img = await gemini.generateImage(`Cinematic whiteboard education visual for: ${sources[0].name}. Professional tutorial style, 4K render.`, "16:9");
       result = { videoUrl: img, summary: `Whiteboard synthesis complete for topic: ${sources[0].name}` };
    } else {
      result = await gemini.generateArtifact(fullContext, type);
    }

    if (result) {
      const newArt: NotebookArtifact = { 
        type, 
        title: `${type.toUpperCase()} - ${sources[0].name.substring(0, 12)}`, 
        data: result, 
        createdAt: Date.now() 
      };
      setArtifacts([newArt, ...artifacts]);
      setActiveArtifact(newArt);
    }
    setIsSynthesizing(false);
