                       <div key={i} className={`w-1.5 bg-indigo-500/40 rounded-full ${isPlaying ? 'animate-pulse' : ''}`} style={{ height: `${h * (isPlaying ? 14 : 6)}px` }} />
                    ))}
                 </div>
