               <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Brain className="w-5 h-5 mr-3 text-emerald-400" /> Artifact Synthesis</h4>
               <div className="grid grid-cols-2 gap-3">
