                   </div>
                   {renderArtifactContent()}
                 </div>
               ) : (
                 <div className="flex-1 flex flex-col items-center justify-center text-center p-10 space-y-12">
                    <div className="p-16 bg-slate-900/60 rounded-[5rem] border border-slate-800 text-slate-700 shadow-inner relative">
                       <Brain className="w-48 h-48 relative z-10 transition-transform duration-1000" />
                    </div>
                    <div>
                       <h4 className="text-6xl font-black text-slate-400 uppercase tracking-tighter">Awaiting Input</h4>
                       <p className="text-slate-600 text-xl max-w-xl mx-auto mt-8 leading-relaxed font-medium">Inject raw nodes or ask a question below to initialize the universal synthesizer.</p>
                    </div>
                 </div>
               )}
            </div>

            {/* Chat Terminal */}
            <div className="flex-1 bg-slate-900/60 backdrop-blur-3xl rounded-[3.5rem] border border-white/5 flex flex-col shadow-2xl min-h-0">
               <div className="flex-1 overflow-y-auto p-10 custom-scrollbar space-y-6">
                  {chatHistory.length === 0 && (
