                     <button onClick={handleChat} disabled={isChatting || sources.length === 0} className="absolute right-3 top-1/2 -translate-y-1/2 p-4 bg-indigo-600 rounded-2xl text-white shadow-xl hover:bg-indigo-500 transition-all disabled:opacity-20">
