export default NotebookStudio;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  Library, Upload, Sparkles, Play, Pause, FileText, Download, 
  Share2, Plus, Trash2, RefreshCw, Volume2, Mic2, Brain, 
  CheckCircle, Headphones, ArrowRight, Video, HelpCircle, 
  Layers, Presentation, LayoutTemplate, Network, Table, Layout, X, Info,
  ChevronRight, Lightbulb, Target, Zap, MessageSquare, Send, History,
  FileDown, FileUp, Globe, Hash, Command, Terminal, Settings
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, NotebookArtifact } from '../types';

interface NotebookStudioProps {
  onSave: (p: Project) => void;
}

interface SourceNode {
  id: string;
  name: string;
  content: string;
}

const NotebookStudio: React.FC<NotebookStudioProps> = ({ onSave }) => {
  const [sources, setSources] = useState<SourceNode[]>([]);
  const [inputText, setInputText] = useState("");
  const [inputName, setInputName] = useState("");
  const [chatQuery, setChatQuery] = useState("");
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai' | 'system', text: string }[]>([]);
  const [isSynthesizing, setIsSynthesizing] = useState(false);
  const [isChatting, setIsChatting] = useState(false);
  const [activeArtifact, setActiveArtifact] = useState<NotebookArtifact | null>(null);
  const [artifacts, setArtifacts] = useState<NotebookArtifact[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleAddSource = () => {
    if (!inputText || !inputName) return;
    setSources([...sources, { id: Date.now().toString(), name: inputName, content: inputText }]);
    setInputText(""); setInputName("");
    setChatHistory(prev => [...prev, { role: 'system', text: `NODE_INJECTED: Source "${inputName}" synchronized to intelligence matrix.` }]);
  };

  const processCommand = async (input: string) => {
    const cmd = input.toLowerCase();

    if (cmd.includes('/generate') || cmd.includes('create') || cmd.includes('generate')) {
      if (sources.length === 0) {
        setChatHistory(prev => [...prev, { role: 'ai', text: "Critical Error: No sources found. Please inject knowledge nodes before generating artifacts." }]);
        return;
      }

      if (cmd.includes('quiz')) return generateArtifact('quiz');
      if (cmd.includes('podcast') || cmd.includes('audio')) return generateArtifact('audio');
      if (cmd.includes('video') || cmd.includes('whiteboard')) return generateArtifact('video');
      if (cmd.includes('mind map') || cmd.includes('mindmap')) return generateArtifact('mindmap');
      if (cmd.includes('slide') || cmd.includes('presentation')) return generateArtifact('slides');
      if (cmd.includes('flashcard')) return generateArtifact('flashcards');
      if (cmd.includes('table') || cmd.includes('data')) return generateArtifact('datatable');
      if (cmd.includes('infographic')) return generateArtifact('infographic');
    }

    // Default to chat if no command detected
    handleChat(input);
  };

  const handleChat = async (queryOverride?: string) => {
    const queryToUse = queryOverride || chatQuery;
    if (!queryToUse || sources.length === 0) return;

    if (!queryOverride) {
      setChatHistory(prev => [...prev, { role: 'user', text: queryToUse }]);
      setChatQuery("");
    }

    setIsChatting(true);
    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const answer = await GeminiService.getInstance().askSource(fullContext, queryToUse);

    setChatHistory(prev => [...prev, { role: 'ai', text: answer }]);
    setIsChatting(false);
  };

  const generateArtifact = async (type: NotebookArtifact['type']) => {
    if (sources.length === 0) return;
    setIsSynthesizing(true);

    setChatHistory(prev => [...prev, { role: 'system', text: `SYNTHESIS_INIT: Commencing ${type.toUpperCase()} artifact construction...` }]);

    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const gemini = GeminiService.getInstance();

    let result;
    try {
      if (type === 'audio') {
        result = await gemini.generateNotebookDeepDive(fullContext);
      } else if (type === 'video') {
         const img = await gemini.generateImage(`Cinematic whiteboard education visual for: ${sources[0].name}. Professional tutorial style, 4K render.`, "16:9");
         result = { videoUrl: img, summary: `Whiteboard synthesis complete for topic: ${sources[0].name}` };
      } else {
        result = await gemini.generateArtifact(fullContext, type);
      }

      if (result) {
        const newArt: NotebookArtifact = { 
          type, 
          title: `${type.toUpperCase()} - ${sources[0].name.substring(0, 12)}`, 
          data: result, 
          createdAt: Date.now() 
        };
        setArtifacts([newArt, ...artifacts]);
        setActiveArtifact(newArt);
        setChatHistory(prev => [...prev, { role: 'ai', text: `Success: ${type.toUpperCase()} artifact generated and pushed to the stack.` }]);
      }
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'system', text: `SYNTHESIS_FAILED: Neural pathway blocked for ${type.toUpperCase()}.` }]);
    }

    setIsSynthesizing(false);
  };

  const renderArtifactContent = () => {
    if (!activeArtifact) return null;
    const { type, data } = activeArtifact;

    switch(type) {
      case 'audio':
        return (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="bg-black/60 rounded-[3rem] p-12 flex flex-col items-center border border-white/5 space-y-8 shadow-[inset_0_0_50px_rgba(0,0,0,0.5)]">
              <div className="flex items-center space-x-12">
                 <div className="text-center">
                    <div className="w-24 h-24 bg-indigo-600/20 border border-indigo-500/20 rounded-full flex items-center justify-center text-indigo-400 mb-4 shadow-[0_0_30px_indigo]">
                       <Mic2 className="w-10 h-10" />
                    </div>
                    <p className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Joe (Host)</p>
                 </div>
                 <div className="flex space-x-2 h-16 items-center">
                    {[1, 2, 3, 4, 5, 6, 5, 4, 3, 2, 1].map((h, i) => (
                       <div key={i} className={`w-1.5 bg-indigo-500/40 rounded-full ${isPlaying ? 'animate-pulse' : ''}`} style={{ height: `${h * (isPlaying ? 14 : 6)}px` }} />
                    ))}
                 </div>
                 <div className="text-center">
                    <div className="w-24 h-24 bg-rose-600/20 border border-rose-500/20 rounded-full flex items-center justify-center text-rose-400 mb-4 shadow-[0_0_30px_rose]">
                       <Mic2 className="w-10 h-10" />
                    </div>
                    <p className="text-[10px] font-black uppercase text-rose-400 tracking-widest">Jane (Guest)</p>
                 </div>
              </div>
              <div className="w-full max-w-lg">
                <audio ref={audioRef} src={data.audioUrl} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} className="hidden" />
                <button onClick={() => audioRef.current && (isPlaying ? audioRef.current.pause() : audioRef.current.play())} className="w-full py-8 bg-white text-black rounded-[2.5rem] flex items-center justify-center shadow-[0_20px_40px_rgba(0,0,0,0.4)] hover:scale-[1.02] transition-all">
                   {isPlaying ? <Pause className="w-12 h-12 fill-current" /> : <Play className="w-12 h-12 fill-current ml-2" />}
                </button>
              </div>
            </div>
            <div className="bg-slate-900/50 rounded-[3rem] p-10 border border-white/5 max-h-[400px] overflow-y-auto custom-scrollbar shadow-inner">
              <h5 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Insight Transcript</h5>
              <p className="text-slate-300 leading-relaxed font-medium whitespace-pre-wrap italic">"{data.script}"</p>
            </div>
          </div>
        );
      case 'quiz':
        return (
          <div className="grid grid-cols-1 gap-6 animate-in slide-in-from-bottom-8">
            {data.questions?.map((q: any, i: number) => (
              <div key={i} className="p-8 bg-slate-900 border border-white/5 rounded-[2.5rem] shadow-xl group hover:border-indigo-500/30 transition-all">
                <p className="text-[10px] font-black text-indigo-400 uppercase mb-4 tracking-[0.2em]">QUESTION_0{i+1}</p>
                <h4 className="text-xl font-black text-white uppercase mb-8 tracking-tight">{q.question}</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {q.options?.map((opt: string, idx: number) => (
                    <button key={idx} className="p-5 bg-black/40 border border-slate-800 rounded-2xl text-left text-xs font-bold text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all active:scale-95">{opt}</button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        );
      case 'flashcards':
        return (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 animate-in zoom-in-95">
            {data.cards?.map((c: any, i: number) => (
              <div key={i} className="perspective h-[300px] group cursor-pointer">
                <div className="relative w-full h-full transition-transform duration-700 preserve-3d group-hover:rotate-y-180">
                  <div className="absolute inset-0 backface-hidden bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 flex flex-col items-center justify-center text-center shadow-2xl">
                     <Lightbulb className="w-8 h-8 text-amber-400 mb-6" />
                     <h4 className="text-sm font-black text-white uppercase tracking-tight leading-relaxed">{c.front}</h4>
                  </div>
                  <div className="absolute inset-0 backface-hidden rotate-y-180 bg-indigo-600 rounded-[2.5rem] p-8 flex flex-col items-center justify-center text-center shadow-2xl border border-indigo-400/30">
                     <p className="text-xs font-bold text-white leading-relaxed">{c.back}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        );
      case 'mindmap':
        return (
          <div className="bg-slate-950/80 rounded-[4rem] border border-white/5 p-12 min-h-[500px] flex items-center justify-center overflow-hidden relative shadow-2xl">
             <div className="absolute inset-0 opacity-5 bg-[radial-gradient(circle_at_center,_#4f46e5_1px,_transparent_1px)] bg-[size:40px_40px]" />
             <div className="flex flex-wrap items-center justify-center gap-10 relative z-10">
                {data.nodes?.map((node: any) => (
                  <div key={node.id} className={`p-10 rounded-3xl border-2 transition-all hover:scale-110 shadow-2xl ${node.parentId ? 'bg-slate-900 border-indigo-500/20 text-slate-400' : 'bg-indigo-600 border-indigo-400 text-white scale-110 ring-[20px] ring-indigo-600/10'}`}>
                    <span className="text-xs font-black uppercase tracking-widest">{node.label}</span>
                  </div>
                ))}
             </div>
          </div>
        );
      case 'datatable':
        return (
          <div className="bg-slate-900 border border-slate-800 rounded-[3rem] p-4 shadow-2xl overflow-hidden">
             <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                    <tr className="bg-slate-950">
                      {data.headers?.map((h: string, i: number) => (
                        <th key={i} className="p-8 text-[10px] font-black text-indigo-400 uppercase tracking-widest border-b border-white/5">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/5">
                    {data.rows?.map((row: any[], i: number) => (
                      <tr key={i} className="hover:bg-indigo-500/5 transition-all">
                        {row.map((cell: string, idx: number) => (
                          <td key={idx} className="p-8 text-xs font-bold text-slate-300">{cell}</td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        );
      case 'slides':
        return (
          <div className="space-y-12 animate-in fade-in slide-in-from-right-8 duration-1000">
             {data.slides?.map((slide: any, i: number) => (
               <div key={i} className="aspect-video bg-white rounded-[2rem] p-16 shadow-2xl relative overflow-hidden group">
                  <div className="absolute top-0 left-0 w-4 h-full bg-indigo-600" />
                  <div className="flex flex-col h-full">
                     <h3 className="text-4xl font-black text-slate-950 uppercase tracking-tighter mb-12">{slide.title}</h3>
                     <ul className="space-y-6">
                        {slide.bullets?.map((b: string, idx: number) => (
                          <li key={idx} className="flex items-center text-slate-600 text-xl font-medium">
                             <div className="w-3 h-3 bg-indigo-600 rounded-full mr-6 shrink-0" />
                             {b}
                          </li>
                        ))}
                     </ul>
                  </div>
                  <div className="absolute bottom-12 right-12 text-[10px] font-black text-slate-300 uppercase tracking-widest">
                     Slide {i+1} of {data.slides.length}
