      return part ? `data:image/png;base64,${part.inlineData.data}` : null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const matches = base64Image.match(/^data:([^;]+);base64,(.+)$/);
      if (!matches) return null;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: matches[1], data: matches[2] } },
            { text: instruction }
          ]
        }
      });

      const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async generateSpeech(text: string, voice: string = 'Kore') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice } } },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null;
    } catch (error) {
      return null;
    }
  }

  async generateVideo(prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: aspectRatio
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!downloadLink) return null;

      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      const blob = await response.blob();
      return URL.createObjectURL(blob);
    } catch (error) {
      console.error("Video generation failed", error);
      return null;
    }
  }
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  Library, Upload, Sparkles, Play, Pause, FileText, Download, 
  Share2, Plus, Trash2, RefreshCw, Volume2, Mic2, Brain, 
  CheckCircle, Headphones, ArrowRight, Video, HelpCircle, 
  Layers, Presentation, LayoutTemplate, Network, Table, Layout, X, Info,
  ChevronRight, Lightbulb, Target, Zap, MessageSquare, Send, History,
  FileDown, FileUp, Globe, Hash, Command, Terminal, Settings, ExternalLink,
  Code, FileJson, FileCode, Search, Microscope
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, NotebookArtifact } from '../types';

interface NotebookStudioProps {
  onSave: (p: Project) => void;
}

interface SourceNode {
  id: string;
  name: string;
  content: string;
  type: 'text' | 'url';
  url?: string;
}

const NotebookStudio: React.FC<NotebookStudioProps> = ({ onSave }) => {
  const [sources, setSources] = useState<SourceNode[]>([]);
  const [inputText, setInputText] = useState("");
  const [inputName, setInputName] = useState("");
  const [inputUrl, setInputUrl] = useState("");
  const [showUrlField, setShowUrlField] = useState(false);
  const [chatQuery, setChatQuery] = useState("");
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai' | 'system', text: string }[]>([]);
  const [isSynthesizing, setIsSynthesizing] = useState(false);
  const [isChatting, setIsChatting] = useState(false);
  const [activeArtifact, setActiveArtifact] = useState<NotebookArtifact | null>(null);
  const [artifacts, setArtifacts] = useState<NotebookArtifact[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleAddSource = () => {
    if ((!inputText && !inputUrl) || !inputName) return;
    const newNode: SourceNode = { 
      id: Date.now().toString(), 
      name: inputName, 
      content: inputText || `Simulated semantic extraction from ${inputUrl}`, 
      type: inputUrl ? 'url' : 'text',
      url: inputUrl 
    };
    setSources([...sources, newNode]);
    setInputText(""); setInputName(""); setInputUrl(""); setShowUrlField(false);
    setChatHistory(prev => [...prev, { role: 'system', text: `NODE_LINK: ${newNode.name} added via ${newNode.type.toUpperCase()} interface.` }]);
  };

  const executeResearch = async () => {
    const researchTopic = "Economic impact of semaglutide on global healthcare systems";
    const researchInstructions = `Include specific figures, trends, statistics, and measurable outcomes. Prioritize reliable, up-to-date sources. Include inline citations and return all source metadata. Be analytical, avoid generalities.`;

    setChatHistory(prev => [...prev, { role: 'user', text: `Initiate Deep Research: ${researchTopic}` }]);
    setChatHistory(prev => [...prev, { role: 'system', text: "DEEP_RESEARCH: Allocating reasoning budget... (32k tokens reserved)" }]);
    setIsSynthesizing(true);

    const context = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const result = await GeminiService.getInstance().performDeepResearch(researchTopic, researchInstructions, context);

    if (result) {
      const researchArt: NotebookArtifact = {
        type: 'infographic',
        title: "RESEARCH_NODE: SEMAGLUTIDE_IMPACT",
        data: { sections: [{ headline: "Analytical Deep Dive", text: result }] },
        createdAt: Date.now()
      };
      setArtifacts([researchArt, ...artifacts]);
      setActiveArtifact(researchArt);
      setChatHistory(prev => [...prev, { role: 'ai', text: "Comprehensive research converged. The analytical report has been pushed to the viewport." }]);
    }
    setIsSynthesizing(false);
  };

  const processCommand = async (input: string) => {
    const cmd = input.toLowerCase();

    if (cmd.startsWith('/install') || cmd.startsWith('install')) {
      const skill = input.split(' ').slice(1).join(' ') || 'Default';
      setChatHistory(prev => [...prev, { role: 'user', text: input }]);
      setChatHistory(prev => [...prev, { role: 'system', text: `PROTOCOL_INIT: Downloading skill package "${skill}"...` }]);
      setTimeout(() => {
        setChatHistory(prev => [...prev, { role: 'ai', text: `Skill "${skill}" successfully integrated into your studio environment.` }]);
      }, 1500);
      setChatQuery("");
      return;
    }

    if (cmd.includes('research') && (cmd.includes('semaglutide') || cmd.includes('economic'))) {
      executeResearch();
      setChatQuery("");
      return;
    }

    if (cmd.includes('download') || cmd.includes('export')) {
      setChatHistory(prev => [...prev, { role: 'user', text: input }]);
      if (!activeArtifact) {
        setChatHistory(prev => [...prev, { role: 'ai', text: "Error: No active artifact selected for export." }]);
      } else {
        const format = cmd.includes('json') ? 'JSON' : cmd.includes('markdown') ? 'Markdown' : 'Industrial_RAW';
        setChatHistory(prev => [...prev, { role: 'system', text: `SERIALIZE: Converging artifact to ${format}...` }]);
        handleDownload(activeArtifact, format);
        setChatHistory(prev => [...prev, { role: 'ai', text: `Successfully exported ${activeArtifact.title} as ${format}.` }]);
      }
      setChatQuery("");
      return;
    }

    if (cmd.includes('generate') || cmd.includes('create') || cmd.startsWith('/')) {
      if (sources.length === 0) {
        setChatHistory(prev => [...prev, { role: 'ai', text: "Status 404: Knowledge matrix empty. Please add sources." }]);
        setChatQuery("");
        return;
      }
      setChatHistory(prev => [...prev, { role: 'user', text: input }]);
      if (cmd.includes('quiz')) generateArtifact('quiz');
      else if (cmd.includes('podcast') || cmd.includes('audio')) generateArtifact('audio');
      else if (cmd.includes('video') || cmd.includes('whiteboard')) generateArtifact('video');
      else if (cmd.includes('mind map') || cmd.includes('mindmap')) generateArtifact('mindmap');
      else if (cmd.includes('slide') || cmd.includes('presentation')) generateArtifact('slides');
      else if (cmd.includes('flashcard')) generateArtifact('flashcards');
      else if (cmd.includes('table') || cmd.includes('data')) generateArtifact('datatable');
      else if (cmd.includes('infographic')) generateArtifact('infographic');
      setChatQuery("");
      return;
    }

    handleChat(input);
  };

  const handleChat = async (queryOverride?: string) => {
    const queryToUse = queryOverride || chatQuery;
    if (!queryToUse || (sources.length === 0 && !queryOverride)) return;

    if (!queryOverride) {
      setChatHistory(prev => [...prev, { role: 'user', text: queryToUse }]);
      setChatQuery("");
    }

    setIsChatting(true);
    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const answer = await GeminiService.getInstance().askSource(fullContext, queryToUse);

    setChatHistory(prev => [...prev, { role: 'ai', text: answer }]);
    setIsChatting(false);
  };

  const generateArtifact = async (type: NotebookArtifact['type']) => {
    if (sources.length === 0) return;
    setIsSynthesizing(true);
    setChatHistory(prev => [...prev, { role: 'system', text: `SYNTHESIS: Rerouting neural buffers for ${type.toUpperCase()}...` }]);
    const fullContext = sources.map(s => `[${s.name}]: ${s.content}`).join('\n');
    const result = (type === 'audio') 
      ? await GeminiService.getInstance().generateNotebookDeepDive(fullContext)
      : (type === 'video')
      ? { videoUrl: await GeminiService.getInstance().generateImage(`Professional whiteboard education summary of: ${sources[0].name}`, "16:9"), summary: `Tutorial converged for ${sources[0].name}` }
      : await GeminiService.getInstance().generateArtifact(fullContext, type);

    if (result) {
      const newArt: NotebookArtifact = { type, title: `${type.toUpperCase()} - ${sources[0].name.substring(0, 12)}`, data: result, createdAt: Date.now() };
      setArtifacts([newArt, ...artifacts]);
      setActiveArtifact(newArt);
      setChatHistory(prev => [...prev, { role: 'ai', text: `Synthesis Complete: ${type.toUpperCase()} artifact stabilized.` }]);
    }
    setIsSynthesizing(false);
  };

  const handleDownload = (artifact: NotebookArtifact, format: string) => {
    const data = JSON.stringify(artifact.data, null, 2);
    const blob = new Blob([data], { type: format === 'JSON' ? 'application/json' : 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${artifact.title.replace(/\s+/g, '_')}.${format.toLowerCase()}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const renderArtifactContent = () => {
    if (!activeArtifact) return null;
    const { type, data } = activeArtifact;
    switch(type) {
      case 'audio':
        return (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="bg-black/60 rounded-[3rem] p-12 flex flex-col items-center border border-white/5 space-y-8">
              <div className="flex items-center space-x-12">
                 <div className="text-center">
                    <div className="w-24 h-24 bg-indigo-600/20 border border-indigo-500/20 rounded-full flex items-center justify-center text-indigo-400 mb-4 shadow-[0_0_30px_indigo]">
                       <Mic2 className="w-10 h-10" />
                    </div>
                    <p className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Joe (AI Host)</p>
                 </div>
                 <div className="flex space-x-2 h-16 items-center">
                    {[1, 2, 3, 4, 5, 6, 5, 4, 3, 2, 1].map((h, i) => (
                       <div key={i} className={`w-1.5 bg-indigo-500/40 rounded-full ${isPlaying ? 'animate-pulse' : ''}`} style={{ height: `${h * (isPlaying ? 14 : 6)}px` }} />
                    ))}
                 </div>
                 <div className="text-center">
                    <div className="w-24 h-24 bg-rose-600/20 border border-rose-500/20 rounded-full flex items-center justify-center text-rose-400 mb-4 shadow-[0_0_30px_rose]">
                       <Mic2 className="w-10 h-10" />
                    </div>
                    <p className="text-[10px] font-black uppercase text-rose-400 tracking-widest">Jane (Guest)</p>
                 </div>
              </div>
              <div className="w-full max-w-lg">
                <audio ref={audioRef} src={data.audioUrl} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} className="hidden" />
                <button onClick={() => audioRef.current && (isPlaying ? audioRef.current.pause() : audioRef.current.play())} className="w-full py-8 bg-white text-black rounded-[2.5rem] flex items-center justify-center shadow-[0_20px_40px_rgba(0,0,0,0.4)] hover:scale-[1.02] transition-all">
                   {isPlaying ? <Pause className="w-12 h-12 fill-current" /> : <Play className="w-12 h-12 fill-current ml-2" />}
                </button>
              </div>
            </div>
            <div className="bg-slate-900/50 rounded-[3rem] p-10 border border-white/5 max-h-[400px] overflow-y-auto custom-scrollbar">
              <h5 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Insight Transcript</h5>
              <p className="text-slate-300 leading-relaxed font-medium whitespace-pre-wrap italic">"{data.script}"</p>
            </div>
          </div>
        );
      case 'quiz':
        return (
          <div className="grid grid-cols-1 gap-6 animate-in slide-in-from-bottom-8">
            {data.questions?.map((q: any, i: number) => (
              <div key={i} className="p-8 bg-slate-900 border border-white/5 rounded-[2.5rem] shadow-xl group hover:border-indigo-500/30 transition-all">
                <p className="text-[10px] font-black text-indigo-400 uppercase mb-4 tracking-[0.2em]">QUESTION_0{i+1}</p>
