                  ))}
                </div>
              </div>
            ))}
          </div>
        );
      case 'infographic':
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-10">
            {data.sections?.map((s: any, i: number) => (
              <div key={i} className="p-12 bg-gradient-to-br from-slate-900 to-black border border-white/5 rounded-[3.5rem] shadow-2xl flex flex-col gap-6 group hover:border-indigo-500/30 transition-all">
                 <div className="flex items-center gap-6">
                   <div className="w-20 h-20 bg-indigo-600/10 border border-indigo-500/20 rounded-[1.5rem] flex items-center justify-center text-indigo-400 shrink-0 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-xl">
                      <Target className="w-10 h-10" />
                   </div>
