             <button onClick={() => setFps(12)} className={`px-8 py-2.5 rounded-xl text-[10px] font-black transition-all ${fps === 12 ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>12 FPS</button>
             <button onClick={() => setFps(24)} className={`px-8 py-2.5 rounded-xl text-[10px] font-black transition-all ${fps === 24 ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>24 FPS</button>
