const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [showUpdateModal, setShowUpdateModal] = useState(false);
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { 
      maintenanceMode: false, 
      activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true, notebook: true }, 
      globalAnnouncement: "",
      version: "6.0.1",
      changelog: "Overhauled Video, Photo, and Animation Studios for professional workflows.",
      lastUpdateDate: Date.now()
    };
  });

  useEffect(() => {
    const syncConfig = () => {
      const saved = localStorage.getItem('lumina_site_config');
      if (saved) {
        const newConfig = JSON.parse(saved);
        if (newConfig.version !== siteConfig.version && user?.role !== 'admin') {
           setShowUpdateModal(true);
        }
        setSiteConfig(newConfig);
      }
    };
    window.addEventListener('storage', syncConfig);
    return () => window.removeEventListener('storage', syncConfig);
  }, [siteConfig.version, user?.role]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    } else {
      localStorage.removeItem('lumina_session');
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'admin' as any };
    setUser(elevatedUser);
  };

  if (!user) return <Auth onLogin={setUser} />;

  const isRtl = ['ar'].includes(user.language);

  return (
    <HashRouter>
      <div className={`flex h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans ${isRtl ? 'rtl' : 'ltr'}`}>
