          id: Date.now().toString(), 
          name: `SYNTH: ${topic.substring(0, 12)}...`, 
          type: 'video', 
          start: playheadPos, 
          duration: 15, 
          content: videoUrl, 
          track: 1, 
          opacity: 100, 
          scale: 1,
          blendingMode: 'normal'
        };
        setLayers(prev => [...prev, newLayer]);
        setSelectedLayerId(newLayer.id);
