interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'rigging' | 'bones' | 'select' | 'erase';
type RenderStyle = 'Disney_Pixar' | 'Ghibli_Anime' | 'Cyber_Concept' | 'Realistic_UE5' | 'Paper_Sketch';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#10b981');
  const [strokeWidth, setStrokeWidth] = useState(8);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('Realistic_UE5');

  const [currentFrame, setCurrentFrame] = useState(0);
  const [frames, setFrames] = useState<string[]>(['']); 
  const [isPlaying, setIsPlaying] = useState(false);
  const [fps, setFps] = useState(12);
  const [rigPoints, setRigPoints] = useState<{id: number, x: number, y: number, name: string}[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const drawRig = (ctx: CanvasRenderingContext2D) => {
    ctx.strokeStyle = '#ef4444';
    ctx.lineWidth = 2;
    rigPoints.forEach((p, i) => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, 6, 0, Math.PI * 2);
        ctx.fillStyle = '#ef4444';
        ctx.fill();
        ctx.stroke();
        if (i > 0) {
            ctx.beginPath();
            ctx.moveTo(rigPoints[i-1].x, rigPoints[i-1].y);
            ctx.lineTo(p.x, p.y);
            ctx.setLineDash([5, 5]);
            ctx.stroke();
            ctx.setLineDash([]);
        }
    });
  };

  const handleCanvasInteraction = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (canvas.width / rect.width);
    const y = (e.clientY - rect.top) * (canvas.height / rect.height);

    if (tool === 'bones') {
        setRigPoints([...rigPoints, { id: Date.now(), x, y, name: `Bone_${rigPoints.length + 1}` }]);
    }
  };

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    // Multi-angle instruction for character creators
    const masterPrompt = `Industrial animation character model sheet: ${prompt}. 
    Style: ${renderStyle}. 
    Required Views: T-pose front, side profile, and 3/4 perspective. 
    High fidelity, professional character design, neutral lighting.`;

    const result = await gemini.generateImage(masterPrompt, "1:1", true);

    if (result) {
      const updatedFrames = [...frames];
      updatedFrames[currentFrame] = result;
      setFrames(updatedFrames);

      onSave({ 
        id: `anim-${Date.now()}`, 
        name: `Char: ${prompt.substring(0, 15)}`, 
        type: StudioMode.PAINT, 
        thumbnail: result, 
        updatedAt: Date.now(), 
        status: 'draft', 
        data: { prompt, renderStyle, frames: updatedFrames, rigPoints } 
      });
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      {/* Animation Studio Header */}
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl shadow-emerald-600/20 ring-2 ring-emerald-500/10">
              <Dna className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Neural <span className="text-emerald-400">Character</span> Creator</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Skeletal Rigging • Multi-View Synthesis</p>
           </div>
           <div className="h-8 w-px bg-white/10" />
           <div className="flex bg-black/40 p-1 rounded-xl">
             <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase bg-white text-black shadow-lg">2D_MESH</button>
             <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase text-slate-500 hover:text-white">3D_VOXEL</button>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 px-4 py-2 bg-slate-950 rounded-xl border border-white/5">
             <Globe className="w-4 h-4 text-emerald-400" />
             <span className="text-[9px] font-black uppercase tracking-widest text-slate-500">Multilingual Engine Active</span>
          </div>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-10 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Spawn Identity
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         {/* Advanced Animation Toolbar */}
         <div className="w-24 bg-slate-900/90 backdrop-blur-3xl rounded-[3rem] border border-white/5 p-4 flex flex-col items-center gap-5 shadow-2xl">
            {[
              { id: 'select', icon: MousePointer2, label: 'Select' },
              { id: 'brush', icon: Pencil, label: 'Sketch' },
              { id: 'erase', icon: Eraser, label: 'Erase' },
              { id: 'bones', icon: Bone, label: 'Rigging' },
              { id: 'rigging', icon: Move3d, label: 'Manipulate' },
            ].map(t => (
              <button 
                key={t.id} 
