                  <div className="absolute top-6 left-6 z-10 flex space-x-3">
                     <div className="px-4 py-1.5 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center">
                        <Box className="w-3 h-3 mr-2 text-emerald-400" /> View: Rig_Viewport_A
                     </div>
                     <div className="px-4 py-1.5 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center">
                        <Activity className="w-3 h-3 mr-2 text-indigo-400" /> State: Idle_Interp
                     </div>
                  </div>

                  {frames[currentFrame] ? (
                     <img src={frames[currentFrame]} className="w-full h-full object-contain" />
                  ) : (
                    <canvas 
                      ref={canvasRef} width={1600} height={1200}
                      onMouseDown={handleCanvasInteraction}
                      className="w-full h-full object-contain cursor-crosshair"
                    />
                  )}

                  {isGenerating && (
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center z-50">
                        <div className="w-20 h-20 border-[6px] border-emerald-500 border-t-transparent rounded-full animate-spin mb-6" />
                        <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Generating Character Mesh</h3>
