                       <button onClick={() => setRigPoints(rigPoints.filter(rp => rp.id !== p.id))} className="text-slate-700 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-3.5 h-3.5" /></button>
