    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { 
      maintenanceMode: false, 
      activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true, notebook: true }, 
      globalAnnouncement: "",
      version: "8.0.0",
      changelog: "Enterprise-grade update: Full NLE Video Editor, Pro Character Rigging, and Pixel Matrix 8.0 Photo Studio.",
      lastUpdateDate: Date.now()
    };
  });

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    } else {
      localStorage.removeItem('lumina_session');
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
