  COMMUNICATION = 'communication',
  OFFICE = 'office',
  SUPPORT = 'support'
}

export type UserRole = 'User' | 'Creator' | 'admin';

export type SubscriptionTier = 'Individual' | 'Creator' | 'Studio' | 'Enterprise';
export type VerificationStatus = 'none' | 'pending' | 'verified' | 'rejected';
export type MarketingAssetType = 'ad' | 'logo' | 'poster' | 'flyer' | 'invitation' | 'business_card' | 'certificate' | 'web_banner' | 'qr_code';

export interface UserProfile {
  name: string;
  role: UserRole;
  avatar: string;
  email: string;
  mobile?: string;
  dob?: string;
  plan: SubscriptionTier;
  credits: number;
  revenue: number;
  referralCode: string;
  referralCount: number;
  facebookConnected: boolean;
  githubConnected: boolean;
  twitterConnected: boolean;
  language: 'en' | 'bn' | 'hi' | 'es' | 'ar' | 'fr' | 'ru' | 'ja' | 'zh' | 'pt';
  studentVerificationStatus: VerificationStatus;
  studentIcardUrl?: string | null;
  isApproved: boolean;
  isBlocked?: boolean;
}

export interface Project {
  id: string;
  name: string;
  type: StudioMode;
  thumbnail: string;
  updatedAt: number;
  data: any;
  status: 'draft' | 'published' | 'archived';
  fileSize?: string;
  fileType?: string;
}

export interface SiteConfig {
  maintenanceMode: boolean;
  activeModules: {
