                <input 
                  value={prompt} onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Universal character prompt: 'Cyber-ronin with digital blade', 'Ghibli forest spirit'..." 
                  className="w-full bg-slate-950 border border-slate-800 rounded-full py-5 pl-14 pr-8 text-white text-xs font-black uppercase tracking-widest focus:ring-4 focus:ring-emerald-500/5 outline-none transition-all shadow-inner"
                />
