            <div className="space-y-6">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Target className="w-4 h-4 mr-2 text-emerald-400" /> Bone Hierarchy</h3>
              <div className="space-y-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-1">
                 {bones.length > 0 ? bones.map((bone, i) => (
                   <div key={bone.id} className="p-4 bg-black/40 border border-white/5 rounded-2xl flex items-center justify-between group hover:border-emerald-500/30 transition-all shadow-md">
