import React, { useState, useEffect, useRef } from 'react';
import { Terminal, X, ChevronRight, Hash, Command, Globe, Zap, Cpu, Database, Network, Search, AlertCircle } from 'lucide-react';
import { UserProfile, Project } from '../types';
import { GeminiService } from '../services/geminiService';

interface GlobalTerminalProps {
  isOpen: boolean;
  onClose: () => void;
  user: UserProfile;
}

interface LogEntry {
  type: 'cmd' | 'resp' | 'error' | 'sys';
  text: string;
  timestamp: string;
}

const GlobalTerminal: React.FC<GlobalTerminalProps> = ({ isOpen, onClose, user }) => {
  const [input, setInput] = useState("");
  const [logs, setLogs] = useState<LogEntry[]>([
    { type: 'sys', text: 'Lumina Studio OS v9.0.1 - Terminal Initialized', timestamp: new Date().toLocaleTimeString() },
    { type: 'sys', text: `Authorized node: ${user.email}`, timestamp: new Date().toLocaleTimeString() },
    { type: 'sys', text: 'Type "help" to see available protocols.', timestamp: new Date().toLocaleTimeString() }
  ]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [logs, isOpen]);

  const addLog = (type: LogEntry['type'], text: string) => {
    setLogs(prev => [...prev, { type, text, timestamp: new Date().toLocaleTimeString() }]);
  };

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const fullCmd = input.trim();
    addLog('cmd', fullCmd);
    setInput("");

    const parts = fullCmd.split(' ');
    const cmd = parts[0].toLowerCase();
    const args = parts.slice(1);

    switch (cmd) {
      case 'help':
        addLog('resp', 'Available Protocols:\n  curl [url]         - Execute network request\n  system --status    - Diagnostic report\n  ls                 - List active studio nodes\n  whoami             - Display identity metadata\n  ai [prompt]        - Query Neural Core\n  clear              - Wipe terminal buffer\n  exit               - Terminate session');
        break;
      case 'clear':
        setLogs([]);
        break;
      case 'exit':
        onClose();
        break;
      case 'whoami':
        addLog('resp', JSON.stringify({
          identity: user.name,
          uplink: user.email,
          tier: user.plan,
          credits: user.credits,
          language: user.language
        }, null, 2));
        break;
      case 'ls':
        const projects = JSON.parse(localStorage.getItem(`lumina_projects_${user.email}`) || '[]');
        addLog('resp', projects.length > 0 
          ? projects.map((p: Project) => `[${p.type.toUpperCase()}] ${p.name} (ID: ${p.id})`).join('\n')
          : 'No active project nodes found.'
        );
        break;
      case 'system':
        if (args[0] === '--status') {
          addLog('resp', 'DIAGNOSTIC REPORT:\n  Neural Core: ONLINE\n  Memory Matrix: 45% Load\n  VFX Acceleration: ENABLED\n  Cloud Sync: SYNCHRONIZED\n  Latency: 14ms');
        } else {
          addLog('error', 'Unknown argument. Usage: system --status');
        }
        break;
      case 'curl':
        if (!args[0]) {
          addLog('error', 'Target URL required. Usage: curl [url]');
          break;
        }
        addLog('sys', `Initiating handshake with ${args[0]}...`);
        try {
          // Simulated curl response for safety/CORS
          setTimeout(() => {
            addLog('resp', `HTTP/1.1 200 OK\nContent-Type: application/json\nX-Studio-Ref: ${Math.random().toString(36).substring(7)}\n\n{\n  "status": "success",\n  "data": "Simulated terminal payload extraction completed for ${args[0]}",\n  "node": "Lumina-Edge-1"\n}`);
          }, 800);
        } catch (err) {
          addLog('error', `Protocol failure: Connection refused for ${args[0]}`);
        }
        break;
      case 'ai':
        const prompt = args.join(' ');
        if (!prompt) {
          addLog('error', 'Neural input required. Usage: ai [prompt]');
          break;
        }
        addLog('sys', 'Consulting Neural Core...');
        try {
          const gemini = GeminiService.getInstance();
          const response = await gemini.refineText(prompt, 'professional');
          addLog('resp', `NEURAL_OUTPUT:\n${response}`);
        } catch (err) {
          addLog('error', 'Neural Core timeout. Check API_KEY.');
        }
        break;
      default:
        addLog('error', `Command not recognized: ${cmd}. Type "help" for protocols.`);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[300] bg-black/80 backdrop-blur-md flex items-center justify-center p-4 md:p-10 animate-in fade-in duration-300">
      <div className="w-full max-w-5xl h-[80vh] bg-[#020617] border border-white/10 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,1)] flex flex-col overflow-hidden relative">
        {/* Terminal Header */}
        <div className="bg-slate-900/50 border-b border-white/5 p-6 flex items-center justify-between">
           <div className="flex items-center space-x-4">
              <div className="w-3 h-3 rounded-full bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.5)]" />
              <div className="w-3 h-3 rounded-full bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]" />
              <div className="w-3 h-3 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
              <div className="h-4 w-px bg-white/10 mx-2" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500 flex items-center">
                 <Terminal className="w-3.5 h-3.5 mr-2 text-indigo-400" />
                 Lumina_Terminal_v9.0.1.sh
              </span>
           </div>
           <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-xl transition-all group">
              <X className="w-5 h-5 text-slate-500 group-hover:text-white" />
           </button>
        </div>

        {/* Console Viewport */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-10 font-mono text-[11px] leading-relaxed custom-scrollbar scrollbar-hide bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.03),rgba(0,255,0,0.01),rgba(0,0,255,0.03))] bg-[length:100%_2px,3px_100%]"
        >
          {logs.map((log, i) => (
            <div key={i} className="mb-3 animate-in slide-in-from-left-2 duration-200">
               <div className="flex items-center space-x-3 opacity-30 mb-1">
                  <span className="text-[8px] font-black">{log.timestamp}</span>
                  <div className="h-px flex-1 bg-white/5" />
               </div>
               <div className="flex items-start">
                  <span className="mr-3 shrink-0">
                    {log.type === 'cmd' ? <ChevronRight className="w-3 h-3 text-indigo-500" /> : 
                     log.type === 'error' ? <AlertCircle className="w-3 h-3 text-rose-500" /> : 
                     log.type === 'sys' ? <Zap className="w-3 h-3 text-amber-500" /> : 
                     <Hash className="w-3 h-3 text-emerald-500" />}
                  </span>
                  <pre className={`whitespace-pre-wrap flex-1 ${
                    log.type === 'cmd' ? 'text-white font-bold' : 
                    log.type === 'error' ? 'text-rose-400' : 
                    log.type === 'sys' ? 'text-amber-400/80 italic' : 
                    'text-emerald-400/90'
                  }`}>
                    {log.text}
                  </pre>
               </div>
            </div>
          ))}
          <div className="h-10" />
        </div>

        {/* Terminal Input Area */}
        <form onSubmit={handleCommand} className="p-8 bg-black/40 border-t border-white/5">
           <div className="flex items-center space-x-4 bg-slate-900/30 rounded-2xl p-4 border border-white/5 focus-within:border-indigo-500/50 transition-all shadow-inner">
