    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { 
      maintenanceMode: false, 
      activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true, notebook: true }, 
      globalAnnouncement: "",
      version: "9.0.1",
      changelog: "Industrial Desktop Overhaul: NLE Video Core, Character Identity Hub, and Multi-Pane Photo Matrix.",
      lastUpdateDate: Date.now()
    };
  });

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsTerminalOpen(prev => !prev);
      }
      if (e.key === '`') {
        e.preventDefault();
        setIsTerminalOpen(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    } else {
      localStorage.removeItem('lumina_session');
