document.addEventListener('DOMContentLoaded', () => {
    const mainPreview = document.getElementById('mainPreview');
    const playPauseBtn = document.getElementById('playPauseBtn');
    const rewindBtn = document.getElementById('rewindBtn');
    const forwardBtn = document.getElementById('forwardBtn');
    const currentTimeDisplay = document.getElementById('currentTime');
    const totalTimeDisplay = document.getElementById('totalTime');
    const playhead = document.getElementById('playhead');
    const trackArea = document.getElementById('trackArea');
    const mediaPool = document.getElementById('mediaPool');

    let isPlaying = false;

    // Format seconds to HH:MM:SS
    function formatTime(seconds) {
        if (isNaN(seconds)) return "00:00:00";
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = Math.floor(seconds % 60);
        return [h, m, s].map(v => v.toString().padStart(2, '0')).join(':');
    }

    // Toggle Playback
    function togglePlay() {
        if (isPlaying) {
            mainPreview.pause();
            playPauseBtn.innerHTML = '<i data-lucide="play"></i>';
        } else {
            mainPreview.play();
            playPauseBtn.innerHTML = '<i data-lucide="pause"></i>';
        }
        isPlaying = !isPlaying;
        lucide.createIcons();
    }

    playPauseBtn.addEventListener('click', togglePlay);

    mainPreview.addEventListener('timeupdate', () => {
        const current = mainPreview.currentTime;
        const duration = mainPreview.duration;

        currentTimeDisplay.textContent = formatTime(current);
        totalTimeDisplay.textContent = formatTime(duration);

        // Move Playhead
        if (duration > 0) {
            const percentage = (current / duration) * 100;
            // offset for track-info width (100px)
            playhead.style.left = `calc(100px + ${percentage}%)`;
        }
    });

    rewindBtn.addEventListener('click', () => {
        mainPreview.currentTime -= 5;
    });

    forwardBtn.addEventListener('click', () => {
        mainPreview.currentTime += 5;
    });

    // Timeline Interaction
    trackArea.addEventListener('click', (e) => {
        const rect = trackArea.getBoundingClientRect();
        const laneX = e.clientX - rect.left - 100; // Subtract info column
        const laneWidth = rect.width - 100;

        if (laneX >= 0) {
            const percentage = laneX / laneWidth;
            if (mainPreview.duration) {
                mainPreview.currentTime = mainPreview.duration * percentage;
            }
        }
    });

    // Mock Asset Library
    const mockAssets = [
        { name: 'Landscape_01', type: 'video', thumb: 'https://picsum.photos/seed/v1/200/120' },
        { name: 'City_Drone', type: 'video', thumb: 'https://picsum.photos/seed/v2/200/120' },
        { name: 'Piano_Melody', type: 'audio', thumb: 'https://picsum.photos/seed/a1/200/120' }
    ];

    function renderMediaPool() {
        mediaPool.innerHTML = mockAssets.map(asset => `
            <div class="media-item" style="margin-bottom: 15px; cursor: pointer;">
                <div style="width: 100%; aspect-ratio: 16/9; border-radius: 8px; overflow: hidden; background: #000; border: 1px solid var(--border);">
                    <img src="${asset.thumb}" style="width: 100%; height: 100%; object-fit: cover; opacity: 0.7;">
                </div>
                <p style="font-size: 9px; font-weight: 900; text-transform: uppercase; color: var(--text-dim); margin-top: 5px;">${asset.name}</p>
            </div>
        `).join('');
    }

    renderMediaPool();

    // Visual feedback for VU Meter
    setInterval(() => {
        if (isPlaying) {
            const fill = document.querySelector('.vu-fill');
            const h = 20 + Math.random() * 60;
            fill.style.height = `${h}%`;
        }
    }, 150);

    // Render icons again to catch dynamic changes
    lucide.createIcons();
});

import React, { useState, useRef, useEffect, useMemo } from 'react';
