  Maximize2, PlayCircle, Settings, Filter, Mic, Globe, MessageSquare,
  ExternalLink, Loader2, FastForward, Rewind, Layers3, Activity, 
  MousePointer2, Clock, Box, Rocket
} from 'lucide-react';
