import { Project, StudioMode, TimelineLayer } from '../types';

interface VideoEditorProps {
  onSave: (project: Project) => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [playheadPos, setPlayheadPos] = useState(15);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedLayerId, setSelectedLayerId] = useState<string | null>('1');
  const [statusMessage, setStatusMessage] = useState("");
  const [zoomLevel, setZoomLevel] = useState(1);

  const [topic, setTopic] = useState("");
  const [theme, setTheme] = useState("Cinematic_Professional");

  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Raw Footage 4K_01', type: 'video', start: 0, duration: 60, content: 'https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?auto=format&fit=crop&q=80&w=1280', track: 1, opacity: 100, scale: 1, blendingMode: 'normal' },
    { id: '2', name: 'Orchestral Score', type: 'audio', start: 0, duration: 100, content: 'audio-src', track: 0, volume: 75 },
    { id: '3', name: 'Lens Flare VFX', type: 'vfx', start: 15, duration: 25, content: 'vfx-src', track: 2, opacity: 60, blendingMode: 'screen' },
    { id: '4', name: 'Main Title Card', type: 'text', start: 5, duration: 30, content: 'LUMINA STUDIOS PRESENT', track: 3, opacity: 100, blendingMode: 'normal' },
  ]);

  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const timelineRef = useRef<HTMLDivElement>(null);

  const activeLayer = useMemo(() => layers.find(l => l.id === selectedLayerId) || layers[0], [layers, selectedLayerId]);

  const handleTimelineInteraction = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const percentage = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setPlayheadPos(percentage);
  };

  const handleTopicSynthesis = async () => {
    if (!topic) return;
    setIsGenerating(true);
    setStatusMessage("Synthesizing Neural Frames...");

    try {
      const gemini = GeminiService.getInstance();
      const videoUrl = await gemini.generateVideo(`Professional 4K cinematic scene: ${topic}. Lighting: ${theme}. High-end commercial quality.`, aspectRatio === '16:9' ? '16:9' : '9:16');
      if (videoUrl) {
        const newLayer: TimelineLayer = { 
          id: Date.now().toString(), 
          name: `SYNTH: ${topic.substring(0, 12)}...`, 
          type: 'video', 
          start: playheadPos, 
          duration: 15, 
          content: videoUrl, 
          track: 1, 
          opacity: 100, 
          scale: 1,
          blendingMode: 'normal'
        };
        setLayers(prev => [...prev, newLayer]);
        setSelectedLayerId(newLayer.id);
      }
    } catch (err) {
      console.error("Synthesis failed", err);
    } finally {
      setIsGenerating(false);
      setTopic("");
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      {/* Desktop Header for Video Editor */}
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-rose-600 rounded-[1.5rem] shadow-xl shadow-rose-600/20">
              <Video className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Pro <span className="text-rose-500">Video</span> Editor</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] mt-1">Multi-Track NLE Core Engine V9</p>
           </div>
           <div className="h-8 w-px bg-white/10" />
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5">
              <button onClick={() => setAspectRatio('16:9')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '16:9' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>16:9</button>
              <button onClick={() => setAspectRatio('9:16')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '9:16' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>9:16</button>
           </div>
        </div>
        <div className="flex items-center space-x-4">
           <a 
             href="/video-editor/index.html" 
             target="_blank" 
             className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700"
           >
             <Rocket className="w-4 h-4 mr-2 text-rose-500" /> Standalone Mode
           </a>
           {isGenerating && (
             <div className="flex items-center space-x-3 bg-indigo-500/10 border border-indigo-500/20 px-5 py-2 rounded-xl animate-pulse">
                <Loader2 className="w-4 h-4 text-indigo-400 animate-spin" />
                <span className="text-[9px] font-black uppercase tracking-widest text-indigo-400">{statusMessage}</span>
             </div>
           )}
           <button onClick={() => onSave({id: 'vid-1', name: 'Production_Master', type: StudioMode.VIDEO, thumbnail: activeLayer.content, updatedAt: Date.now(), status: 'published', data: {layers}})} className="px-10 py-3 bg-white text-black rounded-xl text-[10px] font-black uppercase tracking-[0.3em] shadow-xl hover:bg-slate-100 transition-all flex items-center">
             <Download className="w-4 h-4 mr-2" /> Render MP4
           </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-12 gap-4 min-h-0">
        {/* Left: Project Media & Tools */}
        <div className="col-span-3 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-6 shadow-2xl overflow-hidden">
           <div className="flex items-center justify-between">
              <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center"><Sparkles className="w-4 h-4 mr-2" /> Neural Engine</h3>
              <button className="text-slate-600 hover:text-white transition-colors"><Maximize2 className="w-4 h-4" /></button>
           </div>

           <div className="space-y-4">
              <textarea value={topic} onChange={e => setTopic(e.target.value)} placeholder="Neural clip synthesis prompt..." className="w-full h-28 bg-black/40 border border-slate-800 rounded-2xl p-4 text-xs text-white focus:ring-2 focus:ring-rose-500/20 outline-none resize-none font-bold placeholder:text-slate-800" />
              <button onClick={handleTopicSynthesis} disabled={isGenerating || !topic} className="w-full py-4 bg-rose-600 hover:bg-rose-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center shadow-2xl">
                <RefreshCw className={`w-4 h-4 mr-2 ${isGenerating ? 'animate-spin' : ''}`} /> Synthesize
              </button>
           </div>

           <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pt-4 border-t border-white/5">
              <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Global Asset Vault</h4>
              <div className="grid grid-cols-2 gap-3">
                 {[1, 2, 3, 4].map(i => (
                   <div key={i} className="aspect-square bg-black/40 rounded-xl border border-white/5 hover:border-white/20 transition-all cursor-pointer relative group overflow-hidden">
                      <img src={`https://picsum.photos/seed/nle${i}/200`} className="w-full h-full object-cover opacity-40 group-hover:opacity-100 transition-opacity" />
                   </div>
                 ))}
                 <button className="aspect-square border-2 border-dashed border-slate-800 rounded-xl flex flex-col items-center justify-center text-slate-700 hover:text-white transition-all"><Upload className="w-6 h-6 mb-2" /><span className="text-[8px] font-black uppercase">Import</span></button>
              </div>
           </div>
        </div>

        {/* Center: Viewport */}
        <div className="col-span-6 bg-black rounded-[3rem] border border-white/5 flex flex-col items-center justify-center relative overflow-hidden group shadow-[inset_0_0_80px_rgba(0,0,0,1)]">
           <div className={`transition-all duration-700 overflow-hidden rounded-xl bg-[#020617] relative ${aspectRatio === '9:16' ? 'h-[90%] aspect-[9/16]' : 'w-[90%] aspect-video'} shadow-[0_0_120px_rgba(0,0,0,0.8)] border border-white/5`}>
              <img src={activeLayer.content} className="w-full h-full object-cover" alt="Preview" />
              {isGenerating && (
                <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center z-50 animate-in fade-in duration-500">
                   <Activity className="w-12 h-12 text-rose-600 animate-pulse mb-4" />
                   <p className="text-rose-500 font-black uppercase tracking-[0.5em] text-[10px]">Processing Matrix...</p>
                </div>
              )}
           </div>
           {/* Player Controls */}
           <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center space-x-8 bg-slate-900/90 backdrop-blur-2xl px-10 py-4 rounded-full border border-white/10 shadow-2xl">
              <button className="text-slate-500 hover:text-white transition-colors"><Rewind className="w-5 h-5" /></button>
              <button onClick={() => setIsPlaying(!isPlaying)} className="w-14 h-14 bg-white text-black rounded-full hover:scale-110 active:scale-95 transition-all flex items-center justify-center shadow-xl">
                {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
              </button>
              <button className="text-slate-500 hover:text-white transition-colors"><FastForward className="w-5 h-5" /></button>
              <div className="h-8 w-px bg-white/10 mx-4" />
              <div className="text-2xl font-mono font-black text-white tracking-tighter tabular-nums">
                <span className="text-rose-500">{(playheadPos * 0.6).toFixed(0).padStart(2, '0')}</span>
                <span className="text-slate-700 mx-1">:</span>
                <span className="text-slate-400">{(playheadPos % 1 * 60).toFixed(0).padStart(2, '0')}</span>
              </div>
           </div>
        </div>

        {/* Right: Inspector */}
        <div className="col-span-3 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-8 shadow-2xl overflow-hidden">
           <div className="flex items-center justify-between">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Sliders className="w-4 h-4 mr-2 text-rose-500" /> Node Inspector</h3>
              <Settings className="w-4 h-4 text-slate-700" />
           </div>

           <div className="space-y-6 flex-1 overflow-y-auto custom-scrollbar pr-1">
              <div className="p-5 bg-black/40 rounded-2xl border border-white/5 space-y-6 shadow-inner">
                 <div className="flex items-center justify-between">
                    <p className="text-[9px] font-black text-white uppercase tracking-widest truncate max-w-[120px]">{activeLayer.name}</p>
                    <span className="px-2 py-0.5 bg-slate-800 rounded text-[7px] font-black uppercase text-slate-500">Track_{activeLayer.track}</span>
                 </div>
                 <div className="space-y-6">
                    {['Opacity', 'Scale', 'Volume'].map(prop => (
                      <div key={prop} className="space-y-2">
                        <div className="flex justify-between text-[8px] font-black uppercase text-slate-500 tracking-widest"><span>{prop}</span><span className="text-white">100%</span></div>
                        <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-gradient-to-r from-rose-600 to-indigo-600 shadow-[0_0_8px_rgba(244,63,94,0.4)]" style={{ width: '100%' }} /></div>
                      </div>
                    ))}
                 </div>
                 <div className="space-y-2">
                    <label className="text-[8px] font-black text-slate-600 uppercase tracking-widest block ml-1">Blending Mode</label>
                    <select className="w-full bg-slate-900 border border-slate-800 rounded-lg p-2 text-[9px] font-black uppercase text-white outline-none">
                       <option>Normal</option>
                       <option>Multiply</option>
                       <option>Screen</option>
                       <option>Overlay</option>
                       <option>Difference</option>
                    </select>
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                 {[
                   { icon: Scissors, label: 'Razor Cut' },
                   { icon: Copy, label: 'Clone Node' },
                   { icon: Split, label: 'Crossfade' },
                   { icon: Trash2, label: 'Wipe' }
                 ].map((btn, idx) => (
                   <button key={idx} className="p-5 bg-slate-800/30 border border-slate-700/50 rounded-2xl flex flex-col items-center gap-3 hover:bg-slate-700 transition-all hover:border-rose-500/30 group">
                      <btn.icon className="w-5 h-5 text-slate-600 group-hover:text-white transition-transform group-hover:scale-110" /> 
                      <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 group-hover:text-white leading-tight">{btn.label}</span>
                   </button>
                 ))}
              </div>
           </div>

           <div className="bg-rose-500/10 border border-rose-500/20 p-4 rounded-2xl shadow-inner">
              <div className="flex items-center space-x-3 mb-2">
                 <Cpu className="w-4 h-4 text-rose-500" />
                 <span className="text-[9px] font-black uppercase tracking-widest text-rose-500">Live Engine Info</span>
              </div>
              <p className="text-[8px] text-slate-500 uppercase leading-relaxed">60 FPS Render • RAW_DECODE • 4K HDR Workspace Active</p>
           </div>
        </div>
      </div>

      {/* Multi-Track DAW Timeline Interface */}
      <div className="h-64 bg-slate-950 border border-white/5 rounded-[2.5rem] p-6 flex flex-col shadow-2xl relative overflow-hidden">
         <div className="flex items-center justify-between mb-4 px-4">
            <div className="flex items-center space-x-8">
               <div className="flex items-center space-x-3">
                  <Layers className="w-5 h-5 text-indigo-400" />
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-300">Timeline Engine V9</span>
               </div>
               <div className="flex items-center bg-black/40 p-1.5 rounded-xl border border-white/5 space-x-3">
                  <button onClick={() => setZoomLevel(Math.max(0.5, zoomLevel - 0.2))} className="p-2 text-slate-500 hover:text-white transition-all"><ZoomOut className="w-4 h-4" /></button>
                  <div className="w-px h-4 bg-white/10" />
                  <button onClick={() => setZoomLevel(Math.min(2, zoomLevel + 0.2))} className="p-2 text-slate-500 hover:text-white transition-all"><ZoomIn className="w-4 h-4" /></button>
               </div>
               <div className="flex items-center space-x-2 text-[9px] font-black text-slate-600 uppercase tracking-widest">
                  <Clock className="w-3.5 h-3.5" />
                  <span>Sequence Length: 05:42:12</span>
               </div>
            </div>
            <div className="flex items-center space-x-3">
               <button className="p-3 bg-slate-900 text-slate-500 rounded-xl hover:text-white transition-all"><Settings className="w-4 h-4" /></button>
               <button className="p-3 bg-indigo-600 text-white rounded-xl shadow-lg hover:bg-indigo-500 transition-all"><Plus className="w-4 h-4" /></button>
            </div>
         </div>

         <div className="flex-1 flex flex-col gap-2 overflow-y-auto custom-scrollbar relative pr-4">
            {[
              { id: 3, label: 'TITLES_A', icon: TypeIcon, color: 'bg-amber-600/10 text-amber-500 border-amber-500/20' },
              { id: 2, label: 'VFX_GRADES', icon: Wand2, color: 'bg-indigo-600/10 text-indigo-500 border-indigo-500/20' },
              { id: 1, label: 'VIDEO_MASTER', icon: Film, color: 'bg-rose-600/10 text-rose-500 border-rose-500/20' },
              { id: 0, label: 'AUDIO_SCORE', icon: Music, color: 'bg-emerald-600/10 text-emerald-500 border-emerald-500/20' }
            ].map(track => (
              <div key={track.id} className="flex h-10 min-w-full">
                 <div className={`w-36 flex items-center px-4 rounded-xl border shrink-0 shadow-lg z-10 font-black text-[8px] tracking-widest uppercase ${track.color}`}>
                    <track.icon className="w-4 h-4 mr-3" />
                    {track.label}
                 </div>
                 <div 
                   ref={track.id === 1 ? timelineRef : null}
                   onMouseDown={handleTimelineInteraction}
                   className="flex-1 bg-white/[0.03] rounded-xl ml-4 relative overflow-hidden border border-white/[0.05] cursor-crosshair group/track"
                 >
                    <div className="absolute inset-0 opacity-0 group-hover/track:opacity-100 transition-opacity bg-[linear-gradient(90deg,transparent_99%,rgba(255,255,255,0.03)_99%)] bg-[length:40px_100%]" />
                    {layers.filter(l => l.track === track.id).map(l => (
                      <div 
                        key={l.id}
                        onClick={(e) => { e.stopPropagation(); setSelectedLayerId(l.id); }}
                        style={{ left: `${l.start}%`, width: `${l.duration}%` }}
                        className={`absolute inset-y-1 rounded-lg border flex items-center px-3 cursor-pointer transition-all shadow-xl ${selectedLayerId === l.id ? 'bg-white text-black border-white z-20 scale-[1.01]' : 'bg-slate-900/90 text-slate-500 border-white/5 hover:border-white/10 z-10'}`}
                      >
                         <div className={`w-2 h-2 rounded-full mr-2 shrink-0 ${selectedLayerId === l.id ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,1)]' : 'bg-slate-700'}`} />
                         <span className="text-[8px] font-black uppercase truncate tracking-tighter">{l.name}</span>
                      </div>
                    ))}
                 </div>
              </div>
            ))}

            {/* Playhead */}
            <div style={{ left: `calc(144px + 16px + ${playheadPos}%)` }} className="absolute top-0 bottom-0 w-[1.5px] bg-rose-500 shadow-[0_0_15px_rgba(244,63,94,1)] z-30 pointer-events-none transition-transform duration-75">
               <div className="absolute top-0 -left-1.5 w-4 h-4 bg-rose-600 rounded-full border-2 border-white shadow-xl animate-pulse" />
            </div>
         </div>
      </div>
    </div>
  );
};

export default VideoEditor;

:root {
    --bg-deep: #020617;
    --bg-panel: #0f172a;
    --border: rgba(255, 255, 255, 0.05);
    --accent: #6366f1;
    --text: #f8fafc;
    --text-dim: #64748b;
    --track-h: 40px;
    --sidebar-w: 280px;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Inter', sans-serif;
}

body {
    background: var(--bg-deep);
    color: var(--text);
    overflow: hidden;
    height: 100vh;
}

.app-container {
    display: flex;
    flex-direction: column;
    height: 100vh;
}

/* Toolbar */
.toolbar {
    height: 60px;
    background: var(--bg-deep);
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 20px;
    z-index: 100;
}

.brand {
    display: flex;
    align-items: center;
    gap: 12px;
    font-weight: 900;
    text-transform: uppercase;
    letter-spacing: -0.5px;
    font-size: 14px;
}

.brand-icon {
    color: var(--accent);
}

.project-actions {
    display: flex;
    align-items: center;
    gap: 10px;
}

.btn {
    padding: 8px 16px;
    border-radius: 8px;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    cursor: pointer;
    border: 1px solid transparent;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: all 0.2s;
}

.btn svg { width: 14px; height: 14px; }

.btn.primary { background: var(--accent); color: white; }
.btn.primary:hover { opacity: 0.9; }

.btn.secondary { background: rgba(255,255,255,0.05); color: var(--text); border-color: var(--border); }
.btn.secondary:hover { background: rgba(255,255,255,0.1); }

.divider { width: 1px; height: 20px; background: var(--border); margin: 0 10px; }

/* Main Workspace */
.main-workspace {
    flex: 1;
    display: flex;
    min-height: 0;
}

aside {
    width: var(--sidebar-w);
    background: var(--bg-panel);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
}

.inspector {
    border-right: none;
    border-left: 1px solid var(--border);
}

.sidebar-header {
    padding: 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.sidebar-header h3 {
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--text-dim);
    font-weight: 900;
}

.search-box {
    margin: 0 20px 20px;
    background: rgba(0,0,0,0.2);
    border: 1px solid var(--border);
    border-radius: 8px;
    display: flex;
    align-items: center;
    padding: 8px 12px;
    gap: 10px;
}

.search-box input {
    background: transparent;
    border: none;
    outline: none;
    color: white;
    font-size: 11px;
    width: 100%;
}

.search-box svg { width: 14px; color: var(--text-dim); }

.media-grid {
    flex: 1;
    padding: 0 20px;
    overflow-y: auto;
}

.btn-icon {
    background: transparent;
    border: none;
    color: var(--accent);
    cursor: pointer;
    display: flex;
    align-items: center;
}

/* Viewport */
.viewport {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #000;
    position: relative;
}

.preview-container {
    width: 90%;
    aspect-ratio: 16/9;
    background: #050505;
    border: 1px solid var(--border);
    border-radius: 4px;
    position: relative;
    overflow: hidden;
    box-shadow: 0 0 50px rgba(0,0,0,1);
}

#mainPreview {
    width: 100%;
    height: 100%;
    object-fit: contain;
    transition: filter 0.3s;
}

.playback-controls {
    position: absolute;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 30px;
    background: rgba(15, 23, 42, 0.8);
    backdrop-filter: blur(10px);
    padding: 10px 40px;
    border-radius: 50px;
    border: 1px solid var(--border);
    opacity: 0;
    transition: opacity 0.3s;
}

.preview-container:hover .playback-controls { opacity: 1; }

.btn-ctrl { background: transparent; border: none; color: var(--text-dim); cursor: pointer; transition: color 0.2s; }
.btn-ctrl:hover { color: white; }
.btn-ctrl svg { width: 20px; height: 20px; }

.btn-play {
    width: 50px;
    height: 50px;
    background: white;
    color: black;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.2s;
}

.btn-play:hover { transform: scale(1.1); }
.btn-play svg { width: 24px; height: 24px; fill: currentColor; }

.time-readout {
    margin-top: 20px;
    font-family: monospace;
    font-size: 24px;
    color: var(--text);
    font-weight: 700;
}

.time-readout .sep { color: var(--text-dim); margin: 0 10px; }

/* Inspector Details */
.inspector-tabs {
    display: flex;
    padding: 0 20px;
    border-bottom: 1px solid var(--border);
}

.tab-btn {
    padding: 12px 20px;
    background: transparent;
    border: none;
    border-bottom: 2px solid transparent;
    color: var(--text-dim);
    font-size: 10px;
    font-weight: 900;
    text-transform: uppercase;
    cursor: pointer;
}

.tab-btn.active {
    color: var(--accent);
    border-bottom-color: var(--accent);
}

.property-stack { padding: 20px; display: none; flex-direction: column; gap: 20px; }
.property-stack.active { display: flex; }
.property-group { display: flex; flex-direction: column; gap: 10px; }
.property-group label { font-size: 9px; font-weight: 900; color: var(--text-dim); text-transform: uppercase; }
.property-group input[type="range"] { accent-color: var(--accent); }
.property-group select, .num-input {
    background: rgba(0,0,0,0.3);
    border: 1px solid var(--border);
    padding: 8px;
    border-radius: 6px;
    color: white;
    font-size: 11px;
}

.audio-mixer { margin-top: auto; padding: 20px; border-top: 1px solid var(--border); }
.mixer-header { display: flex; align-items: center; gap: 10px; margin-bottom: 15px; font-size: 10px; font-weight: 900; text-transform: uppercase; color: var(--text-dim); }
.vu-meter { height: 100px; width: 12px; background: rgba(0,0,0,0.5); border-radius: 4px; overflow: hidden; position: relative; margin-left: auto; margin-right: auto; }
.vu-fill { position: absolute; bottom: 0; left: 0; width: 100%; background: linear-gradient(to top, #22c55e, #eab308, #ef4444); transition: height 0.1s; }

/* Timeline */
.timeline-container {
    height: 300px;
    background: var(--bg-deep);
    border-top: 1px solid var(--border);
    display: flex;
    flex-direction: column;
}

.timeline-toolbar {
    height: 40px;
    background: rgba(15, 23, 42, 0.5);
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 20px;
}

.timeline-tools { display: flex; gap: 8px; }
.btn-tool {
    padding: 6px;
    border-radius: 6px;
    background: transparent;
    border: none;
    color: var(--text-dim);
    cursor: pointer;
}

.btn-tool.active { background: var(--accent); color: white; }
.btn-tool svg { width: 16px; height: 16px; }

.timeline-zoom { display: flex; align-items: center; gap: 10px; color: var(--text-dim); }
.timeline-zoom svg { width: 14px; }
.timeline-zoom input { width: 100px; }

.timeline-ruler {
    height: 25px;
    background: rgba(0,0,0,0.3);
    border-bottom: 1px solid var(--border);
    position: relative;
}

.playhead {
    position: absolute;
    top: 0;
    left: 100px;
    width: 2px;
    height: 300px;
    background: #ef4444;
    z-index: 50;
    pointer-events: none;
}

.playhead::after {
    content: '';
    position: absolute;
