    function updateFilters() {
        const b = 100 + parseInt(exposure.value);
        const c = 100 + parseInt(contrast.value);
        const s = 100 + parseInt(saturation.value);
        const bl = blur.value;

        mainImage.style.filter = `${currentBaseFilter === 'none' ? '' : currentBaseFilter} brightness(${b}%) contrast(${c}%) saturate(${s}%) blur(${bl}px)`;
    }

    [exposure, contrast, saturation, blur].forEach(el => {
        el.addEventListener('input', updateFilters);
    });

    document.querySelectorAll('.filter-thumb').forEach(btn => {
        btn.addEventListener('click', () => {
            currentBaseFilter = btn.dataset.filter;
            updateFilters();
        });
    });

    imgUpload.addEventListener('change', (e) => {
        const file = e.target.files[0];
        if (file) {
            mainImage.src = URL.createObjectURL(file);
        }
    });

    saveBtn.addEventListener('click', () => {
        alert("Photo metadata synchronized to Lumina cloud vault.");
    });
});

