document.addEventListener('DOMContentLoaded', () => {
    const canvas = document.getElementById('rigCanvas');
    const ctx = canvas.getContext('2d');
    const boneList = document.getElementById('boneList');

    let tool = 'brush';
    let isDrawing = false;
    let bones = [];

    document.querySelectorAll('.tool-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.tool-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            if (btn.dataset.tool) tool = btn.dataset.tool;
        });
    });

    window.clearCanvas = () => {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        bones = [];
        renderBones();
    };

    function getPos(e) {
        const rect = canvas.getBoundingClientRect();
        return {
            x: (e.clientX - rect.left) * (canvas.width / rect.width),
            y: (e.clientY - rect.top) * (canvas.height / rect.height)
        };
    }

    canvas.addEventListener('mousedown', (e) => {
        const pos = getPos(e);
        if (tool === 'brush') {
            isDrawing = true;
            ctx.beginPath();
            ctx.moveTo(pos.x, pos.y);
            ctx.strokeStyle = '#10b981';
            ctx.lineWidth = 5;
            ctx.lineCap = 'round';
        } else if (tool === 'bone') {
            bones.push({ ...pos, id: Date.now() });
            renderBones();
        }
    });

    canvas.addEventListener('mousemove', (e) => {
        if (!isDrawing || tool !== 'brush') return;
        const pos = getPos(e);
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
    });

    canvas.addEventListener('mouseup', () => {
        isDrawing = false;
    });

    function renderBones() {
        boneList.innerHTML = bones.length ? bones.map((b, i) => `
            <div style="padding:10px; background:rgba(255,255,255,0.03); border-radius:8px; margin-bottom:5px; font-size:10px; display:flex; justify-content:space-between;">
                <span>Bone Node 0${i+1}</span>
                <span style="color:#10b981">${Math.round(b.x)}, ${Math.round(b.y)}</span>
            </div>
        `).join('') : '<p class="empty">No nodes detected</p>';

        // Draw overlay nodes on canvas would need separate layer for efficiency, 
        // here we just mark them for visual feedback
        ctx.fillStyle = '#10b981';
        bones.forEach(b => {
            ctx.beginPath();
            ctx.arc(b.x, b.y, 8, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    document.getElementById('exportRig').addEventListener('click', () => {
        alert("Skeletal rig exported as FBX_JSON metadata.");
    });
});

