import React, { useState, useRef, useEffect } from 'react';
import { 
  Eraser, Download, Sparkles, Layers, Pencil, MousePointer2, Move3d, Zap, Ghost, Eye, RefreshCw, Play, Pause, Plus, Star, Dna, Layout, Sliders, ChevronRight, ChevronLeft, Target, History, Maximize2, Scissors, Box, Radio,
  Bone as BoneIcon, Move, User, Clock, Trash2, Languages, Globe, Activity, Rocket
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, Bone } from '../types';
import { translations } from '../App';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'bones' | 'select' | 'rigging' | 'erase';
type RenderStyle = 'Disney_Pixar' | 'Ghibli_Anime' | 'Cyber_Concept' | 'Realistic_UE5' | 'Paper_Sketch';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#10b981');
  const [strokeWidth, setStrokeWidth] = useState(8);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('Realistic_UE5');

  const [currentFrame, setCurrentFrame] = useState(0);
  const [frames, setFrames] = useState<string[]>(['']); 
  const [isPlaying, setIsPlaying] = useState(false);
  const [fps, setFps] = useState(12);
  const [bones, setBones] = useState<Bone[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent) => {
    const pos = getMousePos(e);
    if (tool === 'bones') {
      const newBone: Bone = {
        id: Date.now().toString(),
        x: pos.x,
        y: pos.y,
        name: `Node_${bones.length + 1}`,
        parentId: bones.length > 0 ? bones[bones.length - 1].id : undefined
      };
      setBones([...bones, newBone]);
      return;
    }

    if (tool === 'brush' || tool === 'erase') {
        setIsDrawing(true);
        const canvas = canvasRef.current;
        const ctx = canvas?.getContext('2d');
        if (ctx) {
          ctx.beginPath();
          ctx.moveTo(pos.x, pos.y);
          ctx.strokeStyle = tool === 'erase' ? '#020617' : color;
          ctx.lineWidth = strokeWidth;
        }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const pos = getMousePos(e);
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (ctx) {
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
    }
  };

  const handleCanvasMouseUp = () => {
    setIsDrawing(false);
    if (canvasRef.current) {
        const updated = [...frames];
        updated[currentFrame] = canvasRef.current.toDataURL();
        setFrames(updated);
    }
  };

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const masterPrompt = `Industrial animation character model sheet: ${prompt}. Style: ${renderStyle}. Views: Professional T-pose front, side profile, and 3/4 perspective for skeletal rigging. High fidelity, neutral commercial lighting, white background.`;
    const result = await gemini.generateImage(masterPrompt, "1:1", true);
    if (result) {
      const updatedFrames = [...frames];
      updatedFrames[currentFrame] = result;
      setFrames(updatedFrames);
      onSave({ id: `anim-${Date.now()}`, name: `Character: ${prompt.substring(0, 15)}`, type: StudioMode.PAINT, thumbnail: result, updatedAt: Date.now(), status: 'draft', data: { prompt, renderStyle, frames: updatedFrames, bones } });
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl shadow-emerald-600/20 ring-2 ring-emerald-500/10">
              <Dna className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Neural <span className="text-emerald-400">Identity</span> Hub</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Industrial Skeletal Rigging • Multi-View Synthesis</p>
           </div>
           <div className="h-8 w-px bg-white/10" />
           <div className="flex bg-black/40 p-1 rounded-xl">
             <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase bg-white text-black shadow-lg">2D_MESH</button>
             <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase text-slate-500 hover:text-white">3D_MODEL</button>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <a href="/animation-studio/index.html" target="_blank" className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700">
             <Rocket className="w-4 h-4 mr-2 text-emerald-400" /> Animation Studio
          </a>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-10 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50 active:scale-95 border border-indigo-400/20">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Spawn Identity
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         <div className="w-24 bg-slate-900/90 backdrop-blur-3xl rounded-[3rem] border border-white/5 p-4 flex flex-col items-center gap-5 shadow-2xl overflow-y-auto custom-scrollbar scrollbar-hide">
            {[
              { id: 'select', icon: MousePointer2, label: 'Manipulate' },
              { id: 'brush', icon: Pencil, label: 'Sketch' },
              { id: 'erase', icon: Eraser, label: 'Erase' },
              { id: 'bones', icon: BoneIcon, label: 'Add Bone' },
              { id: 'rigging', icon: Move3d, label: 'Rig Weights' },
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                title={t.label}
                className={`p-4 rounded-2xl transition-all group relative ${tool === t.id ? 'bg-emerald-600 text-white shadow-xl scale-110' : 'bg-black/40 text-slate-500 hover:text-white hover:bg-white/5'}`}
              >
                <t.icon className="w-6 h-6 transition-transform group-hover:rotate-6" />
              </button>
            ))}
            <div className="w-12 h-px bg-white/5 my-2" />
            <div className="w-10 h-10 rounded-xl cursor-pointer p-0.5 border border-white/10 shadow-inner" style={{ background: color }}>
                <input type="color" value={color} onChange={(e) => setColor(e.target.value)} className="w-full h-full opacity-0 cursor-pointer" />
            </div>
         </div>

         <div className="flex-1 flex flex-col gap-4">
            <div className="flex-1 bg-black rounded-[3rem] border border-white/5 p-8 flex flex-col shadow-2xl relative overflow-hidden group shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
               <div className="flex-1 bg-[#020617] rounded-[2rem] overflow-hidden relative border border-white/5 shadow-2xl">
                  <div className="absolute top-6 left-6 z-10 flex space-x-3">
                     <div className="px-4 py-1.5 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center shadow-xl">
                        <Box className="w-3 h-3 mr-2 text-emerald-400" /> Perspective: Orthographic
                     </div>
                     <div className="px-4 py-1.5 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center shadow-xl">
                        <Activity className="w-3 h-3 mr-2 text-indigo-400" /> Frame Rate: {fps} FPS
                     </div>
                  </div>
                  <canvas ref={canvasRef} width={1600} height={1200} onMouseDown={handleCanvasMouseDown} onMouseMove={handleCanvasMouseMove} onMouseUp={handleCanvasMouseUp} onMouseLeave={handleCanvasMouseUp} className="w-full h-full object-contain cursor-crosshair relative z-0" />
                  <svg className="absolute inset-0 w-full h-full pointer-events-none z-10">
                     {bones.map(bone => (
                        <React.Fragment key={bone.id}>
                           {bone.parentId && <line x1={bones.find(b => b.id === bone.parentId)?.x || 0} y1={bones.find(b => b.id === bone.parentId)?.y || 0} x2={bone.x} y2={bone.y} stroke="#10b981" strokeWidth="4" strokeDasharray="8 4" strokeOpacity="0.6" />}
                           <circle cx={bone.x} cy={bone.y} r="8" fill="#10b981" stroke="white" strokeWidth="2" />
                           <text x={bone.x + 12} y={bone.y + 4} fill="#10b981" fontSize="10" fontWeight="900" textAnchor="start">{bone.name}</text>
                        </React.Fragment>
                     ))}
                  </svg>
                  {isGenerating && (
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center z-50">
                        <div className="w-20 h-20 border-[6px] border-emerald-500 border-t-transparent rounded-full animate-spin mb-6" />
                        <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Generating Character Matrix</h3>
                        <p className="text-emerald-400 font-black uppercase tracking-[0.4em] text-[8px] animate-pulse">Running Neural Skeletal Interpolation...</p>
                    </div>
                  )}
               </div>

               <div className="mt-6 bg-slate-900/60 backdrop-blur-3xl p-4 rounded-[2rem] border border-white/5 flex items-center space-x-6 shadow-xl">
                  <div className="flex items-center space-x-3 border-r border-white/5 pr-6">
                     <button onClick={() => setIsPlaying(!isPlaying)} className={`p-4 rounded-xl transition-all shadow-xl hover:scale-105 active:scale-95 ${isPlaying ? 'bg-rose-600 text-white' : 'bg-emerald-600 text-white'}`}>
                        {isPlaying ? <Pause className="w-5 h-5 fill-current" /> : <Play className="w-5 h-5 fill-current ml-0.5" />}
                     </button>
                     <div className="text-[10px] font-mono font-black text-white w-12 text-center">{currentFrame + 1}/{frames.length}</div>
                  </div>
                  <div className="flex-1 flex space-x-3 overflow-x-auto scrollbar-hide py-1">
                     {frames.map((_, i) => (
                        <button key={i} onClick={() => setCurrentFrame(i)} className={`w-24 h-16 rounded-xl shrink-0 border-2 transition-all flex flex-col items-center justify-center text-[8px] font-black uppercase tracking-widest relative overflow-hidden shadow-lg ${currentFrame === i ? 'border-emerald-500 bg-emerald-500/10 text-emerald-400' : 'border-white/5 bg-black/20 text-slate-700 hover:text-slate-500'}`}>
                           <span className="relative z-10">FRAME_{i+1}</span>
                           <div className="absolute inset-x-0 bottom-0 h-1 bg-slate-800" />
                        </button>
                     ))}
                     <button onClick={() => setFrames([...frames, ''])} className="w-16 h-16 rounded-xl shrink-0 border-2 border-dashed border-slate-800 flex flex-col items-center justify-center text-slate-700 hover:text-white"><Plus className="w-4 h-4" /></button>
                  </div>
                  <div className="flex items-center space-x-3 border-l border-white/5 pl-6">
                     <div className="flex items-center bg-black/40 p-1.5 rounded-lg border border-white/5 shadow-inner">
                        <span className="text-[8px] font-black text-slate-500 uppercase px-2">FPS</span>
                        <input type="number" value={fps} onChange={e => setFps(parseInt(e.target.value))} className="bg-transparent text-white font-mono text-[10px] w-8 focus:outline-none" />
                     </div>
                  </div>
               </div>
            </div>

            <div className="bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 flex gap-5 shadow-2xl">
              <div className="flex-1 relative group">
                <Sparkles className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-indigo-500 animate-pulse" />
                <input value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Universal character prompt: 'Cyber-ronin', 'Ghibli spirit'..." className="w-full bg-slate-950 border border-slate-800 rounded-full py-5 pl-14 pr-8 text-white text-xs font-black uppercase tracking-widest focus:ring-4 focus:ring-emerald-500/5 outline-none transition-all" />
              </div>
              <div className="flex bg-slate-950 border border-slate-800 p-1.5 rounded-full shadow-inner overflow-x-auto scrollbar-hide max-w-sm">
                {['Disney_Pixar', 'Ghibli_Anime', 'Realistic_UE5'].map(s => (
                  <button key={s} onClick={() => setRenderStyle(s as RenderStyle)} className={`px-6 py-2.5 rounded-full text-[9px] font-black uppercase transition-all whitespace-nowrap ${renderStyle === s ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'}`}>{s.split('_')[0]}</button>
                ))}
              </div>
            </div>
         </div>

         <div className="w-80 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-8 shadow-2xl overflow-hidden">
            <div className="space-y-6">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Target className="w-4 h-4 mr-2 text-emerald-400" /> Bone Hierarchy</h3>
