document.addEventListener('DOMContentLoaded', () => {
    const canvas = document.getElementById('rigCanvas');
    const ctx = canvas.getContext('2d');
    const boneList = document.getElementById('boneList');

    let tool = 'brush';
    let isDrawing = false;
    let bones = [];
    let frameHistory = [];

    // Init canvas
    ctx.fillStyle = '#020617';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    document.querySelectorAll('.tool-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.tool-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            if (btn.dataset.tool) tool = btn.dataset.tool;
        });
    });

    window.clearCanvas = () => {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        bones = [];
        renderBones();
    };

    function getPos(e) {
        const rect = canvas.getBoundingClientRect();
        return {
            x: (e.clientX - rect.left) * (canvas.width / rect.width),
            y: (e.clientY - rect.top) * (canvas.height / rect.height)
        };
    }

    canvas.addEventListener('mousedown', (e) => {
        const pos = getPos(e);
        if (tool === 'brush') {
            isDrawing = true;
            ctx.beginPath();
            ctx.moveTo(pos.x, pos.y);
            ctx.strokeStyle = '#10b981';
            ctx.lineWidth = 4;
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';
        } else if (tool === 'bone') {
            bones.push({ ...pos, id: Date.now() });
            renderBones();
        }
    });

    canvas.addEventListener('mousemove', (e) => {
        const pos = getPos(e);
        if (isDrawing && tool === 'brush') {
            ctx.lineTo(pos.x, pos.y);
            ctx.stroke();
        }
    });

    canvas.addEventListener('mouseup', () => {
        if (isDrawing) {
            isDrawing = false;
            // Frame snapshot for animation state (placeholder)
            frameHistory.push(canvas.toDataURL());
        }
    });

    function renderBones() {
        boneList.innerHTML = bones.length ? bones.map((b, i) => `
            <div class="bone-item" style="padding:10px; background:rgba(255,255,255,0.03); border:1px solid rgba(255,255,255,0.05); border-radius:12px; margin-bottom:8px; font-size:9px; font-weight:900; display:flex; justify-content:space-between; align-items:center;">
                <span style="color:#475569">NODE_0${i+1}</span>
                <div style="display:flex; gap:10px; align-items:center;">
                    <span style="color:#10b981">${Math.round(b.x)}x${Math.round(b.y)}</span>
                    <button onclick="removeBone(${b.id})" style="background:transparent; border:none; color:#ef4444; cursor:pointer;">&times;</button>
                </div>
            </div>
        `).join('') : '<p class="empty">No active skeleton nodes</p>';

        // Redraw bone markers
        bones.forEach((b, i) => {
            ctx.fillStyle = '#10b981';
            ctx.beginPath();
            ctx.arc(b.x, b.y, 6, 0, Math.PI * 2);
            ctx.fill();

            // Draw connection to previous bone for simple IK preview
            if (i > 0) {
                ctx.beginPath();
                ctx.moveTo(bones[i-1].x, bones[i-1].y);
                ctx.lineTo(b.x, b.y);
                ctx.strokeStyle = 'rgba(16, 185, 129, 0.3)';
                ctx.lineWidth = 2;
                ctx.setLineDash([5, 5]);
                ctx.stroke();
                ctx.setLineDash([]);
            }
        });
    }

    window.removeBone = (id) => {
        bones = bones.filter(b => b.id !== id);
        renderBones();
    };

    document.getElementById('exportRig').addEventListener('click', () => {
        alert("Lumina Rigging Core: Skeleton identity serialized. Character mesh weights synthesized for 3D export.");
    });
});

