export interface ShotstackLayer {
  id: string;
  type: 'video' | 'audio' | 'image' | 'text';
  src: string;
  start: number;
  duration: number;
}

export class ShotstackService {
  private static instance: ShotstackService;
  private readonly API_KEY = '3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G';
  private readonly API_URL = 'https://api.shotstack.io/v1/render';

  private constructor() {}

  public static getInstance(): ShotstackService {
    if (!ShotstackService.instance) {
      ShotstackService.instance = new ShotstackService();
    }
    return ShotstackService.instance;
  }

  async renderTimeline(layers: any[], aspectRatio: string = '16:9'): Promise<string | null> {
    // Map internal layers to Shotstack JSON format
    const shotstackTracks = [
      {
        clips: layers.map(layer => ({
          asset: {
            type: layer.type === 'text' ? 'html' : (layer.type === 'audio' ? 'audio' : 'video'),
            src: layer.content,
            html: layer.type === 'text' ? `<p style="color: #ffffff; font-family: 'Inter'; font-weight: 900;">${layer.content}</p>` : undefined
          },
          start: (layer.start / 100) * 10, // Simulated scale
          length: (layer.duration / 100) * 10,
          fit: 'cover'
        }))
      }
    ];

    const edit = {
      timeline: {
        tracks: shotstackTracks
      },
      output: {
        format: 'mp4',
        resolution: 'hd',
        aspectRatio: aspectRatio === '9:16' ? '9:16' : '16:9'
      }
    };

    try {
      const response = await fetch(this.API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': this.API_KEY
        },
        body: JSON.stringify(edit)
      });

      if (!response.ok) throw new Error('Shotstack handshake failed.');
      const data = await response.json();
      return data.response.id;
    } catch (error) {
      console.error('Shotstack Render Error:', error);
      return null;
    }
  }

  async checkStatus(id: string): Promise<{ status: string, url?: string }> {
    try {
      const response = await fetch(`${this.API_URL}/${id}`, {
        headers: { 'x-api-key': this.API_KEY }
      });
      const data = await response.json();
      return {
        status: data.response.status,
        url: data.response.url
      };
    } catch (error) {
      return { status: 'failed' };
    }
  }
}

