document.addEventListener('DOMContentLoaded', () => {
    const videoPlayer = document.getElementById('player');
    const playPauseBtn = document.getElementById('playPauseBtn');
    const rewindBtn = document.getElementById('rewindBtn');
    const forwardBtn = document.getElementById('forwardBtn');
    const currentTimeDisplay = document.getElementById('currentTime');
    const totalTimeDisplay = document.getElementById('totalTime');
    const playhead = document.getElementById('playhead');
    const trackArea = document.getElementById('trackArea');
    const mediaPool = document.getElementById('mediaPool');
    const mediaUpload = document.getElementById('mediaUpload');
    const videoUploadInput = document.getElementById('videoUpload');
    const cloudTransformPreset = document.getElementById('cloudTransformPreset');
    const opacitySlider = document.getElementById('opacitySlider');
    const scaleSlider = document.getElementById('scaleSlider');
    const mainClip = document.getElementById('mainClip');
    const startTimeInput = document.getElementById('startTime');
    const endTimeInput = document.getElementById('endTime');
    const exportBtn = document.getElementById('exportBtn');

    let isPlaying = false;
    let duration = 0;

    // --- Industrial API Core: Shotstack ---
    const SHOTSTACK_KEY = '3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G';
    const SHOTSTACK_URL = 'https://api.shotstack.io/v1/render';

    async function triggerShotstackRender() {
        const layers = [{
            asset: { type: 'video', src: videoPlayer.src },
            start: 0,
            length: 5
        }];

        const payload = {
            timeline: { tracks: [{ clips: layers }] },
            output: { format: 'mp4', resolution: 'sd' }
        };

        exportBtn.innerHTML = '<i data-lucide="refresh-cw" class="animate-spin"></i> Shotstack Rendering...';
        lucide.createIcons();

        try {
            const res = await fetch(SHOTSTACK_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'x-api-key': SHOTSTACK_KEY },
                body: JSON.stringify(payload)
            });
            const data = await res.json();
            const renderId = data.response.id;

            const poll = setInterval(async () => {
                const statusRes = await fetch(`${SHOTSTACK_URL}/${renderId}`, {
                    headers: { 'x-api-key': SHOTSTACK_KEY }
                });
                const statusData = await statusRes.json();
                const status = statusData.response.status;

                if (status === 'done') {
                    clearInterval(poll);
                    alert("Lumina Cloud: Rendering Complete via Shotstack Cluster.");
                    window.open(statusData.response.url, '_blank');
                    exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
                    lucide.createIcons();
                } else if (status === 'failed') {
                    clearInterval(poll);
                    alert("Lumina Cloud: Shotstack node encountered a critical error.");
                    exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
                    lucide.createIcons();
                }
            }, 5000);
        } catch (e) {
            alert("Lumina Engine: Global Shotstack Handshake Failed.");
            exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
            lucide.createIcons();
        }
    }

    // --- End Shotstack Logic ---

    // Cloudinary Config (Placeholders)
    const cloudName = "YOUR_CLOUD_NAME";
    const uploadPreset = "YOUR_UPLOAD_PRESET";

    function formatTime(seconds) {
        if (isNaN(seconds)) return "00:00:00";
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = Math.floor(seconds % 60);
        return [h, m, s].map(v => v.toString().padStart(2, '0')).join(':');
    }

    window.uploadVideo = async function() {
        const file = videoUploadInput.files[0];
        if (!file) {
            alert("Lumina Engine: Please select a video asset for cloud sync.");
            return;
        }

        const cloudBtn = document.getElementById('cloudUploadBtn');
        const originalBtnHTML = cloudBtn.innerHTML;
        cloudBtn.innerHTML = '<i data-lucide="refresh-cw" class="animate-spin"></i>';
        lucide.createIcons();

        const formData = new FormData();
        formData.append("file", file);
        formData.append("upload_preset", uploadPreset);

        try {
            const res = await fetch(
                `https://api.cloudinary.com/v1_1/${cloudName}/video/upload`,
                { method: "POST", body: formData }
            );
            const data = await res.json();
            const transformation = cloudTransformPreset.value;
            const trimmedUrl = `https://res.cloudinary.com/${cloudName}/video/upload/${transformation}/${data.public_id}.mp4`;

            videoPlayer.src = trimmedUrl;
            mainClip.textContent = `Cloud: ${file.name} (${transformation})`;

            const thumb = document.createElement('div');
            thumb.className = 'media-item';
            thumb.style.marginBottom = '15px';
            thumb.innerHTML = `
                <div style="width: 100%; aspect-ratio: 16/9; border-radius: 12px; overflow: hidden; background: #000; border: 1px solid var(--accent); cursor: pointer;" onclick="document.getElementById('player').src='${trimmedUrl}'">
                    <video src="${trimmedUrl}" style="width: 100%; height: 100%; object-fit: cover; opacity: 0.7;"></video>
                </div>
                <p style="font-size: 9px; font-weight: 900; text-transform: uppercase; color: var(--accent); margin-top: 5px;">CLOUD NODE: ${file.name}</p>
            `;
            mediaPool.prepend(thumb);
            alert("Lumina Engine: Cloud Sync Stabilized. Transform active.");
        } catch (err) {
            alert("Lumina Engine Error: Cloud Uplink Failure.");
        } finally {
            cloudBtn.innerHTML = originalBtnHTML;
            lucide.createIcons();
        }
    };

    videoUploadInput.addEventListener('change', () => {
        if (videoUploadInput.files[0]) {
            alert("Lumina Engine: Local asset staged for Cloud Sync.");
            switchTab('filters');
        }
    });

    mediaUpload.addEventListener('change', function() {
        const file = this.files[0];
        if (!file) return;
        const url = URL.createObjectURL(file);
        videoPlayer.src = url;
        mainClip.textContent = file.name;

        const thumb = document.createElement('div');
        thumb.className = 'media-item';
        thumb.style.marginBottom = '15px';
        thumb.innerHTML = `
            <div style="width: 100%; aspect-ratio: 16/9; border-radius: 12px; overflow: hidden; background: #000; border: 1px solid var(--border); cursor: pointer;" onclick="document.getElementById('player').src='${url}'">
                <video src="${url}" style="width: 100%; height: 100%; object-fit: cover; opacity: 0.7;"></video>
            </div>
            <p style="font-size: 9px; font-weight: 900; text-transform: uppercase; color: var(--text-dim); margin-top: 5px;">LOCAL NODE: ${file.name}</p>
        `;
        mediaPool.prepend(thumb);
    });

    window.trimVideo = () => {
        const start = parseFloat(startTimeInput.value);
        videoPlayer.currentTime = start;
        updateTimeline();
        alert("Lumina Engine: Local trim preview set to " + start + "s");
    };

    exportBtn.addEventListener('click', triggerShotstackRender);

    function togglePlay() {
        if (isPlaying) {
            videoPlayer.pause();
            playPauseBtn.innerHTML = '<i data-lucide="play"></i>';
        } else {
            videoPlayer.play();
            playPauseBtn.innerHTML = '<i data-lucide="pause"></i>';
        }
        isPlaying = !isPlaying;
        lucide.createIcons();
    }

    playPauseBtn.addEventListener('click', togglePlay);

    videoPlayer.addEventListener('loadedmetadata', () => {
        duration = videoPlayer.duration;
        totalTimeDisplay.textContent = formatTime(duration);
        if (!endTimeInput.value || endTimeInput.value > duration) {
            endTimeInput.value = Math.floor(duration);
        }
        updateTimeline();
    });

    videoPlayer.addEventListener('timeupdate', () => {
        const current = videoPlayer.currentTime;
        currentTimeDisplay.textContent = formatTime(current);
        if (duration > 0) {
            const percentage = (current / duration) * 100;
            playhead.style.left = `calc(100px + ${percentage}%)`;
        }
        const start = parseFloat(startTimeInput.value) || 0;
        const end = parseFloat(endTimeInput.value) || duration;
        if (current < start) videoPlayer.currentTime = start;
        if (current > end) videoPlayer.currentTime = start;
    });

    rewindBtn.addEventListener('click', () => videoPlayer.currentTime -= 5);
    forwardBtn.addEventListener('click', () => videoPlayer.currentTime += 5);

    function updateVisuals() {
        videoPlayer.style.opacity = opacitySlider.value / 100;
        videoPlayer.style.transform = `scale(${scaleSlider.value / 100})`;
    }

    function updateTimeline() {
        const start = parseFloat(startTimeInput.value) || 0;
        const end = parseFloat(endTimeInput.value) || duration;
        const left = (start / duration) * 100;
        const width = ((end - start) / duration) * 100;
        mainClip.style.left = left + '%';
        mainClip.style.width = width + '%';
    }

    [opacitySlider, scaleSlider].forEach(el => {
        el.addEventListener('input', updateVisuals);
    });

    [startTimeInput, endTimeInput].forEach(el => el.addEventListener('input', updateTimeline));

    window.switchTab = (tabId) => {
        document.querySelectorAll('.property-stack').forEach(s => s.classList.remove('active'));
        document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
        document.getElementById(tabId + 'Tab').classList.add('active');
        const activeBtn = Array.from(document.querySelectorAll('.tab-btn')).find(b => b.textContent.toLowerCase().includes(tabId.substring(0, 3)));
        if (activeBtn) activeBtn.classList.add('active');
    };

    setInterval(() => {
        if (isPlaying) {
            const fill = document.getElementById('vuFill');
            if (fill) fill.style.height = `${15 + Math.random() * 65}%`;
        }
    }, 120);

    lucide.createIcons();
});

