interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'bones' | 'select' | 'rigging' | 'erase';
type RenderStyle = 'Disney_Pixar' | 'Ghibli_Anime' | 'Realistic_UE5' | 'Cyber_Punk' | 'Sketch_Book';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#10b981');
  const [strokeWidth, setStrokeWidth] = useState(8);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('Realistic_UE5');

  const [currentFrame, setCurrentFrame] = useState(0);
  const [frames, setFrames] = useState<string[]>(['']); 
  const [isPlaying, setIsPlaying] = useState(false);
  const [fps, setFps] = useState(12);
  const [bones, setBones] = useState<Bone[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent) => {
    const pos = getMousePos(e);
    if (tool === 'bones') {
      const newBone: Bone = {
        id: Date.now().toString(),
        x: pos.x,
        y: pos.y,
        name: `Node_${bones.length + 1}`,
        parentId: bones.length > 0 ? bones[bones.length - 1].id : undefined
      };
      setBones([...bones, newBone]);
      return;
    }

    if (tool === 'brush' || tool === 'erase') {
        setIsDrawing(true);
        const canvas = canvasRef.current;
        const ctx = canvas?.getContext('2d');
        if (ctx) {
          ctx.beginPath();
          ctx.moveTo(pos.x, pos.y);
          ctx.strokeStyle = tool === 'erase' ? '#020617' : color;
          ctx.lineWidth = strokeWidth;
        }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const pos = getMousePos(e);
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (ctx) {
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
    }
  };

  const handleCanvasMouseUp = () => {
    setIsDrawing(false);
    if (canvasRef.current) {
        const updated = [...frames];
        updated[currentFrame] = canvasRef.current.toDataURL();
        setFrames(updated);
    }
  };

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const masterPrompt = `Professional industrial character model sheet: ${prompt}. Style: ${renderStyle}. Multiple views: T-pose, front, side, back. Clean background, sharp details for skeletal rigging.`;
    const result = await gemini.generateImage(masterPrompt, "1:1", true);
    if (result) {
      const updatedFrames = [...frames];
      updatedFrames[currentFrame] = result;
      setFrames(updatedFrames);
      onSave({ id: `anim-${Date.now()}`, name: `Character_${prompt.substring(0, 10)}`, type: StudioMode.PAINT, thumbnail: result, updatedAt: Date.now(), status: 'draft', data: { prompt, renderStyle, frames: updatedFrames, bones } });
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl shadow-emerald-600/20 ring-2 ring-emerald-500/10">
              <Dna className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Identity <span className="text-emerald-400">Synthesis</span> Core</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Multi-View Rigging • Neural Asset Engine V2</p>
           </div>
