const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const axios = require('axios');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;
const SECRET_KEY = process.env.JWT_SECRET || 'lumina_super_secret_key';
const SHOTSTACK_API_KEY = '3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G';

app.use(cors());
app.use(express.json());

// In-memory Stores
let users = [];
let otpStore = {}; 
let siteConfig = {
  maintenanceMode: false,
  activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
  globalAnnouncement: "Build v9.0.5 - Shotstack Industrial Integration Active."
};

// Default Admin Credentials
const admin = {
  email: "admin@lumina.com",
  password: bcrypt.hashSync("StrongAdmin123", 10),
  role: "admin"
};

// --- SHOTSTACK PROXY ROUTE ---
app.post("/api/shotstack/trim", async (req, res) => {
  const { videoUrl, start = 3, length = 12 } = req.body;

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: {
                    type: "video",
                    src: videoUrl
                  },
                  start: 0,
                  length: length
                }
              ]
            }
          ]
        },
        output: {
          format: "mp4",
          resolution: "sd"
        }
      },
      {
        headers: {
          "x-api-key": SHOTSTACK_API_KEY,
          "Content-Type": "application/json"
        }
      }
    );

    res.json(response.data);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// --- MIDDLEWARE ---
const verifyToken = (req, res, next) => {
  const auth = req.headers.authorization;
  if (!auth) return res.status(401).json({ message: "No token" });

  const token = auth.split(" ")[1];
  try {
    const verified = jwt.verify(token, SECRET_KEY);
    req.user = verified;
    next();
  } catch (err) {
    res.status(401).json({ message: "Invalid token" });
  }
};

const isAdmin = (req, res, next) => {
  if (req.user && req.user.role === 'admin') {
    next();
  } else {
    res.status(403).json({ message: 'Require Admin Role!' });
  }
};

// --- ADMIN ROUTES ---
app.post("/api/admin/login", async (req, res) => {
  const { email, password } = req.body;
  if (email !== admin.email) return res.status(400).json({ message: "Invalid email" });
  const valid = await bcrypt.compare(password, admin.password);
  if (!valid) return res.status(400).json({ message: "Wrong password" });

  const otp = Math.floor(100000 + Math.random() * 900000);
  otpStore[email] = otp;
  console.log("ADMIN_OTP:", otp);
  res.json({ message: "OTP sent", otp });
});

app.post("/api/admin/verify-otp", (req, res) => {
  const { email, otp } = req.body;
  if (otpStore[email] != otp) return res.status(400).json({ message: "Invalid OTP" });

  const token = jwt.sign({ email, role: "admin" }, SECRET_KEY, { expiresIn: "1h" });
  delete otpStore[email];
  res.json({ 
    token,
    user: { name: "Lumina Admin", role: "admin", email, avatar: 'https://api.dicebear.com/7.x/identicon/svg?seed=admin' } 
  });
});

// --- CORE STUDIO ROUTES ---
app.post('/api/auth/login', async (req, res) => {
  const { email, password } = req.body;
  const user = users.find(u => u.email === email);
  if (!user) return res.status(404).json({ message: 'User not found' });
  const valid = await bcrypt.compare(password, user.password);
  if (!valid) return res.status(401).json({ message: 'Invalid credentials' });

  const token = jwt.sign({ id: user.id, role: user.role }, SECRET_KEY, { expiresIn: '24h' });
  res.status(200).json({ token, user });
});

app.get('/api/admin/users', [verifyToken, isAdmin], (req, res) => {
  res.json(users.map(({ password, ...rest }) => rest));
});

app.listen(PORT, () => {
  console.log(`Lumina Enterprise Multi-Module Backend Active on Port ${PORT}`);
});

