        const current = videoPlayer.currentTime;
        currentTimeDisplay.textContent = formatTime(current);
        if (duration > 0) {
            const percentage = (current / duration) * 100;
            playhead.style.left = `calc(100px + ${percentage}%)`;
        }
    });

    rewindBtn.addEventListener('click', () => videoPlayer.currentTime -= 5);
    forwardBtn.addEventListener('click', () => videoPlayer.currentTime += 5);

    function formatTime(s) {
        if (isNaN(s)) return "00:00:00";
        const h = Math.floor(s / 3600);
        const m = Math.floor((s % 3600) / 60);
        const sec = Math.floor(s % 60);
        return [h, m, sec].map(v => v.toString().padStart(2, '0')).join(':');
    }

    function updateVisuals() {
        videoPlayer.style.opacity = opacitySlider.value / 100;
        videoPlayer.style.transform = `scale(${scaleSlider.value / 100})`;
    }

    function updateTimeline() {
        const start = parseFloat(startTimeInput.value) || 0;
        const end = parseFloat(endTimeInput.value) || duration;
        const left = (start / duration) * 100;
        const width = ((end - start) / duration) * 100;
        mainClip.style.left = left + '%';
        mainClip.style.width = width + '%';
    }

    [opacitySlider, scaleSlider].forEach(el => el.addEventListener('input', updateVisuals));
    [startTimeInput, endTimeInput].forEach(el => el.addEventListener('input', updateTimeline));

    window.switchTab = (tabId) => {
        document.querySelectorAll('.property-stack').forEach(s => s.classList.remove('active'));
        document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
        document.getElementById(tabId + 'Tab').classList.add('active');
        const activeBtn = Array.from(document.querySelectorAll('.tab-btn')).find(b => b.textContent.toLowerCase().includes(tabId.substring(0, 3)));
        if (activeBtn) activeBtn.classList.add('active');
    };

    setInterval(() => { if (isPlaying) { const f = document.getElementById('vuFill'); if (f) f.style.height = `${15 + Math.random() * 65}%`; } }, 120);
    lucide.createIcons();
});

