app.post("/trim", async (req, res) => {
  const { videoUrl, start = 0, length = 12 } = req.body;

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: {
                    type: "video",
