    { id: '3', name: 'Main Title Node', type: 'text', start: 5, duration: 30, content: 'LUMINA STUDIOS', track: 3, opacity: 100, blendingMode: 'normal' },
  ]);

  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const timelineRef = useRef<HTMLDivElement>(null);
  const activeLayer = useMemo(() => layers.find(l => l.id === selectedLayerId) || layers[0], [layers, selectedLayerId]);

  const handleTimelineInteraction = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const percentage = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
    setPlayheadPos(percentage);
  };

  const handleCloudTrim = async () => {
    if (!activeLayer.content.startsWith('http')) return alert("Select a valid cloud node.");
    setIsRendering(true);
    setRenderStatus("Node Handshake: Requesting Cluster Proxy...");
    try {
      // Aligned with backend /trim endpoint
      const response = await fetch('http://localhost:5000/trim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ videoUrl: activeLayer.content, start: 0, length: 12 })
      });
      const data = await response.json();
      const renderId = data.response.id;
      const interval = setInterval(async () => {
        const shotstack = ShotstackService.getInstance();
        const result = await shotstack.checkStatus(renderId);
        setRenderStatus(`Cluster Sync: ${result.status.toUpperCase()}`);
        if (result.status === 'done' && result.url) {
          clearInterval(interval);
          setIsRendering(false);
          const updated = layers.map(l => l.id === selectedLayerId ? { ...l, content: result.url!, name: l.name + ' (Trimmed)' } : l);
          setLayers(updated);
        } else if (result.status === 'failed') { clearInterval(interval); setIsRendering(false); }
      }, 3000);
    } catch (err) { setRenderStatus("Gateway failure."); setIsRendering(false); }
  };

  const handleRender = async () => {
    setIsRendering(true);
    setRenderStatus("Assembling Industrial Package...");
    const shotstack = ShotstackService.getInstance();
    const renderId = await shotstack.renderTimeline(layers, aspectRatio);
    if (!renderId) { setIsRendering(false); return; }
    const interval = setInterval(async () => {
      const result = await shotstack.checkStatus(renderId);
      setRenderStatus(`Render: ${result.status.toUpperCase()}`);
      if (result.status === 'done' && result.url) {
        clearInterval(interval);
        setIsRendering(false);
        window.open(result.url, '_blank');
      } else if (result.status === 'failed') { clearInterval(interval); setIsRendering(false); }
    }, 3000);
  };

  const handleTopicSynthesis = async () => {
    if (!topic) return;
    setIsGenerating(true);
    try {
      const gemini = GeminiService.getInstance();
      const videoUrl = await gemini.generateVideo(`Professional 4K: ${topic}`, aspectRatio === '16:9' ? '16:9' : '9:16');
      if (videoUrl) {
        const newL: TimelineLayer = { id: Date.now().toString(), name: `NEURAL: ${topic.substring(0, 10)}`, type: 'video', start: playheadPos, duration: 15, content: videoUrl, track: 1, opacity: 100, scale: 1, blendingMode: 'normal' };
        setLayers(prev => [...prev, newL]);
        setSelectedLayerId(newL.id);
      }
    } finally { setIsGenerating(false); setTopic(""); }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-rose-600 rounded-[1.5rem] shadow-xl">
              <Video className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Industrial <span className="text-rose-500">Video</span> Engine</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Multi-Node Cluster Active</p>
           </div>
           <div className="flex bg-black/40 p-1 rounded-xl">
              <button onClick={() => setAspectRatio('16:9')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '16:9' ? 'bg-white text-black shadow-lg' : 'text-slate-500'}`}>16:9</button>
              <button onClick={() => setAspectRatio('9:16')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '9:16' ? 'bg-white text-black shadow-lg' : 'text-slate-500'}`}>9:16</button>
           </div>
        </div>
        <div className="flex items-center space-x-4">
           <button onClick={handleCloudTrim} disabled={isRendering} className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700 disabled:opacity-50">
             <CloudCog className="w-4 h-4 mr-2 text-indigo-400" /> Cloud Trim
           </button>
           <a href="/video-editor/index.html" target="_blank" className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700">
             <Rocket className="w-4 h-4 mr-2 text-rose-500" /> Desktop mode
           </a>
           {isRendering && (
              <div className="flex items-center space-x-3 bg-rose-500/10 border border-rose-500/20 px-5 py-2 rounded-xl animate-pulse">
                <RefreshCw className="w-4 h-4 text-rose-400 animate-spin" />
                <span className="text-[9px] font-black uppercase tracking-widest text-rose-400">{renderStatus}</span>
              </div>
           )}
           <button onClick={handleRender} disabled={isRendering} className="px-10 py-3 bg-white text-black rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center disabled:opacity-50">
             <Download className="w-4 h-4 mr-2" /> Render MP4
           </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-12 gap-4 min-h-0">
        <div className="col-span-3 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-6 shadow-2xl overflow-hidden">
           <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center"><Sparkles className="w-4 h-4 mr-2" /> Neural Engine</h3>
           <div className="space-y-4">
              <textarea value={topic} onChange={e => setTopic(e.target.value)} placeholder="Synthesis directive..." className="w-full h-28 bg-black/40 border border-slate-800 rounded-2xl p-4 text-xs text-white outline-none resize-none font-bold placeholder:text-slate-800" />
              <button onClick={handleTopicSynthesis} disabled={isGenerating || !topic} className="w-full py-4 bg-rose-600 hover:bg-rose-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center">
                <RefreshCw className={`w-4 h-4 mr-2 ${isGenerating ? 'animate-spin' : ''}`} /> Synthesize
              </button>
           </div>
           <div className="flex-1 overflow-y-auto custom-scrollbar pt-4 border-t border-white/5 space-y-4">
              <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Local Asset Staging</h4>
              <div className="grid grid-cols-2 gap-3">
                 {[1, 2].map(i => (
