app.post("/api/admin/login", async (req, res) => {
  const { email, password } = req.body;
  if (email !== admin.email) return res.status(400).json({ message: "Invalid email" });
  const valid = await bcrypt.compare(password, admin.password);
  if (!valid) return res.status(400).json({ message: "Wrong password" });
  const otp = Math.floor(100000 + Math.random() * 900000);
  otpStore[email] = otp;
  res.json({ message: "OTP sent", otp });
});

app.post("/api/admin/verify-otp", (req, res) => {
  const { email, otp } = req.body;
  if (otpStore[email] != otp) return res.status(400).json({ message: "Invalid OTP" });
  const token = jwt.sign({ email, role: "admin" }, SECRET_KEY, { expiresIn: "1h" });
  delete otpStore[email];
  res.json({ token, user: { name: "Lumina Admin", role: "admin", email, avatar: 'https://api.dicebear.com/7.x/identicon/svg?seed=admin' } });
});

