    async function triggerShotstackRender() {
        if (!videoPlayer.src || videoPlayer.src.includes('unsplash')) {
            alert("Industrial Error: Valid cloud sync required for final render.");
            return;
        }

        exportBtn.innerHTML = '<i data-lucide="refresh-cw" class="animate-spin"></i> Cluster Active...';
        lucide.createIcons();

        try {
            const res = await fetch(SHOTSTACK_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'x-api-key': SHOTSTACK_KEY },
                body: JSON.stringify({
                    timeline: { tracks: [{ clips: [{ asset: { type: 'video', src: videoPlayer.src }, start: 0, length: 12 }] }] },
                    output: { format: 'mp4', resolution: 'hd' }
                })
            });
            const data = await res.json();
            const renderId = data.response.id;

            const poll = setInterval(async () => {
                const statusRes = await fetch(`${SHOTSTACK_URL}/${renderId}`, { headers: { 'x-api-key': SHOTSTACK_KEY } });
                const statusData = await statusRes.json();
                const status = statusData.response.status;

                if (status === 'done') {
                    clearInterval(poll);
                    alert("Lumina Cloud: Rendering complete. File available in CDN.");
                    window.open(statusData.response.url, '_blank');
                    exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
                    lucide.createIcons();
                } else if (status === 'failed') {
                    clearInterval(poll);
                    alert("Critical Node Failure: Multi-pass render aborted.");
                    exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
                    lucide.createIcons();
                }
            }, 5000);
        } catch (e) {
            alert("Lumina Engine: Shotstack API rejected the handshake.");
            exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
            lucide.createIcons();
        }
    }

