    { id: '2', name: 'Master Score (Wave)', type: 'audio', start: 0, duration: 100, content: 'audio-src', track: 0, volume: 75 },
    { id: '3', name: 'Title Node Overlay', type: 'text', start: 5, duration: 30, content: 'LUMINA CLUSTER', track: 3, opacity: 100, blendingMode: 'normal' },
  ]);

  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const timelineRef = useRef<HTMLDivElement>(null);
  const activeLayer = useMemo(() => layers.find(l => l.id === selectedLayerId) || layers[0], [layers, selectedLayerId]);

  const handleTimelineInteraction = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const percentage = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
    setPlayheadPos(percentage);
  };

  const handleCloudTrim = async () => {
    if (!activeLayer.content.startsWith('http')) return alert("Select a valid cloud node.");
    setIsRendering(true);
    setRenderStatus("Handshake: Requesting Cluster Proxy...");
    try {
      // Aligned with industrial backend /trim endpoint
      const response = await fetch('http://localhost:5000/trim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ videoUrl: activeLayer.content, start: 0, length: 12 })
      });
      const data = await response.json();
      const renderId = data.response.id;
      const interval = setInterval(async () => {
        const shotstack = ShotstackService.getInstance();
        const result = await shotstack.checkStatus(renderId);
        setRenderStatus(`Sync: ${result.status.toUpperCase()}`);
        if (result.status === 'done' && result.url) {
          clearInterval(interval);
          setIsRendering(false);
          const updated = layers.map(l => l.id === selectedLayerId ? { ...l, content: result.url!, name: l.name + ' (Trimmed)' } : l);
          setLayers(updated);
        } else if (result.status === 'failed') { clearInterval(interval); setIsRendering(false); }
      }, 3000);
    } catch (err) { setRenderStatus("Gateway error."); setIsRendering(false); }
  };

