    setIsRendering(true);
    setRenderStatus("Assembling Cluster Pack...");
    const shotstack = ShotstackService.getInstance();
    const renderId = await shotstack.renderTimeline(layers, aspectRatio);
    if (!renderId) { setIsRendering(false); return; }
    const interval = setInterval(async () => {
      const result = await shotstack.checkStatus(renderId);
      setRenderStatus(`Process: ${result.status.toUpperCase()}`);
      if (result.status === 'done' && result.url) {
        clearInterval(interval);
        setIsRendering(false);
        window.open(result.url, '_blank');
      } else if (result.status === 'failed') { clearInterval(interval); setIsRendering(false); }
    }, 3000);
  };

