        <div className="flex items-center space-x-6">
           <div className="p-4 bg-rose-600 rounded-[1.5rem] shadow-xl">
              <Video className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Industrial <span className="text-rose-500">Video</span> Node</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">NLE Core • Build v10.2 Stable</p>
           </div>
           <div className="flex bg-black/40 p-1 rounded-xl">
              <button onClick={() => setAspectRatio('16:9')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '16:9' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>16:9</button>
              <button onClick={() => setAspectRatio('9:16')} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${aspectRatio === '9:16' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>9:16</button>
           </div>
        </div>
        <div className="flex items-center space-x-4">
           <button onClick={handleCloudTrim} disabled={isRendering} className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700 disabled:opacity-50 shadow-xl group">
             <CloudCog className="w-4 h-4 mr-2 text-indigo-400 group-hover:rotate-180 transition-transform duration-1000" /> Cloud Node Trim
           </button>
           <a href="/video-editor/index.html" target="_blank" className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700">
             <Rocket className="w-4 h-4 mr-2 text-rose-500" /> Standalone mode
           </a>
