import React, { useState, useRef, useEffect } from 'react';
import { 
  ImageIcon, Layers, Wand2, Maximize, Contrast, Sun, RotateCcw,
  Upload, Save, Palette, Download, CheckCircle, FileUp, 
  Stamp, CreditCard, Layout, Sparkles, Image as ImgIcon, Type,
  Scissors, Eraser, Trash2, History, Eye, EyeOff, Lock, Unlock,
  Plus, Sliders, Brush, MousePointer2, Crop, Frame, CornerUpRight,
  Filter, Cloud, Maximize2, Split, Move, Zap, Aperture, Focus,
  Droplets, Blend, Square, Hexagon, Rocket, Info, SlidersHorizontal,
  CloudLightning, MousePointer, Scan, Target
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

const PhotoEditor: React.FC<{ onSave: (p: Project) => void }> = ({ onSave }) => {
  const [image, setImage] = useState<string>("https://images.unsplash.com/photo-1542038784456-1ea8e935640e?auto=format&fit=crop&q=80&w=1280");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTool, setActiveTool] = useState('pointer');
  const [aiQuery, setAiQuery] = useState("");

  // High-density pro adjustments
  const [adjustments, setAdjustments] = useState({
    exposure: 100,
    contrast: 100,
    saturation: 100,
    highlights: 100,
    shadows: 100,
    sharpness: 0,
    blur: 0,
    vignette: 0
  });

  const handleAiCommand = async () => {
    if (!aiQuery) return;
    setIsProcessing(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.editImage(image, `Industrial professional edit: ${aiQuery}. 8K resolution, high contrast, studio lighting.`);
    if (result) setImage(result);
    setIsProcessing(false);
    setAiQuery("");
  };

  const updateAdj = (key: keyof typeof adjustments, val: number) => {
    setAdjustments(prev => ({ ...prev, [key]: val }));
  };

  const filterStyle = {
    filter: `brightness(${adjustments.exposure}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) blur(${adjustments.blur}px) contrast(${1 + adjustments.highlights / 200})`,
    boxShadow: `inset 0 0 ${adjustments.vignette}px rgba(0,0,0,0.9)`
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200 font-sans">
      {/* Studio Header Toolbar */}
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-2xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
         <div className="flex items-center space-x-6">
            <div className="p-4 bg-cyan-600 rounded-[1.5rem] shadow-xl shadow-cyan-600/20">
               <ImageIcon className="w-6 h-6 text-white" />
            </div>
            <div>
               <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Neural <span className="text-cyan-500">Photo</span> Matrix</h2>
               <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Industrial RAW Engine • 8K Multi-Spectral Core</p>
            </div>
            <div className="h-8 w-px bg-white/10" />
            <div className="flex bg-black/40 p-1 rounded-xl">
               <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase bg-white text-black shadow-lg">PRO_MODE</button>
               <button className="px-5 py-1.5 rounded-lg text-[9px] font-black uppercase text-slate-500 hover:text-white">AI_AUTO</button>
            </div>
         </div>
         <div className="flex space-x-3">
            <a href="/photo-editor/index.html" target="_blank" className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center border border-slate-700 shadow-xl group">
               <Rocket className="w-4 h-4 mr-2 text-cyan-400 group-hover:translate-x-1 transition-transform" /> Standalone mode
            </a>
            <button 
              onClick={() => onSave({ id: Date.now().toString(), name: 'Master_RAW_Render', type: StudioMode.PHOTO, thumbnail: image, updatedAt: Date.now(), status: 'published', data: { adjustments } })}
              className="px-10 py-3 bg-cyan-600 rounded-xl text-[10px] font-black uppercase text-white shadow-xl hover:bg-cyan-500 transition-all tracking-[0.2em] flex items-center"
            >
              <CloudLightning className="w-4 h-4 mr-2" /> Commit Render
            </button>
         </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         {/* Vertical Industrial Floating Tools */}
         <div className="w-24 bg-slate-900/90 backdrop-blur-3xl rounded-[3rem] border border-white/5 p-4 flex flex-col items-center gap-5 shadow-2xl">
            {[
              { id: 'pointer', icon: MousePointer2, color: 'text-white' },
              { id: 'focus', icon: Focus, color: 'text-rose-400' },
              { id: 'wand', icon: Wand2, color: 'text-cyan-400' },
              { id: 'crop', icon: Crop, color: 'text-emerald-400' },
              { id: 'brush', icon: Brush, color: 'text-indigo-400' },
              { id: 'droplets', icon: Droplets, color: 'text-blue-400' }
            ].map((tool) => (
              <button 
                key={tool.id} 
                onClick={() => setActiveTool(tool.id)}
                className={`p-4 rounded-2xl transition-all ${activeTool === tool.id ? 'bg-cyan-600 text-white shadow-xl scale-110' : 'bg-black/40 hover:bg-white/5'}`}
              >
                <tool.icon className={`w-6 h-6 ${activeTool === tool.id ? 'text-white' : tool.color} transition-transform`} />
              </button>
            ))}
            <div className="w-10 h-px bg-white/5 my-2" />
            <button onClick={() => setImage("")} className="p-4 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all">
                <Trash2 className="w-6 h-6" />
            </button>
         </div>

         {/* Full Viewport Canvas Area */}
         <div className="flex-1 bg-[#020617] rounded-[3rem] border border-white/5 flex flex-col items-center justify-center relative overflow-hidden group shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
            <div className="absolute top-8 left-8 z-10 flex space-x-3">
               <div className="px-5 py-2 bg-black/60 backdrop-blur-xl rounded-full border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center">
                  <Scan className="w-3 h-3 mr-2 text-cyan-400" /> Resolution: 8K RAW_PRO
               </div>
               <div className="px-5 py-2 bg-black/60 backdrop-blur-xl rounded-full border border-white/10 text-[8px] font-black uppercase text-slate-400 flex items-center">
                  <Zap className="w-3 h-3 mr-2 text-amber-400" /> Latency: 4ms
               </div>
            </div>

            <div className="relative h-[85%] w-[85%] flex items-center justify-center">
              <img 
                src={image || "https://images.unsplash.com/photo-1542038784456-1ea8e935640e?auto=format&fit=crop&q=80&w=1280"} 
                style={filterStyle} 
                className={`object-contain transition-all duration-700 rounded-xl shadow-[0_0_120px_rgba(0,0,0,0.9)] ${isProcessing ? 'blur-2xl opacity-40 scale-95' : 'scale-100 border border-white/5'}`} 
              />
              {isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center z-50 animate-in fade-in duration-500">
                   <div className="w-24 h-24 border-[6px] border-cyan-500 border-t-transparent rounded-full animate-spin mb-8 shadow-[0_0_50px_rgba(6,182,212,0.5)]" />
                   <p className="text-cyan-400 font-black uppercase tracking-[0.5em] text-[10px] animate-pulse">Syncing Neural Layers...</p>
                </div>
              )}
            </div>

            {/* Neural Command Dock */}
            <div className="absolute bottom-10 inset-x-10 max-w-3xl mx-auto">
               <div className="bg-slate-900/90 backdrop-blur-3xl p-3 rounded-full border border-white/10 shadow-[0_20px_60px_rgba(0,0,0,0.6)] flex gap-3">
                  <div className="flex items-center px-6">
                    <Sparkles className="w-6 h-6 text-cyan-400 animate-pulse" />
                  </div>
                  <input 
                    value={aiQuery}
                    onChange={(e) => setAiQuery(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleAiCommand()}
                    placeholder="Input Industrial Directive: 'Remove noise', 'Simulate studio light', 'HDR Bloom'..." 
                    className="flex-1 bg-transparent px-2 text-xs text-white focus:outline-none placeholder:text-slate-700 font-black uppercase tracking-widest" 
                  />
                  <button onClick={handleAiCommand} disabled={isProcessing || !aiQuery} className="px-12 py-4 bg-cyan-600 text-white rounded-full font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-cyan-500 transition-all active:scale-95 disabled:opacity-50">
                    Apply Node
                  </button>
               </div>
            </div>
         </div>

         {/* Layer & Adjustment Stack Inspector */}
         <div className="w-80 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-8 shadow-2xl overflow-hidden">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center"><Layers className="w-4 h-4 mr-2 text-cyan-500" /> Image Inspector</h3>

            <div className="flex-1 space-y-8 overflow-y-auto custom-scrollbar pr-1">
               <div className="space-y-6">
                  {[
                    { id: 'exposure', label: 'Exposure', icon: Sun },
                    { id: 'contrast', label: 'Contrast', icon: Contrast },
                    { id: 'highlights', label: 'Highlights', icon: Zap },
                    { id: 'vignette', label: 'Vignette', icon: Target },
                    { id: 'blur', icon: Droplets, label: 'Gaussian' }
                  ].map(adj => (
                    <div key={adj.id} className="space-y-3">
                       <div className="flex justify-between text-[8px] font-black uppercase text-slate-500">
                          <span className="flex items-center"><adj.icon className="w-3 h-3 mr-2" /> {adj.label}</span>
                          <span className="text-white">{(adjustments as any)[adj.id]}%</span>
                       </div>
                       <input 
                          type="range" 
                          min="0" max="200" 
                          value={(adjustments as any)[adj.id]}
                          onChange={(e) => updateAdj(adj.id as any, parseInt(e.target.value))}
                          className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-cyan-500" 
                       />
                    </div>
                  ))}
               </div>
            </div>

            <div className="bg-slate-950 rounded-2xl p-5 border border-white/10 space-y-4 shadow-xl">
               <div className="flex justify-between items-center text-[9px] font-black text-slate-600 uppercase">
                  <span>Format</span>
                  <span className="text-cyan-500 font-mono">DNG_32_RAW</span>
               </div>
               <button className="w-full py-4 bg-slate-800 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-700 transition-all flex items-center justify-center border border-slate-700 shadow-xl group">
                 <Download className="w-4 h-4 mr-2 text-cyan-400 group-hover:translate-y-1 transition-transform" /> Export Master
               </button>
            </div>
         </div>
      </div>
    </div>
  );
};

export default PhotoEditor;

