        if (!currentUrl || currentUrl.includes('unsplash')) {
            alert("System: Active video node required for cloud trim.");
            return;
        }

        const applyBtn = document.getElementById('btn-apply-trim');
        const originalText = applyBtn.textContent;
        applyBtn.innerHTML = '<i data-lucide="refresh-cw" class="animate-spin"></i> Processing...';
        lucide.createIcons();

        try {
            // Backend endpoint provided by user
            const response = await fetch("http://localhost:5000/trim", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    videoUrl: currentUrl,
                    start: parseFloat(startTimeInput.value) || 0,
                    length: (parseFloat(endTimeInput.value) - parseFloat(startTimeInput.value)) || 12
                })
            });

            const data = await response.json();
            console.log("Cloud Trim Response:", data);

            if (data.response && data.response.id) {
                alert(`Node Handshake Success: Job ID ${data.response.id}. Awaiting cluster synthesis...`);
            }
        } catch (err) {
            console.error("Trim protocol failed:", err);
            alert("Uplink failed. Ensure Lumina backend is online.");
        } finally {
            applyBtn.textContent = originalText;
            lucide.createIcons();
        }
    };

    // --- CLOUDINARY SYNC ---
    const cloudName = "YOUR_CLOUD_NAME";
    const uploadPreset = "YOUR_UPLOAD_PRESET";

