const cors = require("cors");

const app = express();
app.use(cors());
app.use(express.json());

const API_KEY = "YOUR_SANDBOX_API_KEY";

let users = {
  "user1": { credits: 5 }
};

// Trim API
app.post("/render", async (req, res) => {
  const { username, videoUrl, start, end } = req.body;

  if (!users[username] || users[username].credits <= 0) {
    return res.status(400).json({ error: "No credits left" });
  }

  users[username].credits -= 1;

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: { type: "video", src: videoUrl },
                  start: 0,
                  trim: start,
                  length: end - start
                }
              ]
            }
          ]
        },
        output: { format: "mp4", resolution: "sd" }
      },
      {
        headers: {
          "x-api-key": API_KEY,
          "Content-Type": "application/json"
        }
      }
    );

    res.json(response.data);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Admin check credits
app.get("/credits/:username", (req, res) => {
  const user = users[req.params.username];
  res.json(user || { credits: 0 });
});

app.listen(3000, () => console.log("Server running on 3000"));

