const express = require('express');
const cors = require('cors');
const axios = require('axios');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 3000;

// User requested constant
const SHOTSTACK_API = "YOUR_SANDBOX_API_KEY"; 

app.use(cors());
app.use(express.json());

// In-memory User Credit System (as requested)
let users = {
  "user1": { credits: 999 },
  "admin@lumina.com": { credits: 10000 }
};

// Unified Render/Trim API for Industrial Video Processing
app.post("/render", async (req, res) => {
  const { username, videoUrl, start, end, aspectRatio = "16:9" } = req.body;

  const targetUser = username || "user1";
  if (!users[targetUser] || users[targetUser].credits <= 0) {
    return res.status(400).json({ error: "Insufficient node credits for synthesis." });
  }

  // Deduct credit for industrial operation
  users[targetUser].credits -= 1;

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: { type: "video", src: videoUrl },
                  start: 0,
                  trim: start || 0,
                  length: (end - start) || 10
                }
              ]
            }
          ]
        },
        output: { 
          format: "mp4", 
          resolution: "hd",
          aspectRatio: aspectRatio
        }
      },
      {
        headers: {
          "x-api-key": SHOTSTACK_API === "YOUR_SANDBOX_API_KEY" ? '3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G' : SHOTSTACK_API,
          "Content-Type": "application/json"
        }
      }
    );

    res.json({
      ...response.data,
      remainingCredits: users[targetUser].credits
    });
  } catch (err) {
    console.error("Shotstack Node Failure:", err.message);
    res.status(500).json({ error: "Handshake failure in creative cluster." });
  }
});

// Credits check endpoint
app.get("/credits/:username", (req, res) => {
  const user = users[req.params.username];
  res.json(user || { credits: 0 });
});

// Basic Health Check
app.get('/api/health', (req, res) => res.json({ status: 'industrial_cluster_online', version: '10.0.1' }));

app.listen(PORT, () => {
  console.log(`Lumina Creative Backend active on Port ${PORT}`);
});

