import React, { useState, useRef, useEffect } from 'react';
import { 
  Eraser, Download, Sparkles, Layers, Pencil, MousePointer2, Move3d, Zap, Ghost, Eye, RefreshCw, Play, Pause, Plus, Star, Dna, Layout, Sliders, ChevronRight, ChevronLeft, Target, History, Maximize2, Scissors, Box, Radio,
  Bone as BoneIcon, Move, User, Clock, Trash2, Languages, Globe, Activity, Rocket, Cpu, Binary, Layers3, Brush, Palette as PaletteIcon, Scan
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, Bone } from '../types';

const PaintStudio: React.FC<{ onSave: (p: Project) => void }> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<'brush' | 'bones' | 'erase'>('brush');
  const [color, setColor] = useState('#10b981');
  const [brushSize, setBrushSize] = useState(8);
  const [brushFlow, setBrushFlow] = useState(100);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState('Realistic_UE5');
  const [bones, setBones] = useState<Bone[]>([]);
  const [activeLayer, setActiveLayer] = useState(1);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const pos = getMousePos(e);
    if (tool === 'bones') {
      const newBone: Bone = { id: Date.now().toString(), x: pos.x, y: pos.y, name: `Node_SK_${bones.length + 1}` };
      setBones([...bones, newBone]);
      return;
    }
    setIsDrawing(true);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(pos.x, pos.y);
      ctx.strokeStyle = tool === 'erase' ? '#020617' : color;
      ctx.lineWidth = brushSize;
      ctx.globalAlpha = brushFlow / 100;
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const pos = getMousePos(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
    }
  };

  const handleSynthesize = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage(`Universal character identity sheet: ${prompt}. Professional ${renderStyle} style. Full body T-pose front, side, and back views. Orthographic projection, production ready.`, "1:1", true);
    if (result) {
      const img = new Image();
      img.src = result;
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
      };
      onSave({ id: `rig-${Date.now()}`, name: `Identity_${prompt.substring(0, 8)}`, type: StudioMode.PAINT, thumbnail: result, updatedAt: Date.now(), status: 'draft', data: { prompt, bones, renderStyle } });
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl shadow-emerald-600/20">
              <Dna className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Identity <span className="text-emerald-400">Rigging</span> Core</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Skeletal Synthesis Engine • 8K Mesh Projection</p>
           </div>
           <div className="h-8 w-px bg-white/10" />
           <div className="flex bg-black/40 p-1 rounded-xl">
             <button className="px-5 py-1.5 rounded-lg text-[8px] font-black uppercase bg-white text-black shadow-lg">RIG_MODE</button>
             <button className="px-5 py-1.5 rounded-lg text-[8px] font-black uppercase text-slate-500 hover:text-white">ANIM_LAB</button>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <a href="/animation-studio/index.html" target="_blank" className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center border border-slate-700 shadow-xl group">
             <Rocket className="w-4 h-4 mr-2 text-emerald-400 group-hover:translate-x-1 transition-transform" /> Desktop Workspace
          </a>
          <button onClick={handleSynthesize} disabled={isGenerating || !prompt} className="px-10 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Synthesize Identity
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
         {/* Vertical Rigging Tools */}
         <div className="w-24 bg-slate-900/90 backdrop-blur-3xl rounded-[3rem] border border-white/5 p-4 flex flex-col items-center gap-5 shadow-2xl">
            {[
              { id: 'brush', icon: Brush, label: 'Ink' },
              { id: 'bones', icon: BoneIcon, label: 'Rig' },
              { id: 'erase', icon: Eraser, label: 'Wipe' },
              { id: 'select', icon: MousePointer2, label: 'Node' }
            ].map(t => (
              <button key={t.id} onClick={() => setTool(t.id as any)} className={`p-4 rounded-2xl transition-all ${tool === t.id ? 'bg-emerald-600 text-white shadow-xl scale-110' : 'bg-black/40 text-slate-500 hover:text-white'}`}>
                <t.icon className="w-6 h-6" />
              </button>
            ))}
            <div className="w-10 h-10 rounded-xl cursor-pointer p-0.5 border border-white/10 group relative" style={{ background: color }}>
                <input type="color" value={color} onChange={(e) => setColor(e.target.value)} className="w-full h-full opacity-0 cursor-pointer" />
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-0 group-hover:opacity-100"><PaletteIcon className="w-4 h-4 text-white invert" /></div>
            </div>
            <div className="h-px w-10 bg-white/5 my-2" />
            <button onClick={() => setBones([])} className="p-4 text-rose-500 hover:bg-rose-500/10 rounded-2xl transition-all"><Trash2 className="w-6 h-6" /></button>
         </div>

         {/* Animation Viewport */}
         <div className="flex-1 flex flex-col gap-4 min-w-0">
            <div className="flex-1 bg-black rounded-[3rem] border border-white/5 p-8 flex flex-col relative overflow-hidden group shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
               <div className="flex-1 bg-[#020617] rounded-[2.5rem] overflow-hidden relative shadow-2xl border border-white/5">
                  <div className="absolute top-6 left-6 z-20 flex space-x-3">
                     <div className="px-4 py-2 bg-black/60 backdrop-blur-md rounded-xl text-[8px] font-black uppercase text-slate-400 flex items-center border border-white/10">
                        <Scan className="w-3 h-3 mr-2 text-emerald-400" /> Mode: ORTHOGRAPHIC_SYNTHESIS
                     </div>
                     <div className="px-4 py-2 bg-black/60 backdrop-blur-md rounded-xl text-[8px] font-black uppercase text-slate-400 flex items-center border border-white/10">
                        <Activity className="w-3 h-3 mr-2 text-indigo-400" /> Real-time 60FPS
                     </div>
                  </div>
                  <canvas 
                    ref={canvasRef} 
                    width={1600} height={1200} 
                    onMouseDown={handleMouseDown} 
                    onMouseMove={handleMouseMove} 
                    onMouseUp={() => setIsDrawing(false)} 
                    onMouseLeave={() => setIsDrawing(false)} 
                    className="w-full h-full object-contain cursor-crosshair relative z-0" 
                  />
                  {/* Skeletal Visualization Layer */}
                  <svg className="absolute inset-0 w-full h-full pointer-events-none z-10">
                     {bones.map((bone, i) => (
                        <g key={bone.id}>
                           {i > 0 && (
                             <line 
                               x1={bones[i-1].x} y1={bones[i-1].y} x2={bone.x} y2={bone.y} 
                               stroke="#10b981" strokeWidth="3" strokeDasharray="8,8" className="opacity-60 animate-pulse" 
                             />
                           )}
                           <circle cx={bone.x} cy={bone.y} r="12" fill="#10b981" stroke="white" strokeWidth="4" className="shadow-2xl" />
                           <text x={bone.x + 20} y={bone.y + 5} fill="#475569" className="text-[9px] font-black uppercase font-mono tracking-tighter">SK_NODE_0{i+1}</text>
                        </g>
                     ))}
                  </svg>
                  {isGenerating && (
                    <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center z-50 animate-in fade-in duration-500">
                        <div className="w-24 h-24 border-8 border-emerald-500 border-t-transparent rounded-full animate-spin mb-6 shadow-[0_0_50px_rgba(16,185,129,0.4)]" />
