            {/* Identity Directive Dock */}
            <div className="bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 flex gap-5 shadow-2xl items-center">
              <input 
                value={prompt} 
                onChange={(e) => setPrompt(e.target.value)} 
                placeholder="Enter Character Directive (e.g. Neo-Noir Detective, Mechanical Dragon Monk)" 
                className="flex-1 bg-slate-950 border border-slate-800 rounded-full py-5 px-10 text-white text-xs font-black uppercase tracking-widest outline-none focus:ring-4 focus:ring-emerald-500/5 transition-all" 
              />
              <div className="flex bg-slate-950 border border-slate-800 p-1.5 rounded-full overflow-x-auto scrollbar-hide">
                {['Disney_Pixar', 'UE5_Meta', 'Cyber_Punk', 'Classic_Anime'].map(s => (
                  <button key={s} onClick={() => setRenderStyle(s)} className={`px-6 py-2.5 rounded-full text-[9px] font-black uppercase transition-all whitespace-nowrap ${renderStyle === s ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600 hover:text-white'}`}>{s.split('_')[0]}</button>
                ))}
              </div>
            </div>
         </div>

         {/* Bone Stack & Weight Inspector */}
         <div className="w-80 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-8 shadow-2xl overflow-hidden">
            <div className="space-y-6">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Layers3 className="w-4 h-4 mr-2 text-emerald-400" /> Brush Dynamics</h3>
                <div className="space-y-6">
                    <div className="space-y-2">
                        <div className="flex justify-between text-[8px] font-black uppercase text-slate-500"><span>Radius</span><span className="text-white">{brushSize}px</span></div>
                        <input type="range" min="1" max="150" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-emerald-500" />
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between text-[8px] font-black uppercase text-slate-500"><span>Pressure/Flow</span><span className="text-white">{brushFlow}%</span></div>
                        <input type="range" min="1" max="100" value={brushFlow} onChange={(e) => setBrushFlow(parseInt(e.target.value))} className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-emerald-500" />
                    </div>
                </div>
            </div>

            <div className="h-px bg-white/5" />

