                 </div>
               ))}
               {bones.length === 0 && <p className="text-[9px] font-black uppercase text-slate-600 text-center py-10 opacity-50">Empty Rig Skeleton</p>}
            </div>

            <div className="bg-slate-950 rounded-3xl p-6 border border-white/10 space-y-4 shadow-2xl">
               <div className="flex justify-between items-center text-[9px] font-black text-slate-600 uppercase">
