            lucide.createIcons();
        }
    };

    exportBtn.addEventListener('click', renderVideo);

    // --- CLOUDINARY SYNC ---
    const cloudName = "YOUR_CLOUD_NAME";
    const uploadPreset = "YOUR_UPLOAD_PRESET";

    window.uploadVideo = async function() {
        const file = videoUploadInput.files[0];
        if (!file) return;

        const cloudBtn = document.getElementById('cloudUploadBtn');
        cloudBtn.innerHTML = '<i data-lucide="refresh-cw" class="animate-spin"></i>';
        lucide.createIcons();

        const formData = new FormData();
        formData.append("file", file);
        formData.append("upload_preset", uploadPreset);

        try {
            const res = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/video/upload`, { method: "POST", body: formData });
            const data = await res.json();
            const transformation = "so_3,eo_15,q_auto,f_mp4";
            const trimmedUrl = `https://res.cloudinary.com/${cloudName}/video/upload/${transformation}/${data.public_id}.mp4`;

            videoPlayer.src = trimmedUrl;
            mainClip.textContent = `Active_Node: ${file.name}`;

            const thumb = document.createElement('div');
            thumb.className = 'media-item';
            thumb.innerHTML = `
                <div style="width: 100%; aspect-ratio: 16/9; border-radius: 12px; overflow: hidden; background: #000; border: 1px solid var(--accent); cursor: pointer;" onclick="document.getElementById('player').src='${trimmedUrl}'">
                    <video src="${trimmedUrl}" style="width: 100%; height: 100%; object-fit: cover; opacity: 0.7;"></video>
                </div>
                <p style="font-size: 8px; font-weight: 900; text-transform: uppercase; color: var(--accent); margin-top: 5px;">SYNCED</p>
            `;
            mediaPool.prepend(thumb);
        } catch (err) {
            alert("Handshake Failure: Check Cloudinary credentials.");
        } finally {
            cloudBtn.innerHTML = '<i data-lucide="cloud-upload"></i>';
            lucide.createIcons();
        }
    };

    // Listeners
    playPauseBtn.addEventListener('click', () => {
        isPlaying ? videoPlayer.pause() : videoPlayer.play();
        isPlaying = !isPlaying;
        playPauseBtn.innerHTML = isPlaying ? '<i data-lucide="pause"></i>' : '<i data-lucide="play"></i>';
        lucide.createIcons();
    });

    videoPlayer.addEventListener('loadedmetadata', () => { duration = videoPlayer.duration; totalTimeDisplay.textContent = formatTime(duration); });
    videoPlayer.addEventListener('timeupdate', () => {
        currentTimeDisplay.textContent = formatTime(videoPlayer.currentTime);
        if (duration > 0) playhead.style.left = `calc(100px + ${(videoPlayer.currentTime / duration) * 100}%)`;
    });

    function formatTime(s) { return [Math.floor(s/3600), Math.floor((s%3600)/60), Math.floor(s%60)].map(v => v.toString().padStart(2, '0')).join(':'); }

    window.switchTab = (id) => {
        document.querySelectorAll('.property-stack').forEach(s => s.classList.remove('active'));
        document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
        const target = id === 'filters' ? 'filtersTab' : 'transformTab';
        document.getElementById(target).classList.add('active');
        document.getElementById('tab-' + (id === 'filters' ? 'cloud' : 'transform')).classList.add('active');
    };

    updateLanguage();
    lucide.createIcons();
});

import { TimelineLayer } from '../types';

export class ShotstackService {
  private static instance: ShotstackService;
  private readonly BACKEND_URL = 'http://localhost:3000/render';

  private constructor() {}

  public static getInstance(): ShotstackService {
    if (!ShotstackService.instance) {
      ShotstackService.instance = new ShotstackService();
    }
    return ShotstackService.instance;
  }

  async renderTimeline(layers: TimelineLayer[], aspectRatio: string = '16:9'): Promise<string | null> {
    const mainVideo = layers.find(l => l.type === 'video');
    if (!mainVideo) return null;

    try {
      const response = await fetch(this.BACKEND_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          username: "user1",
          videoUrl: mainVideo.content,
          start: mainVideo.start,
          end: mainVideo.start + mainVideo.duration,
          aspectRatio: aspectRatio
        })
      });

      if (!response.ok) throw new Error('Shotstack cluster handshake failed.');
      const data = await response.json();
      return data.response.id;
    } catch (error) {
      console.error('Render Protocol Error:', error);
      return null;
    }
  }

  async checkStatus(id: string): Promise<{ status: string, url?: string }> {
    try {
      const response = await fetch(`https://api.shotstack.io/v1/render/${id}`, {
        headers: { 'x-api-key': '3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G' }
      });
      const data = await response.json();
      return {
        status: data.response.status,
        url: data.response.url
      };
    } catch (error) {
      return { status: 'failed' };
    }
  }
}

