        try {
            // Updated to use the user's provided backend logic
            const response = await fetch("http://localhost:3000/render", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    username: "user1",
                    videoUrl: currentUrl,
                    start: start,
                    end: end
                })
            });

            const data = await response.json();
            if (data.error) throw new Error(data.error);

            alert(`Cluster Authorization Successful: Credits: ${data.remainingCredits}. Job ID: ${data.response.id}`);
            console.log("Remote Synth Data:", data);
        } catch (err) {
            console.error("Cluster Uplink Failed:", err);
            alert("Critical Node Error: " + err.message);
        } finally {
            exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
            lucide.createIcons();
        }
    };

