const PaintStudio: React.FC<{ onSave: (p: Project) => void }> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<'brush' | 'bones' | 'erase'>('brush');
  const [color, setColor] = useState('#10b981');
  const [brushSize, setBrushSize] = useState(8);
  const [brushFlow, setBrushFlow] = useState(100);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState('Realistic_UE5');
  const [bones, setBones] = useState<Bone[]>([]);
  const [activeLayer, setActiveLayer] = useState(1);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const pos = getMousePos(e);
    if (tool === 'bones') {
      const newBone: Bone = { id: Date.now().toString(), x: pos.x, y: pos.y, name: `SK_NODE_0${bones.length + 1}` };
      setBones([...bones, newBone]);
      return;
    }
    setIsDrawing(true);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(pos.x, pos.y);
      ctx.strokeStyle = tool === 'erase' ? '#020617' : color;
      ctx.lineWidth = brushSize;
      ctx.globalAlpha = brushFlow / 100;
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const pos = getMousePos(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
    }
  };

  const handleSynthesize = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage(`Professional character rig sheet: ${prompt}. ${renderStyle} high-poly model. T-pose front, side, back views. Orthographic projection, production ready textures, 8K resolution.`, "1:1", true);
    if (result) {
      const img = new Image();
      img.src = result;
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
      };
      onSave({ id: `anim-rig-${Date.now()}`, name: `Identity_${prompt.substring(0, 10)}`, type: StudioMode.PAINT, thumbnail: result, updatedAt: Date.now(), status: 'draft', data: { prompt, bones, renderStyle } });
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-4 animate-in fade-in duration-500 overflow-hidden text-slate-200">
      {/* Studio Header */}
      <div className="flex justify-between items-center bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl shadow-emerald-600/20">
              <Dna className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Identity <span className="text-emerald-400">Rigging</span> Hub</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Multi-Skeletal Animation Matrix • v3.2 Stable</p>
           </div>
           <div className="h-8 w-px bg-white/10" />
           <div className="flex bg-black/40 p-1 rounded-xl">
             <button className="px-5 py-1.5 rounded-lg text-[8px] font-black uppercase bg-white text-black shadow-lg">RIG_VIEW</button>
             <button className="px-5 py-1.5 rounded-lg text-[8px] font-black uppercase text-slate-500 hover:text-white">ANIM_LAB</button>
          </div>
        </div>
