// Render/Trim API
app.post("/render", async (req, res) => {
  const { username, videoUrl, start, end } = req.body;
  const targetUser = username || "user1";

  if (!users[targetUser] || users[targetUser].credits <= 0) {
    return res.status(400).json({ error: "No credits left in your node." });
  }

  users[targetUser].credits -= 1;

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: { type: "video", src: videoUrl },
                  start: 0,
                  trim: start,
                  length: end - start
                }
              ]
            }
          ]
        },
        output: { format: "mp4", resolution: "sd" }
      },
      {
        headers: {
          "x-api-key": API_KEY,
          "Content-Type": "application/json"
        }
      }
    );

    res.json({ ...response.data, remainingCredits: users[targetUser].credits });
  } catch (err) {
    console.error("Render failure:", err.message);
    res.status(500).json({ error: err.message });
  }
});

