        {/* ... Rest of tabs (telemetry, deploy, features, nodes) unchanged ... */}
        {activeTab === 'telemetry' && (
           <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 animate-in fade-in">
              {[
                { label: 'CPU LOAD', val: `32%`, icon: Cpu, color: 'text-emerald-500' },
                { label: 'MEMORY', val: `48%`, icon: Database, color: 'text-blue-500' },
                { label: 'TRAFFIC', val: `512GB`, icon: Radio, color: 'text-amber-500' },
                { label: 'THREATS BLOCKED', val: 12, icon: Shield, color: 'text-rose-500' }
