            alert(`Cluster Authorization Successful: Credits Remainder: ${data.remainingCredits}. Render ID: ${data.response?.id || 'SYNTH-ACK'}`);
            console.log("Render Node Response:", data);
        } catch (err) {
            console.error("Cluster Handshake Failed:", err);
            alert("Critical Node Error: " + err.message);
        } finally {
            exportBtn.innerHTML = '<i data-lucide="download"></i> Render MP4';
            lucide.createIcons();
        }
