  const [isRendering, setIsRendering] = useState(false);
  const [renderStatus, setRenderStatus] = useState("");
  const [selectedLayerId, setSelectedLayerId] = useState<string | null>('1');

  const [topic, setTopic] = useState("");

  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Source Footage 8K_01', type: 'video', start: 0, duration: 60, content: 'https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?auto=format&fit=crop&q=80&w=1280', track: 1, opacity: 100, scale: 1, blendingMode: 'normal' },
    { id: '2', name: 'Master Score (Wave)', type: 'audio', start: 0, duration: 100, content: 'audio-src', track: 0, volume: 75 },
