  const activeLayer = useMemo(() => layers.find(l => l.id === selectedLayerId) || layers[0], [layers, selectedLayerId]);

  const handleTimelineInteraction = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const percentage = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
    setPlayheadPos(percentage);
  };

  const handleRender = async () => {
    if (!activeLayer.content.startsWith('http')) return alert("Select a valid cloud node.");
    setIsRendering(true);
    setRenderStatus("Handshake: Requesting Cluster Proxy...");
    try {
      // Points to the specific backend requested by user on Port 3000
      const response = await fetch('http://localhost:3000/render', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          username: "user1",
          videoUrl: activeLayer.content, 
          start: 0, 
          end: 10 
        })
      });
      const data = await response.json();
      if (data.error) throw new Error(data.error);

      setRenderStatus(`Sync: ${data.response?.status.toUpperCase() || 'SYNTHESIZING'}`);
      alert(`Synthesis Initialized. Credits remaining: ${data.remainingCredits}. Job ID: ${data.response?.id}`);
    } catch (err: any) { 
      setRenderStatus("Gateway failure."); 
      alert("Cluster Error: " + err.message);
    } finally {
      setIsRendering(false);
