           <button onClick={handleTopicSynthesis} disabled={isGenerating || !topic} className="w-full py-4 bg-rose-600 hover:bg-rose-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl">Synthesize Node</button>
