                <span className="text-slate-400">{(playheadPos % 1 * 60).toFixed(0).padStart(2, '0')}</span>
              </div>
           </div>
        </div>

        <div className="col-span-3 bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-6 flex flex-col gap-8 shadow-2xl overflow-hidden">
           <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center"><Sliders className="w-4 h-4 mr-2 text-rose-500" /> Node Inspector</h3>
