      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: { type: "video", src: videoUrl },
                  start: 0,
                  trim: start || 0,
                  length: (end - start) || 10
                }
              ]
            }
          ]
        },
        output: { 
          format: "mp4", 
          resolution: "hd",
          aspectRatio: "16:9"
        }
      },
      {
        headers: {
          "x-api-key": API_KEY,
          "Content-Type": "application/json"
