const express = require("express");
const axios = require("axios");
const cors = require("cors");

const app = express();
app.use(cors());
app.use(express.json());

// User requested API Key constant for industrial video synthesis
const API_KEY = "3Ie0acSRfw217AaxfltDPMZBTFj0qCsa4ZskPK4G"; 

// Memory cache for simulation
let users = {
  "user1": { credits: 100, lastRequest: 0 },
  "admin@lumina.com": { credits: 10000, lastRequest: 0 },
  "kader": { credits: 500, lastRequest: 0 }
};

// Middleware: Simulation of Rate Limiting and Credit Check
const authSaaS = (req, res, next) => {
  const { username } = req.body;
  const targetUser = username || "user1";

  if (!users[targetUser]) {
    return res.status(401).json({ error: "Node Identity Unknown." });
  }

  // Rate Limit Check (simulated 2s between renders)
  const now = Date.now();
  if (now - users[targetUser].lastRequest < 2000) {
    return res.status(429).json({ error: "Throttling active. Wait for cluster synchronization." });
  }

  if (users[targetUser].credits <= 0) {
    return res.status(402).json({ error: "Insufficient node credits for synthesis." });
  }

  req.userIdentity = targetUser;
  next();
};

// Main Industrial Render/Trim API
app.post("/render", authSaaS, async (req, res) => {
  const { videoUrl, start, end } = req.body;
  const targetUser = req.userIdentity;

  // Deduct credit and update timestamp
  users[targetUser].credits -= 1;
  users[targetUser].lastRequest = Date.now();

  try {
    const response = await axios.post(
      "https://api.shotstack.io/v1/render",
      {
        timeline: {
          tracks: [
            {
              clips: [
                {
                  asset: { type: "video", src: videoUrl },
                  start: 0,
                  trim: start || 0,
                  length: (end - start) || 10
                }
              ]
            }
          ]
        },
        output: { 
          format: "mp4", 
          resolution: "hd",
          aspectRatio: "16:9"
        }
      },
      {
        headers: {
          "x-api-key": API_KEY,
          "Content-Type": "application/json"
        }
      }
    );

    console.log(`Render initiated for ${targetUser}: ${response.data.response.id}`);

    res.json({ 
      ...response.data, 
      remainingCredits: users[targetUser].credits 
    });
  } catch (err) {
    console.error("Shotstack Node Failure:", err.message);
    res.status(500).json({ error: "Handshake failure in creative cluster: " + err.message });
  }
});

