  "kader": { email: "kader@lumina.com", credits: 500, role: "admin" }
};

// Middleware: Node Authorization & Credit Verification
const authNode = (req, res, next) => {
  const { username } = req.body;
  const target = username || "user1";

  if (!memoryUsers[target]) {
    return res.status(401).json({ error: "Node Identity Unknown." });
  }

  if (memoryUsers[target].credits <= 0) {
    return res.status(402).json({ error: "Insufficient node credits for synthesis." });
  }

  req.userNode = memoryUsers[target];
  next();
};

