                     </div>
                  </div>
                  <canvas ref={canvasRef} width={1600} height={1200} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={() => setIsDrawing(false)} className="w-full h-full object-contain cursor-crosshair relative z-0" />
                  <svg className="absolute inset-0 w-full h-full pointer-events-none z-10">
                     {(poses[currentPoseIdx]?.bones || bones).map((bone, i, arr) => (
                        <g key={bone.id}>
                           {i > 0 && <line x1={arr[i-1].x} y1={arr[i-1].y} x2={bone.x} y2={bone.y} stroke="#10b981" strokeWidth="4" strokeDasharray="10,6" className="opacity-50 animate-pulse" />}
                           <circle cx={bone.x} cy={bone.y} r="14" fill="#10b981" stroke="white" strokeWidth="4" className="shadow-2xl" />
                        </g>
                     ))}
                  </svg>
                  {isGenerating && (
                    <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center z-50 animate-in fade-in duration-500">
