                        <p className="text-emerald-400 font-black uppercase tracking-[0.5em] text-[11px]">Synthesizing Identity...</p>
                    </div>
                  )}
               </div>
            </div>

            <div className="bg-slate-900/90 backdrop-blur-3xl p-4 rounded-[2rem] border border-white/5 flex flex-col gap-4 shadow-2xl">
               <div className="flex items-center justify-between px-4">
                  <div className="flex items-center space-x-4">
                    <Film className="w-4 h-4 text-emerald-400" />
                    <span className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-500">Pose Sequence Timeline</span>
                  </div>
                  <div className="flex items-center space-x-3">
                    <button onClick={() => setIsPlayingAnim(!isPlayingAnim)} className="p-2 bg-white text-black rounded-lg hover:scale-105 transition-all">
                      {isPlayingAnim ? <Pause className="w-4 h-4 fill-current" /> : <Play className="w-4 h-4 fill-current" />}
                    </button>
                    <button onClick={handleCapturePose} className="px-4 py-2 bg-emerald-600 text-white rounded-lg text-[8px] font-black uppercase flex items-center">
                      <Frame className="w-3 h-3 mr-2" /> Capture Pose
                    </button>
