               </div>
               <div className="flex items-center space-x-2 bg-black/40 p-2 rounded-xl h-16 overflow-x-auto custom-scrollbar">
                  {poses.map((p, idx) => (
                    <button key={p.id} onClick={() => setCurrentPoseIdx(idx)} className={`flex-shrink-0 w-20 h-full rounded-lg border flex flex-col items-center justify-center transition-all ${currentPoseIdx === idx ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-slate-800 border-white/5 text-slate-500'}`}>
                      <span className="text-[7px] font-black">FRAME_0{idx+1}</span>
                    </button>
                  ))}
               </div>
            </div>

            <div className="bg-slate-900/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border border-white/5 flex gap-5 shadow-2xl items-center">
              <input value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Describe Character: 'Viking Cyberpunk'..." className="flex-1 bg-slate-950 border border-slate-800 rounded-full py-5 px-10 text-white text-xs font-black uppercase outline-none focus:ring-4 focus:ring-emerald-500/5 transition-all" />
              <div className="flex bg-slate-950 border border-slate-800 p-1.5 rounded-full overflow-x-auto scrollbar-hide max-w-sm">
                {['Disney_3D', 'UE5_Meta', 'High_Anime'].map(s => (
