    if (result) {
      const img = new Image();
      img.src = result;
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
      };
      onSave({ id: `anim-rig-${Date.now()}`, name: `Identity_${prompt.substring(0, 10)}`, type: StudioMode.PAINT, thumbnail: result, updatedAt: Date.now(), status: 'draft', data: { bones, poses } });
