        <div className="flex items-center space-x-6">
           <div className="p-4 bg-emerald-600 rounded-[1.5rem] shadow-xl ring-4 ring-emerald-600/10"><Dna className="w-6 h-6 text-white" /></div>
           <div>
              <h2 className="text-xl font-black uppercase tracking-tighter leading-tight">Identity <span className="text-emerald-400">Rigging</span> Core</h2>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Skeletal Animation Matrix • Industrial v10.5</p>
           </div>
           <div className="h-8 w-px bg-white/10 mx-2" />
           <div className="flex bg-black/40 p-1.5 rounded-xl border border-white/5">
              <button className="px-5 py-1.5 rounded-lg text-[8px] font-black uppercase bg-white text-black shadow-lg">RIG_MODE</button>
