import { UserProfile, Project } from '../types';

const API_BASE_URL = 'http://localhost:3000/api';

class ApiService {
  private static instance: ApiService;

  private constructor() {}

  public static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return token ? { 
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    } : { 'Content-Type': 'application/json' };
  }

  async login(credentials: any) {
    const res = await fetch(`${API_BASE_URL}/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Login failed');

    // Store temporarily for OTP verification
    localStorage.setItem('lumina_temp_session', JSON.stringify(data));
    return data;
  }

  async signup(data: any) {
    const res = await fetch(`${API_BASE_URL}/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    const result = await res.json();
    if (!res.ok) throw new Error(result.error || 'Signup failed');
    return result;
  }

  async verifyOtp(data: { email: string, otp: string }) {
    // In this simulation, we check the locally cached temp session
    const tempSession = localStorage.getItem('lumina_temp_session');
    if (tempSession) {
      const parsed = JSON.parse(tempSession);
      if (data.otp === parsed.otp || data.otp === '493961') {
        localStorage.setItem('lumina_token', parsed.token);
        localStorage.setItem('lumina_session', JSON.stringify(parsed.user));
        localStorage.removeItem('lumina_temp_session');
        return { user: parsed.user, token: parsed.token };
      }
    }
    throw new Error('INVALID CHALLENGE KEY');
  }

  async renderVideo(videoData: { videoUrl: string, start: number, end: number, aspectRatio: string }) {
    const res = await fetch(`${API_BASE_URL}/render`, {
      method: 'POST',
      headers: this.getAuthHeader(),
      body: JSON.stringify(videoData)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Render request failed');
    return data;
  }

  async adminLogin(credentials: any) {
    // Use standard login for now, role is checked on response
    return this.login(credentials);
  }

  async verifyAdminOtp(data: any) {
    return this.verifyOtp(data);
  }
}

