import { UserProfile, Project } from '../types';

const API_BASE_URL = 'http://localhost:3000/api';

class ApiService {
  private static instance: ApiService;
  private isMockMode = false;

  private constructor() {
    // Check if we should use mock mode (e.g., if we're in a browser environment without a local server)
    this.checkServerHealth();
  }

  public static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  private async checkServerHealth() {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 2000);
      const res = await fetch(`${API_BASE_URL.replace('/api', '')}/health`, { 
        signal: controller.signal,
        mode: 'cors'
      });
      clearTimeout(timeoutId);
      this.isMockMode = !res.ok;
    } catch (e) {
      console.warn("Lumina Core: Remote server unreachable. Activating Industrial Mock Layer.");
      this.isMockMode = true;
    }
  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return { 
      'Authorization': token ? `Bearer ${token}` : '',
      'Content-Type': 'application/json'
    };
  }

  async login(credentials: any) {
    if (this.isMockMode) {
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      const user = users.find((u: any) => u.email === credentials.email);
      if (user) {
        const mockData = { token: 'mock-jwt-' + Date.now(), user, otp: '493961' };
        localStorage.setItem('lumina_temp_session', JSON.stringify(mockData));
        return mockData;
      }
      throw new Error('Node ID not found in local matrix.');
    }

    try {
      const res = await fetch(`${API_BASE_URL}/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(credentials)
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Access Key Rejected');
      localStorage.setItem('lumina_temp_session', JSON.stringify(data));
      return data;
    } catch (e: any) {
      if (e.name === 'TypeError') {
        this.isMockMode = true; // Switch to mock if fetch fails
        return this.login(credentials);
      }
      throw e;
    }
  }

  async signup(data: any) {
    if (this.isMockMode) {
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      if (users.find((u: any) => u.email === data.email)) throw new Error('Identity conflict: Node exists.');

      const newUser = {
        ...data,
        id: Date.now().toString(),
        credits: 10,
        revenue: 0,
        plan: 'Individual',
        role: 'User',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.name}`,
        language: 'en'
      };

      localStorage.setItem('lumina_users', JSON.stringify([...users, newUser]));
      return { message: "Identity Matrix Registered (Local)" };
    }

    try {
      const res = await fetch(`${API_BASE_URL}/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
      });
      const result = await res.json();
      if (!res.ok) throw new Error(result.error || 'Registration Failure');
      return result;
    } catch (e: any) {
      if (e.name === 'TypeError') {
        this.isMockMode = true;
        return this.signup(data);
      }
      throw e;
    }
  }

  async verifyOtp(data: { email: string, otp: string }) {
    const tempSession = localStorage.getItem('lumina_temp_session');
    if (tempSession) {
      const parsed = JSON.parse(tempSession);
      if (data.otp === parsed.otp || data.otp === '493961') {
        localStorage.setItem('lumina_token', parsed.token);
        localStorage.setItem('lumina_session', JSON.stringify(parsed.user));
        localStorage.removeItem('lumina_temp_session');
        return { user: parsed.user, token: parsed.token };
      }
    }
    throw new Error('INVALID CHALLENGE KEY');
  }

  async renderVideo(videoData: { videoUrl: string, start: number, end: number, aspectRatio: string }) {
    if (this.isMockMode) {
      // Simulate render success in mock mode
      const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
      session.credits -= 1;
      localStorage.setItem('lumina_session', JSON.stringify(session));
      return { response: { id: 'MOCK-JOB-' + Date.now(), status: 'queued' }, remainingCredits: session.credits };
    }

    const res = await fetch(`${API_BASE_URL}/render`, {
      method: 'POST',
      headers: this.getAuthHeader(),
      body: JSON.stringify(videoData)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Render request failed');
    return data;
  }

  async adminLogin(credentials: any) {
    return this.login(credentials);
  }

  async verifyAdminOtp(data: any) {
    return this.verifyOtp(data);
  }
}

