                      </div>
                      <span className="text-[7px] font-black px-2 py-0.5 bg-slate-800 rounded-md text-slate-500">{skill.status}</span>
                   </div>
                 ))}
              </div>
            </div>
         </div>
      </div>
    </div>
  );
};

export default NotebookStudio;

