import { UserProfile, Project } from '../types';

const API_BASE_URL = 'http://localhost:3000/api';

class ApiService {
  private static instance: ApiService;
  private isMockMode = false;

  private constructor() {
    this.checkServerHealth();
  }

  public static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  private async checkServerHealth() {
    try {
      const res = await fetch(`${API_BASE_URL}/health`);
      this.isMockMode = !res.ok;
    } catch (e) {
      this.isMockMode = true;
    }
  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return { 
      'Authorization': token ? `Bearer ${token}` : '',
      'Content-Type': 'application/json'
    };
  }

  async login(credentials: any) {
    if (this.isMockMode) {
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      const user = users.find((u: any) => u.email === credentials.email);
      if (user) {
        const mockData = { token: 'mock-jwt', user, otp: '493961' };
        localStorage.setItem('lumina_temp_session', JSON.stringify(mockData));
        return mockData;
      }
      throw new Error('Identity not found.');
    }

    const res = await fetch(`${API_BASE_URL}/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error);
    localStorage.setItem('lumina_temp_session', JSON.stringify(data));
    return data;
  }

  async updateProfile(updateData: any) {
    if (this.isMockMode) {
      const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      const updatedUser = { ...session, ...updateData };
      const updatedUsers = users.map((u: any) => u.email === session.email ? updatedUser : u);
      localStorage.setItem('lumina_session', JSON.stringify(updatedUser));
      localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
      return { user: updatedUser };
    }

    const res = await fetch(`${API_BASE_URL}/user/update`, {
      method: 'PATCH',
      headers: this.getAuthHeader(),
      body: JSON.stringify(updateData)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error);
    return data;
  }

  async signup(data: any) {
    if (this.isMockMode) {
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      const newUser = { ...data, credits: 10, role: 'User', avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.name}` };
      localStorage.setItem('lumina_users', JSON.stringify([...users, newUser]));
      return { message: "Registered locally" };
    }
    const res = await fetch(`${API_BASE_URL}/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  }

  async verifyOtp(data: { email: string, otp: string }) {
    const temp = JSON.parse(localStorage.getItem('lumina_temp_session') || '{}');
    if (data.otp === temp.otp || data.otp === '493961') {
      localStorage.setItem('lumina_token', temp.token);
      localStorage.setItem('lumina_session', JSON.stringify(temp.user));
      return temp;
    }
    throw new Error('Invalid OTP');
  }

  // Added renderVideo method to handle video synthesis requests and fix the missing property error in VideoEditor.tsx
  async renderVideo(payload: any) {
    if (this.isMockMode) {
      const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
      const updatedUser = { ...session, credits: (session.credits || 10) - 1 };
      localStorage.setItem('lumina_session', JSON.stringify(updatedUser));
      return { 
        response: { status: 'queued', id: 'mock-render-' + Date.now() }, 
        remainingCredits: updatedUser.credits 
      };
    }

    const res = await fetch(`${API_BASE_URL}/render`, {
      method: 'POST',
      headers: this.getAuthHeader(),
      body: JSON.stringify(payload)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Render failed');
    return data;
  }

  async adminLogin(creds: any) { return this.login(creds); }
  async verifyAdminOtp(data: any) { return this.verifyOtp(data); }
}

export const api = ApiService.getInstance();

