  const timelineRef = useRef<HTMLDivElement>(null);

  // Load files from storage for gallery
  const galleryAssets = useMemo(() => {
    const sessionStr = localStorage.getItem('lumina_session');
    if (!sessionStr) return [];
    const user = JSON.parse(sessionStr);
    const projects = JSON.parse(localStorage.getItem(`lumina_projects_${user.email}`) || '[]');
    return projects.filter((p: Project) => p.type === StudioMode.VIDEO || p.type === StudioMode.PHOTO);
