      if (videoUrl) {
        const newL: TimelineLayer = { 
          id: Date.now().toString(), 
          name: `NEURAL_${topic.substring(0, 8).toUpperCase()}`, 
          type: 'video', 
          start: playheadPos, 
          duration: 15, 
          content: videoUrl, 
          track: 1, 
          opacity: 100 
        };
        setLayers(prev => [...prev, newL]);
        setSelectedLayerId(newL.id);
      }
    } finally {
      setIsGenerating(false);
      setTopic("");
    }
  };

